INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027895e3c98b0941765706', '房间非常好 装修很厚重奢华 一开始看评论 看酒店自己po的照片 感觉跟快捷酒店一样 有些害怕  但来了之后 真的很惊喜 装修很厚重 很奢华 跟一些老牌的日系酒店 （帝国酒店）之类的感觉 没想到在广州也有这样开业时间很长但仍然配套跟得上的酒店。。
服务很好！ 门童拿行李迎宾开门 比一些国际连锁的五星要好多了。 退房时候liren还帮忙直接登记了退房 不用排队了。什么时候北京的酒店服务也能跟上广州呢。。。
另外吃的真的很好
晚上去楼顶旋转自助吃 螃蟹腿鲍鱼进口生蚝 吃撑了 还有最爱吃的金蒜牛肉 做的真的很好吃 比北京第六季那种什么海鲜都拿来涮的自助强好多
酒店里还有花园 大锦鲤吃的真的好 又大又肥
总体来说 物超所值  下次还来', '["https://dimg04.c-ctrip.com/images/0230y12000jkw8gdf4A0A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000jkw8c5xF397_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000jkw939u15B4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000jkvndawCBC2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000jkvsb4g1234_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000jkvk75x709D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000jkvf2xf4D38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000jkufeze39FC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000jkura218677_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-05', '红棉大床套房', '套房', '家庭亲子', 320, 5.771441123130016, 0, 0.0, 7, 2.079441541679836, 9, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '房间非常好 装修很厚重奢华 一开始看评论 看酒店自己po的照片 感觉跟快捷酒店一', '房间非常好 装修很厚重奢华 一开始看评论 看酒店自己po的照片 感觉跟快捷酒店一样 有些害怕  但来了之后 真的很惊喜 装修很厚重 很奢华 跟一些老牌的日系酒店 （帝国酒店）之类的感觉 没想到在广州也有这样开业时间很长但仍然配套跟得上的酒店。。
服务很好！ 门童拿行李迎宾开门 比一些国际连锁的五星要好多了。 退房时候liren还帮忙直接登记了退房 不用排队了。什么时候北京的酒店服务也能跟上广州呢。。。
