INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278ace3c98b094176571b', '第二次入住广州花园酒店，进门就闻到了熟悉的香氛味道。广交会期间客人很多，但酒店工作人员基本应对自如，忙碌且有序。2点准时入住，这次入住红棉双床套房，中式装修风格，更适合国人审美房间面相花园和泳池景观。恰逢阴雨大风天气，下午在一楼行政酒廊下午茶+欢乐时光，看着窗外的风雨交加和云卷云舒，很惬意。晚餐在30楼的凌璇阁，住店客人可享5折优惠，最近也有凭景点打卡记录享餐厅买一赠一活动。至于餐食和口味，倒是没有特别惊艳。第二天早餐后大堂小何帮办理了快捷退房，小郑经理介绍了????羊羊吉祥物，忍不住入手了龙年限定版??图14，照例逛了后花园和4楼博物馆，可谓花园酒店的精髓。嗯，下次还来！', '["https://dimg04.c-ctrip.com/images/0236o12000jrkquvk8A62_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000jrkxd1m576B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000jrl5yjgBF72_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000jrl00r306F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000jrkvpru2871_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000jrkx4xz9E34_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000jrl0le3D3A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000jrl0b3j9A4A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000jrl0ycf0C08_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-13', '红棉双床套房', '套房', '商务出差', 290, 5.673323267171493, 0, 0.0, 13, 2.6390573296152584, 9, '["整体满意度", "景观/朝向", "前台服务"]'::jsonb, '整体满意度', '景观/朝向', '前台服务', '未知酒店', '未知地点', '匿名', '第二次入住广州花园酒店，进门就闻到了熟悉的香氛味道。广交会期间客人很多，但酒店工', '第二次入住广州花园酒店，进门就闻到了熟悉的香氛味道。广交会期间客人很多，但酒店工作人员基本应对自如，忙碌且有序。2点准时入住，这次入住红棉双床套房，中式装修风格，更适合国人审美房间面相花园和泳池景观。恰逢阴雨大风天气，下午在一楼行政酒廊下午茶+欢乐时光，看着窗外的风雨交加和云卷云舒，很惬意。晚餐在30楼的凌璇阁，住店客人可享5折优惠，最近也有凭景点打卡记录享餐厅买一赠一活动。至于餐食和口味，倒是没有特别惊艳。第二天早餐后大堂小何帮办理了快捷退房，小郑经理介绍了????羊羊吉祥物，忍不住入手了龙年限定版??图14，照例逛了后花园和4楼博物馆，可谓花园酒店的精髓。嗯，下次还来！', '2025-04-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278ace3c98b094176571c', '每次到广州出差都会选择花园酒店，首先老牌五星酒店值得信赖，再加服务方面确实比较扎实，感谢前台接待CECILIA，办理入住非常热情周到，还要感谢一下行政酒廊的，Carrie跟Kitty,服务都是很热情周到，让每一位旅客感觉到宾至如归的感觉，下次来广州依然会选择花园酒店！！！', '["https://dimg04.c-ctrip.com/images/0234u224x8zzey06b4865_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g224x8zzfgjc61B15_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x224x8zzfb1w8C166_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-18', '花园双床房', '双床房', '商务出差', 136, 4.919980925828125, 0, 0.0, 30, 3.4339872044851463, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '每次到广州出差都会选择花园酒店，首先老牌五星酒店值得信赖，再加服务方面确实比较扎', '每次到广州出差都会选择花园酒店，首先老牌五星酒店值得信赖，再加服务方面确实比较扎实，感谢前台接待CECILIA，办理入住非常热情周到，还要感谢一下行政酒廊的，Carrie跟Kitty,服务都是很热情周到，让每一位旅客感觉到宾至如归的感觉，下次来广州依然会选择花园酒店！！！', '2025-03-18', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278ace3c98b094176571d', '前台对业务不太熟悉，入住第二晚在前台询问晚餐时间及价钱，前台两位工作人员都不知道（也可能是实习生），需打电话询问，且想当然的认为我们只是来吃饭的，导致信息有偏差。除此以外，都不错。', '["https://dimg04.c-ctrip.com/images/0233v12000jfwvh5mF82A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000jfwq0u26597_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b12000jfwyea182B0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-03-31', '花园大床房', '大床房', '家庭亲子', 90, 4.51085950651685, 0, 0.0, 30, 3.4339872044851463, 7, '["前台服务"]'::jsonb, '前台服务', NULL, NULL, '未知酒店', '未知地点', '匿名', '前台对业务不太熟悉，入住第二晚在前台询问晚餐时间及价钱，前台两位工作人员都不知道', '前台对业务不太熟悉，入住第二晚在前台询问晚餐时间及价钱，前台两位工作人员都不知道（也可能是实习生），需打电话询问，且想当然的认为我们只是来吃饭的，导致信息有偏差。除此以外，都不错。', '2025-03-31', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278ace3c98b094176571e', '房间很好，符合预期，位置也很方便，距离商业圈很近，都是步行5分钟的距离。电梯好多我有点迷糊～35块钱包minibar部分软饮我觉得是比较划算的，前台送了玫瑰花和冰箱贴，很美～', '["https://dimg04.c-ctrip.com/images/0231b12000jnuk1253355_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q12000jnutmuhB564_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000jntdply8252_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-09', '花园大床房', '大床房', '家庭亲子', 87, 4.477336814478207, 0, 0.0, 18, 2.9444389791664403, 7, '["性价比", "周边配套", "前台服务"]'::jsonb, '性价比', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '房间很好，符合预期，位置也很方便，距离商业圈很近，都是步行5分钟的距离。电梯好多', '房间很好，符合预期，位置也很方便，距离商业圈很近，都是步行5分钟的距离。电梯好多我有点迷糊～35块钱包minibar部分软饮我觉得是比较划算的，前台送了玫瑰花和冰箱贴，很美～', '2025-04-09', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278ace3c98b094176571f', '花园酒店环境幽雅别致。
服务：服务满意
卫生：满意
荔湾亭茶点满意
早餐一层就餐人较多，需要等位。早餐菜品不是很多。四层博物馆需要预约，值得去。还有文创产品。目前酒店旁边有工地装修有点减分。酒店离淘金地铁站很近，去东山口就两站地很方便，很多景区地铁都直达。打车也很方便。酒店离市区必逛的景区都很近。酒店是涉外酒店，外国人较多。', '["https://dimg04.c-ctrip.com/images/0236312000j5bg1rhD140_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000j5bzfer9B1B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000j5b7aucDF6F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000j5buo8rAEE0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000j5brvduB881_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000j5cde2k1DB5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2025-03-18', '花园大床房', '大床房', '家庭亲子', 163, 5.099866427824199, 0, 0.0, 6, 1.9459101490553128, 8, '["交通便利性", "周边配套", "整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '花园酒店环境幽雅别致。', '花园酒店环境幽雅别致。
服务：服务满意
卫生：满意
荔湾亭茶点满意
早餐一层就餐人较多，需要等位。早餐菜品不是很多。四层博物馆需要预约，值得去。还有文创产品。目前酒店旁边有工地装修有点减分。酒店离淘金地铁站很近，去东山口就两站地很方便，很多景区地铁都直达。打车也很方便。酒店离市区必逛的景区都很近。酒店是涉外酒店，外国人较多。', '2025-03-18', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278ace3c98b0941765720', '环境：整体酒店环境设计很好，瀑布和花园很有特色，贝聿铭的设计是加分项，酒店博物馆也用心了，不住也可也来逛逛拍照。老牌五星级酒店的水准还在，只是房间内有些年代留下的痕迹，酒店房间也在逐步更新，外围有修地铁施工确实噪音影响很大，临近的房间影响休息，广州规定是早七晚十可施工，但施工单位违规，投诉效果不佳，酒店也有做提示。
服务：五星酒店的服务没得挑，携程铂金会员给升级了岭南金卡会员的优待，升了房型，因为室内空气和室外噪音问题，客服部帮忙换了两次房间，还赠送了早餐，客户的诉求相应很快，会员让人有再次入住的想法。
早餐：一层和三十层的早餐都是自助，种类差不多，不太符合美食之都五星酒店该有的水准，味道中规中矩。一层八点半后人很多，需要等位。三十层位置少，可远眺城景，安静很多。三层是套餐，座位有限，最好预约一下，这次没吃到。
设施：床品很好，舒服，可按需求选枕头，行政大床房的床垫是乳胶的，自带角度，非常好。洗漱用品的品牌和五星不太匹配，使用上没什么问题。', '["https://dimg04.c-ctrip.com/images/0230f12000iozprh779FF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000iozql0w0C78_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000ioyud535309_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p12000ioyyyr7F504_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236512000ioz3cqq3C71_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000iozp45m9135_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232i12000ioz7jkmA0DE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000iozp13c4718_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000iozk2kq5090_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-23', '花园大床房', '大床房', '独自旅行', 426, 6.056784013228625, 0, 0.0, 8, 2.19722457733622, 9, '["安静程度", "房间设施", "前台服务"]'::jsonb, '安静程度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '环境：整体酒店环境设计很好，瀑布和花园很有特色，贝聿铭的设计是加分项，酒店博物馆', '环境：整体酒店环境设计很好，瀑布和花园很有特色，贝聿铭的设计是加分项，酒店博物馆也用心了，不住也可也来逛逛拍照。老牌五星级酒店的水准还在，只是房间内有些年代留下的痕迹，酒店房间也在逐步更新，外围有修地铁施工确实噪音影响很大，临近的房间影响休息，广州规定是早七晚十可施工，但施工单位违规，投诉效果不佳，酒店也有做提示。
服务：五星酒店的服务没得挑，携程铂金会员给升级了岭南金卡会员的优待，升了房型，因为室内空气和室外噪音问题，客服部帮忙换了两次房间，还赠送了早餐，客户的诉求相应很快，会员让人有再次入住的想法。
早餐：一层和三十层的早餐都是自助，种类差不多，不太符合美食之都五星酒店该有的水准，味道中规中矩。一层八点半后人很多，需要等位。三十层位置少，可远眺城景，安静很多。三层是套餐，座位有限，最好预约一下，这次没吃到。
设施：床品很好，舒服，可按需求选枕头，行政大床房的床垫是乳胶的，自带角度，非常好。洗漱用品的品牌和五星不太匹配，使用上没什么问题。', '2025-02-23', 5, '安静程度');
