INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278ace3c98b0941765722', '作为一家老牌白金五星级酒店，酒店环境依然是酒店门面。
设施：刚到房间就遇到打不开门，又要跑下楼找前台，前台服务人员非常积极应对，并及时找工作人员上楼查看，原来门把手要反使用习惯先向上提一下再往下按才打得开门，可之后进出又不用先向上提了。房间内的设施就真的让人大跌眼镜！首先图一可以看到洗手间和淋浴间是共用一扇门，但这扇门无论是在马桶那边还是在淋浴这边，门居然都是倾斜的！根本无法完全关闭，留着一条粗壮的门缝。其次浴缸的花洒托架也是松动的，从图二可见底托已经完全脱离了墙壁，感觉随时都会脱落下来。由此可见酒店平时就疏于对房间设施的有效维护。
卫生：图三是卫生间的墙角，坐在马桶上就能看到这厚厚的污渍，就这么看也有一年半载的量了吧。
服务：本来是想给三颗星的，原因晚上十一点半临时要开车出去，结果到大堂前厅办理停车票的时候居然发现整个前厅都没有工作人员！又要走进去大堂找前台服务人员帮忙，还要前台服务人员打电话给前厅的服务人员叫人过来，打完电话还要登了几分钟才有人来。最后给半颗星原因退房寄存行李后和家人朋友外出吃饭聊天直到下午四点多才回酒店拿行李并办理停车出场。结果在办理停车的时候这个叫     ROY    的服务人员一脸嫌弃的说我们不能办理停车，有人办理了。当时我们都莫名其妙一下子也都不明白啥意思。接着这个叫   ROY   的服务人员说一间房不能办理两台车，我们就更不懂了，明明我们才来办理怎么就不能办理呢？何况我们真的开了两台车过来。经过一番争论后原来是有其他人挂在我们房间下。而这位叫   ROY.   的服务人员也并没有表达歉意，并且由始至终都是一副厌烦的态度在对待我们。果真白金五星级酒店的待客之道就是有独特的见解。
相比2024年5月入住的时候整体水平可以用天差地别来形容。', '["https://dimg04.c-ctrip.com/images/0232l12000j1ais189254_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000j1az6xv1AAD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000j1b5fq0F936_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.6, 2, '2025-03-12', '花园大床房', '大床房', '商务出差', 750, 6.621405651764134, 3, 1.3862943611198906, 6, 1.9459101490553128, 9, '["房间设施", "前台服务", "卫生状况"]'::jsonb, '房间设施', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '作为一家老牌白金五星级酒店，酒店环境依然是酒店门面。', '作为一家老牌白金五星级酒店，酒店环境依然是酒店门面。
设施：刚到房间就遇到打不开门，又要跑下楼找前台，前台服务人员非常积极应对，并及时找工作人员上楼查看，原来门把手要反使用习惯先向上提一下再往下按才打得开门，可之后进出又不用先向上提了。房间内的设施就真的让人大跌眼镜！首先图一可以看到洗手间和淋浴间是共用一扇门，但这扇门无论是在马桶那边还是在淋浴这边，门居然都是倾斜的！根本无法完全关闭，留着一条粗壮的门缝。其次浴缸的花洒托架也是松动的，从图二可见底托已经完全脱离了墙壁，感觉随时都会脱落下来。由此可见酒店平时就疏于对房间设施的有效维护。
卫生：图三是卫生间的墙角，坐在马桶上就能看到这厚厚的污渍，就这么看也有一年半载的量了吧。
服务：本来是想给三颗星的，原因晚上十一点半临时要开车出去，结果到大堂前厅办理停车票的时候居然发现整个前厅都没有工作人员！又要走进去大堂找前台服务人员帮忙，还要前台服务人员打电话给前厅的服务人员叫人过来，打完电话还要登了几分钟才有人来。最后给半颗星原因退房寄存行李后和家人朋友外出吃饭聊天直到下午四点多才回酒店拿行李并办理停车出场。结果在办理停车的时候这个叫     ROY    的服务人员一脸嫌弃的说我们不能办理停车，有人办理了。当时我们都莫名其妙一下子也都不明白啥意思。接着这个叫   ROY   的服务人员说一间房不能办理两台车，我们就更不懂了，明明我们才来办理怎么就不能办理呢？何况我们真的开了两台车过来。经过一番争论后原来是有其他人挂在我们房间下。而这位叫   ROY.   的服务人员也并没有表达歉意，并且由始至终都是一副厌烦的态度在对待我们。果真白金五星级酒店的待客之道就是有独特的见解。
相比2024年5月入住的时候整体水平可以用天差地别来形容。', '2025-03-12', 2, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278ace3c98b0941765723', '三八妇女节遇上了阴冷天，咱来个投机取巧，选择了广州花园酒店，周六上午午饭后，步行进入酒店，前后还送了二枝??。这家酒店1985年营业至今四十年哦。依然保持着五星级水准，难能可贵是在酒店四层，开了个世界酒店史话主题的博物馆，里面珍藏品不少咧。酒店后花园也属于别具匠心精心布置有三个瀑布，锦鲤鱼池，小桥，鲜花朵朵草地绿油油的，地方不大小巧玲珑的。', '["https://dimg04.c-ctrip.com/images/0231d12000iyzfws6CA20_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0236y12000iyzfsyr7765_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-03-09', '花园大床房', '大床房', '家庭亲子', 171, 5.147494476813453, 0, 0.0, 95, 4.564348191467836, 9, '["公共设施", "整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '三八妇女节遇上了阴冷天，咱来个投机取巧，选择了广州花园酒店，周六上午午饭后，步行', '三八妇女节遇上了阴冷天，咱来个投机取巧，选择了广州花园酒店，周六上午午饭后，步行进入酒店，前后还送了二枝??。这家酒店1985年营业至今四十年哦。依然保持着五星级水准，难能可贵是在酒店四层，开了个世界酒店史话主题的博物馆，里面珍藏品不少咧。酒店后花园也属于别具匠心精心布置有三个瀑布，锦鲤鱼池，小桥，鲜花朵朵草地绿油油的，地方不大小巧玲珑的。', '2025-03-09', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278b7e3c98b0941765724', '没想到我们自己国家也有歧视中国人的服务员。我和朋友排队等待进入餐厅吃早饭的时候，有四五个外国人一起排在我们前面，他们等候一分钟左右便入场。等我们排到队伍最前时，服务生说现在等候时间不确定，可能会等很久，建议我们去高层另一处早餐厅。我和朋友是为了一楼早餐厅山水景观专门来住宿、就餐，所以决定继续等待。期间服务员反复说“不确定等候多久，建议上楼就餐”，然而她们并没有和前面的外国人顾客说这些。并且，当我和朋友等待两三分钟入场后，发现早餐厅空位很多，尤其是水果餐区附近几乎没有几个客人。以后绝不会再来这家酒店。我不需要道歉，不需要解释，酒店餐厅不专业的服务已经说明了一切。', '["https://dimg04.c-ctrip.com/images/0233y224x903ptspv5005_R_150_150_R5_Q70_D.jpg"]'::jsonb, 0.7, 1, '2025-03-24', '花园双床房', '双床房', '家庭亲子', 283, 5.648974238161206, 4, 1.6094379124341005, 12, 2.5649493574615367, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '没想到我们自己国家也有歧视中国人的服务员。我和朋友排队等待进入餐厅吃早饭的时候，', '没想到我们自己国家也有歧视中国人的服务员。我和朋友排队等待进入餐厅吃早饭的时候，有四五个外国人一起排在我们前面，他们等候一分钟左右便入场。等我们排到队伍最前时，服务生说现在等候时间不确定，可能会等很久，建议我们去高层另一处早餐厅。我和朋友是为了一楼早餐厅山水景观专门来住宿、就餐，所以决定继续等待。期间服务员反复说“不确定等候多久，建议上楼就餐”，然而她们并没有和前面的外国人顾客说这些。并且，当我和朋友等待两三分钟入场后，发现早餐厅空位很多，尤其是水果餐区附近几乎没有几个客人。以后绝不会再来这家酒店。我不需要道歉，不需要解释，酒店餐厅不专业的服务已经说明了一切。', '2025-03-24', 1, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278b7e3c98b0941765725', '优点：
酒店很大很漂亮，住的高层，窗外风景很棒。服务也很不错。离地铁站近，出门很方便。
酒店有历史底蕴，四楼有博物馆，展现了酒店业的发展，也让我种草了好多酒店，下次来广州一定要去体验。
不足：
办理入住排队时间较久；荔湾亭茶点一般，早餐还行，就是早餐要排队，瀑布餐厅着实小了点。
总体感觉还不错。', '["https://dimg04.c-ctrip.com/images/0233u12000j01s2byF511_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000j028m1o0E6E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000j01xd8y317F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.3, 4, '2025-03-11', '花园双床房', '双床房', '朋友出游', 148, 5.003946305945459, 0, 0.0, 14, 2.70805020110221, 8, '["景观/朝向", "交通便利性", "退房/入住效率"]'::jsonb, '景观/朝向', '交通便利性', '退房/入住效率', '未知酒店', '未知地点', '匿名', '优点：', '优点：
酒店很大很漂亮，住的高层，窗外风景很棒。服务也很不错。离地铁站近，出门很方便。
酒店有历史底蕴，四楼有博物馆，展现了酒店业的发展，也让我种草了好多酒店，下次来广州一定要去体验。
不足：
办理入住排队时间较久；荔湾亭茶点一般，早餐还行，就是早餐要排队，瀑布餐厅着实小了点。
总体感觉还不错。', '2025-03-11', 4, '景观/朝向');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278b7e3c98b0941765726', '花园酒店给我和孩子的感觉是一点都不像老酒店，不管是设施还是服务都特别不错，酒店当天还免费给我们升级了房型，干净、温馨、大气。另外，店内荔湾亭的餐食也是不错的，瀑布餐厅的自助餐虽然品种较少，但其实我们想吃的食物也不会太多，也都能满足。谢谢花园酒店，让我和孩子三天两夜的广州之行过得非常愉快。PS：这也是一家有博物馆的酒店。', '["https://dimg04.c-ctrip.com/images/0233q12000ilmma6cFBFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000ilm7a485DDC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000ilmd1blC804_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000ilmo9fj701A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000ilmsnhiA864_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000ilmn3y08483_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000illwniv7346_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000ilmaj9eBEAD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000ilmoxq3E5E9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-18', '花园双床房', '双床房', '家庭亲子', 160, 5.081404364984463, 0, 0.0, 12, 2.5649493574615367, 9, '["整体满意度", "房间设施", "餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '花园酒店给我和孩子的感觉是一点都不像老酒店，不管是设施还是服务都特别不错，酒店当', '花园酒店给我和孩子的感觉是一点都不像老酒店，不管是设施还是服务都特别不错，酒店当天还免费给我们升级了房型，干净、温馨、大气。另外，店内荔湾亭的餐食也是不错的，瀑布餐厅的自助餐虽然品种较少，但其实我们想吃的食物也不会太多，也都能满足。谢谢花园酒店，让我和孩子三天两夜的广州之行过得非常愉快。PS：这也是一家有博物馆的酒店。', '2025-02-18', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278b7e3c98b0941765727', '老牌地标性酒店，独占好位置。酒店太大了，入住时有很多团队，是我办理check-in最混乱的一次，带着老人也没有能休息的地方，也找不到引导人员，非常尴尬。好在房间不错，房间窗外能能远眺半截小蛮腰。两家餐厅桃园馆和荔湾亭的出品尚可，但是通过客服中心电话预定的桃园馆位置到场后却没有安排，那么预定的意义何在呢？早餐分一楼和顶楼，怕吵选了顶楼，出品很好，但顶楼的旋转餐厅坏了，能使用的餐台餐桌停在了非常丑的朝向位置上，有些可惜了广州的天际线。', '["https://dimg04.c-ctrip.com/images/0231912000iyycci37823_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000iyy4q22A197_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000iyy8vpc7170_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-03-09', '花园双床房', '双床房', '家庭亲子', 217, 5.384495062789089, 1, 0.6931471805599453, 44, 3.80666248977032, 9, '["前台服务", "景观/朝向", "餐饮设施"]'::jsonb, '前台服务', '景观/朝向', '餐饮设施', '未知酒店', '未知地点', '匿名', '老牌地标性酒店，独占好位置。酒店太大了，入住时有很多团队，是我办理check-i', '老牌地标性酒店，独占好位置。酒店太大了，入住时有很多团队，是我办理check-in最混乱的一次，带着老人也没有能休息的地方，也找不到引导人员，非常尴尬。好在房间不错，房间窗外能能远眺半截小蛮腰。两家餐厅桃园馆和荔湾亭的出品尚可，但是通过客服中心电话预定的桃园馆位置到场后却没有安排，那么预定的意义何在呢？早餐分一楼和顶楼，怕吵选了顶楼，出品很好，但顶楼的旋转餐厅坏了，能使用的餐台餐桌停在了非常丑的朝向位置上，有些可惜了广州的天际线。', '2025-03-09', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278b7e3c98b0941765728', '广州花园酒店地址便捷，房间设施设备很齐全，已经续住很多天了，特别表扬前台的Winnie wei 服务态度一级棒，还有前台lavinia .表扬她们，自信有笑容。以后一定再选择这个酒店', '["https://dimg04.c-ctrip.com/images/0233712000j7xt2ww1064_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000j7ypw6xA07B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000j7ytyhqDEC3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000j7x1o7536CA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-21', '城央绿意大床房', '大床房', '商务出差', 91, 4.5217885770490405, 0, 0.0, 9, 2.302585092994046, 8, '["前台服务", "房间设施", "交通便利性"]'::jsonb, '前台服务', '房间设施', '交通便利性', '未知酒店', '未知地点', '匿名', '广州花园酒店地址便捷，房间设施设备很齐全，已经续住很多天了，特别表扬前台的Win', '广州花园酒店地址便捷，房间设施设备很齐全，已经续住很多天了，特别表扬前台的Winnie wei 服务态度一级棒，还有前台lavinia .表扬她们，自信有笑容。以后一定再选择这个酒店', '2025-03-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278b7e3c98b0941765729', '交通便利非常好，酒店国际化很多来自世界各地的游客和商务人士，酒店早餐3个餐厅选择，种类多样。一楼大厅很大鲜花多样，酒店外面还有花园等景观，瀑布餐厅装修的非常好，来广州玩的两天很舒适，酒店服务也很棒！', '["https://dimg04.c-ctrip.com/images/0234h12000izo5swbD46B_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233q12000izo6v3g8D70_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232812000izo9koxE533_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-03-10', '花园双床房', '双床房', '家庭亲子', 99, 4.605170185988092, 1, 0.6931471805599453, 1, 0.6931471805599453, 8, '["交通便利性", "餐饮设施", "整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '交通便利非常好，酒店国际化很多来自世界各地的游客和商务人士，酒店早餐3个餐厅选择', '交通便利非常好，酒店国际化很多来自世界各地的游客和商务人士，酒店早餐3个餐厅选择，种类多样。一楼大厅很大鲜花多样，酒店外面还有花园等景观，瀑布餐厅装修的非常好，来广州玩的两天很舒适，酒店服务也很棒！', '2025-03-10', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278b7e3c98b094176572a', '三十多年前的首选酒店，也是当时广州三家五星涉外酒店的首选！现在似乎有点老态龙钟了，花园还是一样的漂亮！但服务也还是觉对一流的，值得称赞??', '["https://dimg04.c-ctrip.com/images/02360224x902mw7767EB4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000j8xt3rfCD0C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000j8xd0bx6546_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000j8xbfuxB904_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000j8wfo2e11D1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000j8wxwplBA6B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000j8xfpku0D48_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000j8x9e5n2947_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d12000j8we660D938_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-03-22', '红棉大床套房', '套房', '商务出差', 69, 4.248495242049359, 0, 0.0, 15, 2.772588722239781, 7, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '三十多年前的首选酒店，也是当时广州三家五星涉外酒店的首选！现在似乎有点老态龙钟了', '三十多年前的首选酒店，也是当时广州三家五星涉外酒店的首选！现在似乎有点老态龙钟了，花园还是一样的漂亮！但服务也还是觉对一流的，值得称赞??', '2025-03-22', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278b7e3c98b094176572b', '我当时查阅携程就发现这是一家久负盛名的老酒店，很有历史感，又是贝聿铭先生的设计，一下子让我决定了就订这家了。到了酒店后，感觉都很心怡，确实是一家很棒的酒店。客人特别多，但是工作人员都特别亲切周到，没有忙乱，都是井井有条。check in时还升级了房间，特别惊喜，房间宽敞明亮，设施很好。无论酒店内外还是房间内的卫生都很不错，卫生肯定是一个酒店好坏的最重要的标准。再有就是这家酒店的餐饮超级棒，是非常值得来品尝的，广州特色美食特别丰富，真是让我们流连忘返，我们就餐时还看到餐厅里有很多当地的老人，可见实至名归啊。对了还有交通位置很不错，紧挨地铁站，去哪儿都方便。。。总之是很不错的广州之行。', '["https://dimg04.c-ctrip.com/images/0236912000jcmfcjn28A4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000jcm0zyiFD1C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000jclpuo87621_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000jcmh8gzB67B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-27', '城央绿意双床房', '双床房', '家庭亲子', 294, 5.68697535633982, 0, 0.0, 12, 2.5649493574615367, 9, '["整体满意度", "餐饮设施", "交通便利性"]'::jsonb, '整体满意度', '餐饮设施', '交通便利性', '未知酒店', '未知地点', '匿名', '我当时查阅携程就发现这是一家久负盛名的老酒店，很有历史感，又是贝聿铭先生的设计，', '我当时查阅携程就发现这是一家久负盛名的老酒店，很有历史感，又是贝聿铭先生的设计，一下子让我决定了就订这家了。到了酒店后，感觉都很心怡，确实是一家很棒的酒店。客人特别多，但是工作人员都特别亲切周到，没有忙乱，都是井井有条。check in时还升级了房间，特别惊喜，房间宽敞明亮，设施很好。无论酒店内外还是房间内的卫生都很不错，卫生肯定是一个酒店好坏的最重要的标准。再有就是这家酒店的餐饮超级棒，是非常值得来品尝的，广州特色美食特别丰富，真是让我们流连忘返，我们就餐时还看到餐厅里有很多当地的老人，可见实至名归啊。对了还有交通位置很不错，紧挨地铁站，去哪儿都方便。。。总之是很不错的广州之行。', '2025-03-27', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278b7e3c98b094176572c', '花园酒店是这次去广州旅行的超预期惊喜，酒店的瀑布餐厅，云上餐厅和花园酒廊在风景和食物方面各具特色，水准一流。有设计感精心维护的瀑布花园漂亮精致，很多女孩子拍照打卡。酒店工作人员非常专业，服务暖心细致周到，礼宾部的员工会帮忙收快递客人没有剪刀他们还帮忙拆箱，前台的Lavinia Wu注意到我续订的住房没有酒廊待遇，主动送给我让我在酒店可以享受一致的待遇，酒廊的Jennifer 和Cathy细致温和令人愉快，穿金色亮片的Rain是我离店前最后的美好印象，下次来广州，花园酒店会是我的首选。', '["https://dimg04.c-ctrip.com/images/0231f12000jeiv9uh05CE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000jej9px88EBA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000jej3eefE27B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000jej0dp1E7B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231812000jej3e2dDB35_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000jejbm8h4C00_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000jejhk0l7294_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000jeiu7jp65B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000jej3e2f2CD0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-29', '花园双床房', '双床房', '家庭亲子', 244, 5.501258210544727, 0, 0.0, 2, 1.0986122886681098, 9, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '花园酒店是这次去广州旅行的超预期惊喜，酒店的瀑布餐厅，云上餐厅和花园酒廊在风景和', '花园酒店是这次去广州旅行的超预期惊喜，酒店的瀑布餐厅，云上餐厅和花园酒廊在风景和食物方面各具特色，水准一流。有设计感精心维护的瀑布花园漂亮精致，很多女孩子拍照打卡。酒店工作人员非常专业，服务暖心细致周到，礼宾部的员工会帮忙收快递客人没有剪刀他们还帮忙拆箱，前台的Lavinia Wu注意到我续订的住房没有酒廊待遇，主动送给我让我在酒店可以享受一致的待遇，酒廊的Jennifer 和Cathy细致温和令人愉快，穿金色亮片的Rain是我离店前最后的美好印象，下次来广州，花园酒店会是我的首选。', '2025-03-29', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278b7e3c98b094176572d', '这次主要是带孩子出来玩的，这个酒店很适合带娃玩，酒店25处打卡景点，非常适合泡酒店，带娃不累，酒店工作人员都很热情，特别感谢Tina服务特别好！', '["https://dimg04.c-ctrip.com/images/0235e12000jrscrzv309D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000jrrwo0f50BA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000jrsdv7h8FDD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000jrrwtwdE50D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-13', '花园大床房', '大床房', '家庭亲子', 72, 4.290459441148391, 0, 0.0, 2, 1.0986122886681098, 8, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '这次主要是带孩子出来玩的，这个酒店很适合带娃玩，酒店25处打卡景点，非常适合泡酒', '这次主要是带孩子出来玩的，这个酒店很适合带娃玩，酒店25处打卡景点，非常适合泡酒店，带娃不累，酒店工作人员都很热情，特别感谢Tina服务特别好！', '2025-04-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278c1e3c98b094176572e', '这次的花园酒店很是满意??酒店硬件无可挑剔，大堂，客房都很有设计感，交通更是方便，出门就是地铁站，对我们绿色出行非常便捷[强]前台小姐姐还给我们升级了套房，她家的自助餐更是无话可说[强][玫瑰]', '["https://dimg04.c-ctrip.com/images/0232812000jbhh8kf288D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000jbgghxxF187_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000jbh38wzF9CD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000jbhmrgvBBD9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000jbg2jud4871_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-26', '花园双床房', '双床房', '家庭亲子', 97, 4.584967478670572, 0, 0.0, 5, 1.791759469228055, 8, '["交通便利性", "整体满意度", "前台服务"]'::jsonb, '交通便利性', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '这次的花园酒店很是满意??酒店硬件无可挑剔，大堂，客房都很有设计感，交通更是方便', '这次的花园酒店很是满意??酒店硬件无可挑剔，大堂，客房都很有设计感，交通更是方便，出门就是地铁站，对我们绿色出行非常便捷[强]前台小姐姐还给我们升级了套房，她家的自助餐更是无话可说[强][玫瑰]', '2025-03-26', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278c1e3c98b094176572f', '三八节和朋友出游广州入住花园酒店两天两晚，体验非常好。酒店设施古朴，风格典雅，卫生干净，环境优美，被满满的设计感和中国元素深深地吸引到了。几大亮点突出：酒店大唐富丽堂皇，空间很大，前台的美女帅哥热情耐心快捷，我是钻石会员，给我们送了餐还升级了房间；酒店有四个不同风格的餐厅，我们用餐去了一楼和顶楼，自助餐好吃，服务员热情周到；主楼后面自带花园，亭台楼阁，花团锦簇，四楼还有一个小型博物馆很值得去，因为有感觉参观酒店用了我们半天的时间。总之很满意，再到广州花园酒店是不二之选。', '["https://dimg04.c-ctrip.com/images/0232w12000j0ep17w8535_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234t12000j0egywkF63D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000j0erc8qF462_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000j0ersx41840_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000j0erjx93A8C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000j0ez3bsF9F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000j0eyzsiF1E5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000j0f4ebf3BF3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-11', '花园双床房', '双床房', '朋友出游', 237, 5.472270673671475, 0, 0.0, 11, 2.4849066497880004, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '三八节和朋友出游广州入住花园酒店两天两晚，体验非常好。酒店设施古朴，风格典雅，卫', '三八节和朋友出游广州入住花园酒店两天两晚，体验非常好。酒店设施古朴，风格典雅，卫生干净，环境优美，被满满的设计感和中国元素深深地吸引到了。几大亮点突出：酒店大唐富丽堂皇，空间很大，前台的美女帅哥热情耐心快捷，我是钻石会员，给我们送了餐还升级了房间；酒店有四个不同风格的餐厅，我们用餐去了一楼和顶楼，自助餐好吃，服务员热情周到；主楼后面自带花园，亭台楼阁，花团锦簇，四楼还有一个小型博物馆很值得去，因为有感觉参观酒店用了我们半天的时间。总之很满意，再到广州花园酒店是不二之选。', '2025-03-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278c1e3c98b0941765730', '岭南园林中的艺术殿堂 | 入住即享博物馆级体验 ??
??城市绿洲·广府文化·细节控福音
推开花园酒店的玻璃穹顶大门，仿佛踏入一座「会呼吸的艺术馆」——白孔雀雕塑在喷泉旁优雅迎客，20米高的《红楼梦》金箔壁画在长廊流转生辉，每一步都是视觉盛宴。作为住过30+五星酒店的老广，这次入住彻底刷新了我对“奢华”的定义：
? **客房亮点**  
- 入住「粤韵套房」，岭南窗花元素与智能家居融合，迷你吧竟藏着广式凉茶套装，床头柜上的手写欢迎卡是粤绣纹样，细节控狂喜！  
- 180°落地窗俯瞰环市东夜景，浴缸旁配香薰石和精油，泡澡时还能欣赏到花园瀑布景观，妥妥出片圣地。
?? **园林秘境**  
- 被住客称为「隐世花园」的后庭院超出片！锦鲤池、瀑布山石、百年古树构成都市桃源，晨跑时偶遇园丁阿叔热情介绍稀有植物，瞬间get酒店40年历史的温度。
?? **味觉惊喜**  
- 桃园馆的「荔枝木烤乳鸽」让我这个老广竖起大拇指，米其林水准果然名不虚传  
- 意外发现大堂吧有「广府下午茶」，鸡公榄造型点心+西关风情器皿，服务生小哥还会讲解每道茶点的故事
?? **服务彩蛋**  
- 礼宾部竟然有「隐藏服务」！主动提供手绘版《周边美食地图》，连肠粉店的火候差异都标注清楚  
- 退房时收到装着小羊的伴手礼，经理说「希望您把岭南小羊带回家」，这波文化输出我给满分！
最后的最后感谢?viria的热情接待', '["https://dimg04.c-ctrip.com/images/0232d12000jb3cj1l3099_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000jb5dnwoC80D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000jb5ex4f9104_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000jb5fw5eFB9A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-25', '花园大床房', '大床房', '商务出差', 610, 6.415096959171596, 0, 0.0, 3, 1.3862943611198906, 10, '["整体满意度", "房间设施", "前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '岭南园林中的艺术殿堂 | 入住即享博物馆级体验 ??', '岭南园林中的艺术殿堂 | 入住即享博物馆级体验 ??
??城市绿洲·广府文化·细节控福音
推开花园酒店的玻璃穹顶大门，仿佛踏入一座「会呼吸的艺术馆」——白孔雀雕塑在喷泉旁优雅迎客，20米高的《红楼梦》金箔壁画在长廊流转生辉，每一步都是视觉盛宴。作为住过30+五星酒店的老广，这次入住彻底刷新了我对“奢华”的定义：
? **客房亮点**  
- 入住「粤韵套房」，岭南窗花元素与智能家居融合，迷你吧竟藏着广式凉茶套装，床头柜上的手写欢迎卡是粤绣纹样，细节控狂喜！  
- 180°落地窗俯瞰环市东夜景，浴缸旁配香薰石和精油，泡澡时还能欣赏到花园瀑布景观，妥妥出片圣地。
?? **园林秘境**  
- 被住客称为「隐世花园」的后庭院超出片！锦鲤池、瀑布山石、百年古树构成都市桃源，晨跑时偶遇园丁阿叔热情介绍稀有植物，瞬间get酒店40年历史的温度。
?? **味觉惊喜**  
- 桃园馆的「荔枝木烤乳鸽」让我这个老广竖起大拇指，米其林水准果然名不虚传  
- 意外发现大堂吧有「广府下午茶」，鸡公榄造型点心+西关风情器皿，服务生小哥还会讲解每道茶点的故事
?? **服务彩蛋**  
- 礼宾部竟然有「隐藏服务」！主动提供手绘版《周边美食地图》，连肠粉店的火候差异都标注清楚  
- 退房时收到装着小羊的伴手礼，经理说「希望您把岭南小羊带回家」，这波文化输出我给满分！
最后的最后感谢?viria的热情接待', '2025-03-25', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278c1e3c98b0941765731', '广州花园酒店是中国仅有的3家白金五星级酒店其中的一家，处处彰显其作为白金酒店的优雅高贵，以及典雅传奇。大堂的背景墙是用金打造的“红楼梦”壁画，有石刻画手漆画等，酒店自带的园林，瀑布、亭台楼阁、小桥流水等自然景象，酒店内就是一个旅游景点，美不胜收，小朋友喜欢。
还有比较值得一提的就是它们家的餐厅了。荔湾亭、瀑布餐厅、桃园馆、名仕阁、凌轩阁都是很不错的选择（一楼早餐厅晚去需要排队）。', '["https://dimg04.c-ctrip.com/images/0202w12000javxqgb901A_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0232312000jav1w218E6B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-25', '花园双床房', '双床房', '家庭亲子', 191, 5.2574953720277815, 0, 0.0, 12, 2.5649493574615367, 9, '["公共设施", "餐饮设施", "整体满意度"]'::jsonb, '公共设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '广州花园酒店是中国仅有的3家白金五星级酒店其中的一家，处处彰显其作为白金酒店的优', '广州花园酒店是中国仅有的3家白金五星级酒店其中的一家，处处彰显其作为白金酒店的优雅高贵，以及典雅传奇。大堂的背景墙是用金打造的“红楼梦”壁画，有石刻画手漆画等，酒店自带的园林，瀑布、亭台楼阁、小桥流水等自然景象，酒店内就是一个旅游景点，美不胜收，小朋友喜欢。
还有比较值得一提的就是它们家的餐厅了。荔湾亭、瀑布餐厅、桃园馆、名仕阁、凌轩阁都是很不错的选择（一楼早餐厅晚去需要排队）。', '2025-03-25', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278c1e3c98b0941765732', '记得20多年前就经常住花园，后新连锁酒店雨后春笋，就很少再住花园了，这次入住，更新改造后的花园一如既往的非常豪横，给升级房型，赠送早餐，送果盘，送口罩，送送送.......，服务超级给力，令人耳目一心，但遗憾的是，西侧修地铁，从早上7点到凌晨零点，噪音巨大，当然这怪不得酒店，只是提醒办理入住时，一天要求房间要朝向环市东路一侧，否则，心理会留下阴影。', '["https://dimg04.c-ctrip.com/images/0201s12000inqycliF5B1_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0234m12000inqak915397_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000inpxqyo4BC0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000inq1zxm56D4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000inqwosu6C38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000inqn0lf6998_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000inqc3y00631_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000inq14ji5E16_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000inqmrya3238_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231b12000inqlbi2A600_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-21', '花园大床房', '大床房', '商务出差', 175, 5.170483995038151, 0, 0.0, 42, 3.7612001156935615, 8, '["前台服务", "安静程度", "整体满意度"]'::jsonb, '前台服务', '安静程度', '整体满意度', '未知酒店', '未知地点', '匿名', '记得20多年前就经常住花园，后新连锁酒店雨后春笋，就很少再住花园了，这次入住，更', '记得20多年前就经常住花园，后新连锁酒店雨后春笋，就很少再住花园了，这次入住，更新改造后的花园一如既往的非常豪横，给升级房型，赠送早餐，送果盘，送口罩，送送送.......，服务超级给力，令人耳目一心，但遗憾的是，西侧修地铁，从早上7点到凌晨零点，噪音巨大，当然这怪不得酒店，只是提醒办理入住时，一天要求房间要朝向环市东路一侧，否则，心理会留下阴影。', '2025-02-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278c1e3c98b0941765733', '怎么说呢，一次很满意的入住，从前台到服务中心从客房到礼宾，都是非常专业的服务，酒店呢环境优雅美丽，软件很到位，只是硬件有待提高就更完美了', '["https://dimg04.c-ctrip.com/images/0231212000jncf08r5D1F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000jncf1c78AF3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-08', '花园大床房', '大床房', '独自旅行', 68, 4.23410650459726, 0, 0.0, 9, 2.302585092994046, 7, '["前台服务", "整体满意度", "房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '怎么说呢，一次很满意的入住，从前台到服务中心从客房到礼宾，都是非常专业的服务，酒', '怎么说呢，一次很满意的入住，从前台到服务中心从客房到礼宾，都是非常专业的服务，酒店呢环境优雅美丽，软件很到位，只是硬件有待提高就更完美了', '2025-04-08', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278c1e3c98b0941765734', '趁老公生日的机会，选择在花园酒店度过愉快的一晚，红棉套房套餐体验很好，提前备注酒店帮忙做了生日布置，还送了小蛋糕。各个工作人员都很热情，特别是行政酒廊Louis服务热情。', '["https://dimg04.c-ctrip.com/images/0230n12000j2ugpfhDA71_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000j2ub0px9904_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000j2uutbv47BC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-14', '红棉大床套房', '套房', '家庭亲子', 85, 4.454347296253507, 0, 0.0, 10, 2.3978952727983707, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '趁老公生日的机会，选择在花园酒店度过愉快的一晚，红棉套房套餐体验很好，提前备注酒', '趁老公生日的机会，选择在花园酒店度过愉快的一晚，红棉套房套餐体验很好，提前备注酒店帮忙做了生日布置，还送了小蛋糕。各个工作人员都很热情，特别是行政酒廊Louis服务热情。', '2025-03-14', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278c1e3c98b0941765735', '过年期间商务出差二次入住。最后那次入住房间有股经久不散的异味，适逢家属患有中重度鼻炎，十分不适。所幸反馈给酒店后，客房经理马上上房间处理并第一时间帮我们换房，随后赠送了迎宾水果作为诚意。虽然此前订单中我已特别备注，入住被安排到有异味的房间，到换至新的房间时已差不多15点半，家属第二天要长时间外派出行还是稍有不悦，但所幸酒店反应迅速，态度积极热情，努力为客人解决问题，毫不推搪，又令我对该酒店重拾信心。希望下次安排入住时能参考一下客人备注需求，继续保持酒店在老广、来穗游客心中的形象和地位，下次出差时，会再次三刷体验。ps，酒店的行政礼遇不错??，品种虽少但出品保证，环境不错经常有人拍照留念，值得打卡。', '["https://dimg04.c-ctrip.com/images/0231p12000ip4qkl5C90E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231o12000ip552h99E6E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-23', '花园大床房', '大床房', '商务出差', 302, 5.713732805509369, 0, 0.0, 5, 1.791759469228055, 9, '["客房服务", "整体满意度", "餐饮设施"]'::jsonb, '客房服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '过年期间商务出差二次入住。最后那次入住房间有股经久不散的异味，适逢家属患有中重度', '过年期间商务出差二次入住。最后那次入住房间有股经久不散的异味，适逢家属患有中重度鼻炎，十分不适。所幸反馈给酒店后，客房经理马上上房间处理并第一时间帮我们换房，随后赠送了迎宾水果作为诚意。虽然此前订单中我已特别备注，入住被安排到有异味的房间，到换至新的房间时已差不多15点半，家属第二天要长时间外派出行还是稍有不悦，但所幸酒店反应迅速，态度积极热情，努力为客人解决问题，毫不推搪，又令我对该酒店重拾信心。希望下次安排入住时能参考一下客人备注需求，继续保持酒店在老广、来穗游客心中的形象和地位，下次出差时，会再次三刷体验。ps，酒店的行政礼遇不错??，品种虽少但出品保证，环境不错经常有人拍照留念，值得打卡。', '2025-02-23', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278c1e3c98b0941765736', '不愧叫花园酒店，随处可见的花花，令人心旷神怡～外面看着很大气，一进去给人富丽堂皇的感觉，房间干净整洁、设施都不错。酒店内部花园有瀑布有池塘，孩子很喜欢。酒店博物馆有时间的话值得一看。很感叹于一个开业这么久的酒店能维护得这么好，酒店管理的水平相当高??', '["https://dimg04.c-ctrip.com/images/0232y12000jfyqa3tD1A5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000jfyxioy2852_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000jfy6vga20BA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000jfz0bw6532C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000jfyvql892AA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-31', '红棉大床套房', '套房', '家庭亲子', 125, 4.836281906951478, 0, 0.0, 5, 1.791759469228055, 9, '["整体满意度", "房间设施", "公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施', '未知酒店', '未知地点', '匿名', '不愧叫花园酒店，随处可见的花花，令人心旷神怡～外面看着很大气，一进去给人富丽堂皇', '不愧叫花园酒店，随处可见的花花，令人心旷神怡～外面看着很大气，一进去给人富丽堂皇的感觉，房间干净整洁、设施都不错。酒店内部花园有瀑布有池塘，孩子很喜欢。酒店博物馆有时间的话值得一看。很感叹于一个开业这么久的酒店能维护得这么好，酒店管理的水平相当高??', '2025-03-31', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278c1e3c98b0941765737', '服务真不错，因个人原因导致没到前台退押金，我又回家了，但是工作人员积极协调，很人性化的帮我处理了，坐了4晚感觉真不错，环境，设施，卫生，服务都很满意。', '["https://dimg04.c-ctrip.com/images/0236512000j7z3t5t25A1_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231312000j7z3r8j421E_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232d12000j7z45ap476B_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-03-21', '红棉大床套房', '套房', '商务出差', 75, 4.330733340286331, 0, 0.0, 2, 1.0986122886681098, 8, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '服务真不错，因个人原因导致没到前台退押金，我又回家了，但是工作人员积极协调，很人', '服务真不错，因个人原因导致没到前台退押金，我又回家了，但是工作人员积极协调，很人性化的帮我处理了，坐了4晚感觉真不错，环境，设施，卫生，服务都很满意。', '2025-03-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278cde3c98b0941765738', '花园酒店是这次广州行的最大惊喜，真的是惊喜多多。首先硬件无可挑剔，交通方便，门外就是地铁站。无论大堂还是房间得设施真的是感觉非常棒，免费升级房间、赠送早餐、享用行政酒廊、收到生日蛋糕……，真的贴心。服务真的一级棒，可以说每个服务员都是经过专业的培训，要夸赞花园酒店的管理层真的不错呢！要夸赞行政酒廊的Carrie和Blair，真的是笑容服务，会和客人温柔的聊天，很有亲和力。园子里的锦鲤也是超好看，下次去广州还会住这里！', '["https://dimg04.c-ctrip.com/images/0231512000im0h1pb01C2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000im0pxuz0BCC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000im0pw39B411_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235j12000im0pxv1D6D1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000im0syz7080B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234l12000im0nkaaD7B4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000im0l7x58687_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000im0ebjbAA9C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000im0l7x71EF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-19', '花园大床房', '大床房', '家庭亲子', 210, 5.351858133476067, 0, 0.0, 2, 1.0986122886681098, 9, '["整体满意度", "前台服务", "交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '花园酒店是这次广州行的最大惊喜，真的是惊喜多多。首先硬件无可挑剔，交通方便，门外', '花园酒店是这次广州行的最大惊喜，真的是惊喜多多。首先硬件无可挑剔，交通方便，门外就是地铁站。无论大堂还是房间得设施真的是感觉非常棒，免费升级房间、赠送早餐、享用行政酒廊、收到生日蛋糕……，真的贴心。服务真的一级棒，可以说每个服务员都是经过专业的培训，要夸赞花园酒店的管理层真的不错呢！要夸赞行政酒廊的Carrie和Blair，真的是笑容服务，会和客人温柔的聊天，很有亲和力。园子里的锦鲤也是超好看，下次去广州还会住这里！', '2025-02-19', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278cde3c98b0941765739', '环境：不愧是花园酒店，后花园和瀑布太美了。
服务：态度很好，大部分人都主动打招呼、提供帮助。入住时小姐姐还帮我们升了套房，非常感谢。
卫生：很不错，很放心。
设施：全皮办公桌椅很气派，但可能是太久了，卫生间的马桶圈小了一圈，还晃来晃去不合适，和整体风格格格不入。一个洗手池下水极其缓慢，另外一个洗手池下水也很慢。', '["https://dimg04.c-ctrip.com/images/0233g12000ijwww2c9660_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000ijwtiji38AE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000ijwzxp856F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000ijxejz7E447_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000ijxkrlmC2B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231912000ijxejz9E686_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-16', '花园双床房', '双床房', '家庭亲子', 156, 5.056245805348308, 1, 0.6931471805599453, 9, 2.302585092994046, 8, '["房间设施", "前台服务", "卫生状况"]'::jsonb, '房间设施', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '环境：不愧是花园酒店，后花园和瀑布太美了。', '环境：不愧是花园酒店，后花园和瀑布太美了。
服务：态度很好，大部分人都主动打招呼、提供帮助。入住时小姐姐还帮我们升了套房，非常感谢。
卫生：很不错，很放心。
设施：全皮办公桌椅很气派，但可能是太久了，卫生间的马桶圈小了一圈，还晃来晃去不合适，和整体风格格格不入。一个洗手池下水极其缓慢，另外一个洗手池下水也很慢。', '2025-02-16', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278cde3c98b094176573a', '酒店房间干净、卫生。酒店本身自带的花园非常漂亮，瀑布餐厅早餐品种丰富。打扫房间的东南亚小哥认真负责。酒店边上就是淘金地铁站，外出方便。周边吃饭餐馆选择多，以后来广州还会选择花园酒店。
另外酒店有直达香港，澳门的巴士，去港澳非常方便。', '["https://dimg04.c-ctrip.com/images/0231b12000in4zau2DD93_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000in52vvv6087_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-20', '花园双床房', '双床房', '家庭亲子', 117, 4.770684624465665, 0, 0.0, 10, 2.3978952727983707, 8, '["卫生状况", "交通便利性", "周边配套"]'::jsonb, '卫生状况', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '酒店房间干净、卫生。酒店本身自带的花园非常漂亮，瀑布餐厅早餐品种丰富。打扫房间的', '酒店房间干净、卫生。酒店本身自带的花园非常漂亮，瀑布餐厅早餐品种丰富。打扫房间的东南亚小哥认真负责。酒店边上就是淘金地铁站，外出方便。周边吃饭餐馆选择多，以后来广州还会选择花园酒店。
另外酒店有直达香港，澳门的巴士，去港澳非常方便。', '2025-02-20', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278cde3c98b094176573b', '花园酒店是中国星级酒店的代表，三家白金五星级酒店之一，大堂气派，尽管酒店很有历史，设施并不陈旧。红棉大床房对于家庭出行很方便，客厅有专门的写字桌和台灯，孩子晚上方便写会作业。早餐选择的30层旋转餐厅，虽说味道一般，但是感觉还不错。周边交通方便，吃喝逛都很方便。总体来说，性价比很高，值得推荐。', '["https://dimg04.c-ctrip.com/images/0234b12000ifsp5450E8E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233412000iftpxwrC9F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235412000ifto5gc1B58_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000ift50gnB97E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000iftn76fDA17_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-10', '红棉大床套房', '套房', '家庭亲子', 146, 4.990432586778736, 0, 0.0, 6, 1.9459101490553128, 9, '["性价比", "周边配套", "房间设施"]'::jsonb, '性价比', '周边配套', '房间设施', '未知酒店', '未知地点', '匿名', '花园酒店是中国星级酒店的代表，三家白金五星级酒店之一，大堂气派，尽管酒店很有历史', '花园酒店是中国星级酒店的代表，三家白金五星级酒店之一，大堂气派，尽管酒店很有历史，设施并不陈旧。红棉大床房对于家庭出行很方便，客厅有专门的写字桌和台灯，孩子晚上方便写会作业。早餐选择的30层旋转餐厅，虽说味道一般，但是感觉还不错。周边交通方便，吃喝逛都很方便。总体来说，性价比很高，值得推荐。', '2025-02-10', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278cde3c98b094176573c', '带着老人小孩出行，前台办理入住没有排队，帮我两个房间都升级了套房。30楼旋转餐厅的早餐还不错，各种样式的菜都有。旁边就是淘金地铁站，出门打车也很方便。酒店出去右手边有个点都德不远。对面有个购物中心，很方便', '["https://dimg04.c-ctrip.com/images/0234312000in5ukniABE9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000in5jgqf339A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233g12000in5kscoBE05_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000in5fkvr0423_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000in5jgqhB7ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-20', '花园双床房', '双床房', '家庭亲子', 102, 4.634728988229636, 0, 0.0, 23, 3.1780538303479458, 8, '["前台服务", "交通便利性", "周边配套"]'::jsonb, '前台服务', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '带着老人小孩出行，前台办理入住没有排队，帮我两个房间都升级了套房。30楼旋转餐厅', '带着老人小孩出行，前台办理入住没有排队，帮我两个房间都升级了套房。30楼旋转餐厅的早餐还不错，各种样式的菜都有。旁边就是淘金地铁站，出门打车也很方便。酒店出去右手边有个点都德不远。对面有个购物中心，很方便', '2025-02-20', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278cde3c98b094176573d', '酒店很高大上，考虑了康莱德和白天鹅，最后还是选这里，也因为白金五星的历史感。花园和博物馆都不错，博物馆很有情怀，不虚此行。
早餐很好，选的30层旋转餐厅，大部分菜品味道在线。晚餐是荔湾亭点心半自助，以一个外省人的角度很好吃。
健身的地方有点不好找，但设施还行，该有的都有，不大。
停车不方便，地下停车场离大厅有距离，地上停车场又比较小，自驾游可能要考虑下停车的预案。门口就是地铁站，地铁很方便。
花园双床房非常小，小到唤起我对某些日本酒店的印象：地上能不能平铺开行李箱？能平铺开就算是大房间。按这个标准，这里的也算大房间。但如果再住这里的话，我不会选基础房，俩大人带个孩子太局促了。
有点逗的是晚上22-23点房间出现高频断续刺耳异响，我推断是某些房间用水或者是上下水导致的水管尖锐鸣声。当时孩子已经睡了，俩大人面面相觑，客房服务人员A来的时候没响，她说自己很忙，也没法停留五分钟听一下到底是什么声音，解决方案是要么我们自己内线拨0沟通换房，要么她送耳塞过来。我们的诉求是请她优先解决声音问题，解决不了再换房，毕竟孩子睡着了，不太想折腾。过了一会来了个客房服务B，只送来一副耳塞并且当场听到了连续且刺耳的声音，说立刻回去报告，然后就没有然后了。俩成年人一副耳塞，问题也假装不存在，大半夜大家可能都比较累，凑合睡吧。', '["https://dimg04.c-ctrip.com/images/0232m12000iee56tfBA99_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000iedr9xd8241_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000ieddjzaF0B6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2025-02-08', '花园双床房', '双床房', '家庭亲子', 557, 6.324358962381311, 3, 1.3862943611198906, 11, 2.4849066497880004, 9, '["房间设施", "客房服务", "交通便利性"]'::jsonb, '房间设施', '客房服务', '交通便利性', '未知酒店', '未知地点', '匿名', '酒店很高大上，考虑了康莱德和白天鹅，最后还是选这里，也因为白金五星的历史感。花园', '酒店很高大上，考虑了康莱德和白天鹅，最后还是选这里，也因为白金五星的历史感。花园和博物馆都不错，博物馆很有情怀，不虚此行。
早餐很好，选的30层旋转餐厅，大部分菜品味道在线。晚餐是荔湾亭点心半自助，以一个外省人的角度很好吃。
健身的地方有点不好找，但设施还行，该有的都有，不大。
停车不方便，地下停车场离大厅有距离，地上停车场又比较小，自驾游可能要考虑下停车的预案。门口就是地铁站，地铁很方便。
花园双床房非常小，小到唤起我对某些日本酒店的印象：地上能不能平铺开行李箱？能平铺开就算是大房间。按这个标准，这里的也算大房间。但如果再住这里的话，我不会选基础房，俩大人带个孩子太局促了。
有点逗的是晚上22-23点房间出现高频断续刺耳异响，我推断是某些房间用水或者是上下水导致的水管尖锐鸣声。当时孩子已经睡了，俩大人面面相觑，客房服务人员A来的时候没响，她说自己很忙，也没法停留五分钟听一下到底是什么声音，解决方案是要么我们自己内线拨0沟通换房，要么她送耳塞过来。我们的诉求是请她优先解决声音问题，解决不了再换房，毕竟孩子睡着了，不太想折腾。过了一会来了个客房服务B，只送来一副耳塞并且当场听到了连续且刺耳的声音，说立刻回去报告，然后就没有然后了。俩成年人一副耳塞，问题也假装不存在，大半夜大家可能都比较累，凑合睡吧。', '2025-02-08', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278cde3c98b094176573e', '房间很好，早餐也不错，品种齐全，楼顶旋转餐厅视野无敌。花园太美了，散步根本不想上楼。无论晴天阴天，白天还是夜晚，都好适合散步。
游泳池是露天的，但不恒温。
器械也可以。24小时
下次还来', '["https://dimg04.c-ctrip.com/images/0236312000ioze5h0DE96_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233j12000iozcgit8274_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000ioyirngFD47_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000ioyswww0874_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000ioypyu2766D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000ioypyu4D8A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000ioz5tk6D023_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000ioz9wgkA6E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000ioz0p5l080C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-23', '花园大床房', '大床房', '独自旅行', 93, 4.543294782270004, 0, 0.0, 9, 2.302585092994046, 7, '["餐饮设施", "公共设施", "整体满意度"]'::jsonb, '餐饮设施', '公共设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间很好，早餐也不错，品种齐全，楼顶旋转餐厅视野无敌。花园太美了，散步根本不想上', '房间很好，早餐也不错，品种齐全，楼顶旋转餐厅视野无敌。花园太美了，散步根本不想上楼。无论晴天阴天，白天还是夜晚，都好适合散步。
游泳池是露天的，但不恒温。
