INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278cde3c98b094176573f', '首先说说地理位置，酒店位于广州的越秀区，周边有商场及饭店吃喝都很便利，酒店门口就有一个地铁站无论是坐公共交通还是打车都很方便。 再说说环境，酒店非常大还自带一个后花园饭后散散步十分惬意，除此之外酒店的四楼还有一个关于酒店历史的博物馆住店客人是免费的值得一逛，房间和公共区域都非常干净。 所有的服务人员都非常礼貌、看到客人都会主动打招呼，即便春节期间入住客人非常的多但服务人员的精神面貌都非常好！ 最后来说说房间，卫生情况是不需要担忧的非常干净，但毕竟是1985年就开业的酒店，房间的布局及设施稍稍落后了一些，没有USB插头、吹风机还是最老式的那种，洗浴后没有能放干净换洗衣物的地方，且浴室及床之间仅有一扇透明的隔门（建议稍稍改进一下）。但总体来说酒店很棒，如有机会再次来广州一定还会选择花园酒店', '["https://dimg04.c-ctrip.com/images/0235d12000iizo4qnE6BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000iizjych9F24_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000iiyyetwFE52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000iizc8urBF3E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000iiz2eqb09CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000iizkg6y92B6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000iizjusfC75F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000iizk2xwB718_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-14', '花园大床房', '大床房', '家庭亲子', 347, 5.8522024797744745, 0, 0.0, 7, 2.079441541679836, 9, '["房间设施", "交通便利性", "周边配套"]'::jsonb, '房间设施', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '首先说说地理位置，酒店位于广州的越秀区，周边有商场及饭店吃喝都很便利，酒店门口就', '首先说说地理位置，酒店位于广州的越秀区，周边有商场及饭店吃喝都很便利，酒店门口就有一个地铁站无论是坐公共交通还是打车都很方便。 再说说环境，酒店非常大还自带一个后花园饭后散散步十分惬意，除此之外酒店的四楼还有一个关于酒店历史的博物馆住店客人是免费的值得一逛，房间和公共区域都非常干净。 所有的服务人员都非常礼貌、看到客人都会主动打招呼，即便春节期间入住客人非常的多但服务人员的精神面貌都非常好！ 最后来说说房间，卫生情况是不需要担忧的非常干净，但毕竟是1985年就开业的酒店，房间的布局及设施稍稍落后了一些，没有USB插头、吹风机还是最老式的那种，洗浴后没有能放干净换洗衣物的地方，且浴室及床之间仅有一扇透明的隔门（建议稍稍改进一下）。但总体来说酒店很棒，如有机会再次来广州一定还会选择花园酒店', '2025-02-14', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278cde3c98b0941765740', '服务：前台接待的小姐姐服务超级赞，帮我们从红棉升到了海韵，送了两支鲜花，给我们介绍了酒店、酒店套餐、博物馆和周边交通，很暖心。
住：房间整体不错，床品很舒服，房间除了没有浴缸外，其他都不错。
吃：早餐和其他五星相比品种不多，胜在瀑布餐厅环境不错；酒吧外国人比较多，有驻唱歌手，唱得很棒，但鸡尾酒很一般。荔湾亭菜品不错，说古很有传统特色，但服务员之间频繁相互呛声，稍显不够友爱。', '["https://dimg04.c-ctrip.com/images/0232612000ifpamjsDA6F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231z12000ifo3s7oD26E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000ifo5q3cC7FE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000ifnys4sA368_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000ifok2kz2F06_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000ifoywkc7D95_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234112000ifod14s117A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.1, 4, '2025-02-10', '红棉双床套房', '套房', '家庭亲子', 188, 5.241747015059643, 0, 0.0, 6, 1.9459101490553128, 9, '["前台服务", "房间设施", "餐饮设施"]'::jsonb, '前台服务', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '服务：前台接待的小姐姐服务超级赞，帮我们从红棉升到了海韵，送了两支鲜花，给我们介', '服务：前台接待的小姐姐服务超级赞，帮我们从红棉升到了海韵，送了两支鲜花，给我们介绍了酒店、酒店套餐、博物馆和周边交通，很暖心。
住：房间整体不错，床品很舒服，房间除了没有浴缸外，其他都不错。
吃：早餐和其他五星相比品种不多，胜在瀑布餐厅环境不错；酒吧外国人比较多，有驻唱歌手，唱得很棒，但鸡尾酒很一般。荔湾亭菜品不错，说古很有传统特色，但服务员之间频繁相互呛声，稍显不够友爱。', '2025-02-10', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278cde3c98b0941765741', '8年前曾经住过的酒店留给我很好的印象，所以这次来广州旅游一定要再体验一下。酒店位置很方便，地铁淘金站出来就到了，马路对面就是广州酒家和友谊商店，附近还有点都德。这次订的花园大床房，房间虽不大，但布局合理，送了欢迎水果：苹果香蕉沙糖桔很甜，房间里有胶囊咖啡机，和川宁茶包，提供的水是屈臣氏绿瓶矿泉水。早上10点到的酒店，被告知要下午2点才能入住，所以到门口寄存处把行李寄好就到对面广州酒家喝早茶去了。在此要表扬寄存处的工作人员（外籍）很有礼貌，很有绅士风度。还有进出酒店都有门童帮忙拉门并热情打招呼，这都是酒店留给我的好印象，并且一直保持到现在，真的是很不容易！不愧是老牌超五星酒店的优良传统，希望一直保持下去。（忘记拍照了，放几张广州夜景照）', '["https://dimg04.c-ctrip.com/images/0235f12000ip244gbBABC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000ip14ifp8798_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000ip19xfq62C2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000ip1jiju6D69_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-23', '花园大床房', '大床房', '家庭亲子', 321, 5.7745515455444085, 0, 0.0, 19, 2.995732273553991, 9, '["整体满意度", "交通便利性", "前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '8年前曾经住过的酒店留给我很好的印象，所以这次来广州旅游一定要再体验一下。酒店位', '8年前曾经住过的酒店留给我很好的印象，所以这次来广州旅游一定要再体验一下。酒店位置很方便，地铁淘金站出来就到了，马路对面就是广州酒家和友谊商店，附近还有点都德。这次订的花园大床房，房间虽不大，但布局合理，送了欢迎水果：苹果香蕉沙糖桔很甜，房间里有胶囊咖啡机，和川宁茶包，提供的水是屈臣氏绿瓶矿泉水。早上10点到的酒店，被告知要下午2点才能入住，所以到门口寄存处把行李寄好就到对面广州酒家喝早茶去了。在此要表扬寄存处的工作人员（外籍）很有礼貌，很有绅士风度。还有进出酒店都有门童帮忙拉门并热情打招呼，这都是酒店留给我的好印象，并且一直保持到现在，真的是很不容易！不愧是老牌超五星酒店的优良传统，希望一直保持下去。（忘记拍照了，放几张广州夜景照）', '2025-02-23', 5, '整体满意度');
