INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278efe3c98b0941765757', '老牌代表性酒店，各个岗位服务人员态度都很训练有素?? 春节氛围很浓，鲜花摆设处处都有。入住期间生日还有布置了房间并准备了蛋糕；房间整理清洁James观察细致，还手写留条祝新年快乐；酒店内餐点选择很多元，酒廊的茶点水果每日都有不同，Carrie热情聊天很温暖。周边出行、美食也都特别多选择。酒店博物馆很有特色，也是酒店行业发展难得的记录。唯一美中不足的部分康体设施在维修。', '["https://dimg04.c-ctrip.com/images/0234a12000i9wqn6m2639_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000i9wspla4324_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233j12000i9w9tdv523E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000i9wvg9q9211_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000i9wx5mp4A17_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000i9vurhm0CB6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000i9w0sv942C4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-02-03', '花园大床房', '大床房', '家庭亲子', 185, 5.225746673713202, 0, 0.0, 9, 2.302585092994046, 9, '["前台服务", "客房服务", "餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '老牌代表性酒店，各个岗位服务人员态度都很训练有素?? 春节氛围很浓，鲜花摆设处处', '老牌代表性酒店，各个岗位服务人员态度都很训练有素?? 春节氛围很浓，鲜花摆设处处都有。入住期间生日还有布置了房间并准备了蛋糕；房间整理清洁James观察细致，还手写留条祝新年快乐；酒店内餐点选择很多元，酒廊的茶点水果每日都有不同，Carrie热情聊天很温暖。周边出行、美食也都特别多选择。酒店博物馆很有特色，也是酒店行业发展难得的记录。唯一美中不足的部分康体设施在维修。', '2025-02-03', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278efe3c98b0941765758', '对广州老牌子酒店有很多期待，住完广州迎宾馆来到花园酒店，大堂金碧辉煌的绘画很是震撼，春节氛围感很好，装饰热闹，还有专门给人拍摄的服务，很赞。大堂春节还有欢乐表演。房间给了升级套房，让我们体验了两种不同的房型很赞。酒店有个小博物馆让我们了解了广州酒店的发展史。花园瀑布很漂亮，喂鱼是一道风景线，孩子很欢乐。每个酒店打卡点都看了一下还是不错的，房间有不同国家的服务生，尽显花园酒店的国际化，房间服务也非常好。水、咖啡、茶都补足。不足之处：房间比较老化，没有足够的USB插口，也没有像莲花山酒店专门放一个多用途转接头。床太软太软，对我要不好的人来说睡眠是灾难，这点建议参考迎宾馆的床简直太舒服了。旋转餐厅服务体验不好，明档下面的地方没有规则，孩子大人要了两次面都被别人拿走，要么有个叫号牌，要么放在旁边等我们来拿。虽然我们现场投诉了，但来道歉的主厨看上去趾高气扬熬的傲气，可能老牌子酒店的服务就是有点高高在上的。咖啡间台拥挤，我被人踩到几次。服务生像是临时招聘，我和他说桌上餐盘收掉，他叫了别人，说他自己有点忙。瀑布餐厅玻璃不干净不能看到美景，明档的面没有楼上好吃。说实在对拥有米其林餐厅的花园酒店自助早餐实在没什么好吃的，我问了连虾饺都没有。口味不如亚朵一碗面和华夫饼。有时候老牌子也要向新品牌学习。花园酒店是广州的一个招牌，还是希望下次来入住有更好的体验。', '["https://dimg04.c-ctrip.com/images/0232k12000i6zcdi4A415_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000i6xpbdo14B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000i6yf89y516D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000i6y7whn3A46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000i6z9wvv0241_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000i6y4bh99FA3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000i6xd57t710B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000i6xz2co8C2D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000i6yezoo7F92_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.8, 3, '2025-01-31', '花园双床房', '双床房', '家庭亲子', 577, 6.359573868672378, 1, 0.6931471805599453, 7, 2.079441541679836, 9, '["房间设施", "整体满意度", "餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '对广州老牌子酒店有很多期待，住完广州迎宾馆来到花园酒店，大堂金碧辉煌的绘画很是震', '对广州老牌子酒店有很多期待，住完广州迎宾馆来到花园酒店，大堂金碧辉煌的绘画很是震撼，春节氛围感很好，装饰热闹，还有专门给人拍摄的服务，很赞。大堂春节还有欢乐表演。房间给了升级套房，让我们体验了两种不同的房型很赞。酒店有个小博物馆让我们了解了广州酒店的发展史。花园瀑布很漂亮，喂鱼是一道风景线，孩子很欢乐。每个酒店打卡点都看了一下还是不错的，房间有不同国家的服务生，尽显花园酒店的国际化，房间服务也非常好。水、咖啡、茶都补足。不足之处：房间比较老化，没有足够的USB插口，也没有像莲花山酒店专门放一个多用途转接头。床太软太软，对我要不好的人来说睡眠是灾难，这点建议参考迎宾馆的床简直太舒服了。旋转餐厅服务体验不好，明档下面的地方没有规则，孩子大人要了两次面都被别人拿走，要么有个叫号牌，要么放在旁边等我们来拿。虽然我们现场投诉了，但来道歉的主厨看上去趾高气扬熬的傲气，可能老牌子酒店的服务就是有点高高在上的。咖啡间台拥挤，我被人踩到几次。服务生像是临时招聘，我和他说桌上餐盘收掉，他叫了别人，说他自己有点忙。瀑布餐厅玻璃不干净不能看到美景，明档的面没有楼上好吃。说实在对拥有米其林餐厅的花园酒店自助早餐实在没什么好吃的，我问了连虾饺都没有。口味不如亚朵一碗面和华夫饼。有时候老牌子也要向新品牌学习。花园酒店是广州的一个招牌，还是希望下次来入住有更好的体验。', '2025-01-31', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278efe3c98b0941765759', '在广州住的四个酒店中最满意的。服务人员多，态度好，临近过年酒店大堂布置的也很喜庆。还有个酒店博物馆，可以看挺久，看得出很用心普及酒店知识，很有趣。后院小而精致，瀑布池塘里的锦鲤超级肥大，见人就过来张嘴，哈哈。酒店位置也很不错，出门就是地铁站，对面是白云宾馆和友谊商店。房间设计还不错，基本可以做到关灯全黑。唯一一点就是我的房间在布草间旁边，早上会有点吵。但服务人员的态度抵消了这点，都非常友好，超赞！', '["https://dimg04.c-ctrip.com/images/0232r12000i99blopC1C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000i98fyd48FCC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000i981jnxB850_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000i99gu6n6D62_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000i98u9ybCF70_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000i986tt52950_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000i984ub948EB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000i985axy3FCD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-02', '花园大床房', '大床房', '家庭亲子', 200, 5.303304908059076, 0, 0.0, 16, 2.833213344056216, 9, '["前台服务", "交通便利性", "安静程度"]'::jsonb, '前台服务', '交通便利性', '安静程度', '未知酒店', '未知地点', '匿名', '在广州住的四个酒店中最满意的。服务人员多，态度好，临近过年酒店大堂布置的也很喜庆', '在广州住的四个酒店中最满意的。服务人员多，态度好，临近过年酒店大堂布置的也很喜庆。还有个酒店博物馆，可以看挺久，看得出很用心普及酒店知识，很有趣。后院小而精致，瀑布池塘里的锦鲤超级肥大，见人就过来张嘴，哈哈。酒店位置也很不错，出门就是地铁站，对面是白云宾馆和友谊商店。房间设计还不错，基本可以做到关灯全黑。唯一一点就是我的房间在布草间旁边，早上会有点吵。但服务人员的态度抵消了这点，都非常友好，超赞！', '2025-02-02', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278efe3c98b094176575a', '设施：设施齐全，看着都挺新的
