INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278fee3c98b0941765763', '30多年前，父亲经常在花园酒店对面广州友谊商店出差，本次跟父母一同到广州怀旧之旅，首选花园酒店，满满的童年回忆！感谢入住时Kasas给我们升级了房间，房间装修温馨典雅，极具老钱风，床品舒适，瀑布餐厅就餐也很惬意！退房时，大堂金色衣服LiVen、Rain给我们服务很好，退房效率高。', '["https://dimg04.c-ctrip.com/images/0232012000jgssu8j05EF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000jgsr8f1AE15_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-01', '花园大床房', '大床房', '家庭亲子', 140, 4.948759890378168, 0, 0.0, 6, 1.9459101490553128, 8, '["前台服务", "退房/入住效率", "房间设施"]'::jsonb, '前台服务', '退房/入住效率', '房间设施', '未知酒店', '未知地点', '匿名', '30多年前，父亲经常在花园酒店对面广州友谊商店出差，本次跟父母一同到广州怀旧之旅', '30多年前，父亲经常在花园酒店对面广州友谊商店出差，本次跟父母一同到广州怀旧之旅，首选花园酒店，满满的童年回忆！感谢入住时Kasas给我们升级了房间，房间装修温馨典雅，极具老钱风，床品舒适，瀑布餐厅就餐也很惬意！退房时，大堂金色衣服LiVen、Rain给我们服务很好，退房效率高。', '2025-04-01', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278fee3c98b0941765764', '广州来过很多次，终于亲自体验了一次评价不一的花园，个人觉得值得好评，环境 布置 房间 餐饮各方面都非常大气 华贵而且价格值得，最重要的是这里的服务人员人情味很足 会主动服务并态度耐心真诚 必须给大堂的ANNA和WAYNE两位帅哥靓女五星好评！', '["https://dimg04.c-ctrip.com/images/0231812000i5gd4q301F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000i5gw9z1CA86_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000i5eptmz4FFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000i5g0o0iD202_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000i5fkdroCFF8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-30', '红棉大床套房', '套房', '家庭亲子', 121, 4.804021044733257, 0, 0.0, 8, 2.19722457733622, 8, '["整体满意度", "前台服务", "性价比"]'::jsonb, '整体满意度', '前台服务', '性价比', '未知酒店', '未知地点', '匿名', '广州来过很多次，终于亲自体验了一次评价不一的花园，个人觉得值得好评，环境 布置 ', '广州来过很多次，终于亲自体验了一次评价不一的花园，个人觉得值得好评，环境 布置 房间 餐饮各方面都非常大气 华贵而且价格值得，最重要的是这里的服务人员人情味很足 会主动服务并态度耐心真诚 必须给大堂的ANNA和WAYNE两位帅哥靓女五星好评！', '2025-01-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278fee3c98b0941765765', '老店的服务一如既往的的好，来广州就夜泊花园酒店，早饮在白天鹅酒店，也许就是对老广的那种情怀。时隔七年，是我第四次来羊城，第一次带娃来住，感谢前台接待员帮我升级套房和主动提供儿童洗漱备品。闺女很喜欢瀑布餐厅，餐厅服务员给了小饼干??给小朋友喂鱼，闺女在鱼池玩得很开心，不愿离开.......期待下次还来这家酒店。', '["https://dimg04.c-ctrip.com/images/0230g12000i1qb36l50C4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231812000i1ps97m699B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000i1pp6rn55BB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000i1q92beE383_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v12000i1pqul7C3E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000i1punnw5DCF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-25', '花园大床房', '大床房', '家庭亲子', 155, 5.049856007249537, 0, 0.0, 23, 3.1780538303479458, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '老店的服务一如既往的的好，来广州就夜泊花园酒店，早饮在白天鹅酒店，也许就是对老广', '老店的服务一如既往的的好，来广州就夜泊花园酒店，早饮在白天鹅酒店，也许就是对老广的那种情怀。时隔七年，是我第四次来羊城，第一次带娃来住，感谢前台接待员帮我升级套房和主动提供儿童洗漱备品。闺女很喜欢瀑布餐厅，餐厅服务员给了小饼干??给小朋友喂鱼，闺女在鱼池玩得很开心，不愿离开.......期待下次还来这家酒店。', '2025-01-25', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278fee3c98b0941765766', '老牌五星酒店，环境优美，位置优越，大厅富丽堂皇，布置的非常有岭南过春节的气氛。酒店里的几家馆子也非常好吃。1.3米的双床房非常适合亲子游的一家三口。房间有点小，设施旧。淋浴设计的非常不喜欢。', '["https://dimg04.c-ctrip.com/images/0233412000ia0rysc0736_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.3, 4, '2025-02-03', '城央绿意双床房', '双床房', '家庭亲子', 95, 4.564348191467836, 0, 0.0, 23, 3.1780538303479458, 8, '["房间设施", "周边配套", "整体满意度"]'::jsonb, '房间设施', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '老牌五星酒店，环境优美，位置优越，大厅富丽堂皇，布置的非常有岭南过春节的气氛。酒', '老牌五星酒店，环境优美，位置优越，大厅富丽堂皇，布置的非常有岭南过春节的气氛。酒店里的几家馆子也非常好吃。1.3米的双床房非常适合亲子游的一家三口。房间有点小，设施旧。淋浴设计的非常不喜欢。', '2025-02-03', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278fee3c98b0941765767', '低楼层客房整体装修不算过时，不过细节欠佳，房门有起皮现象，沙发也显得很旧，坐感不太舒适。
桃园餐厅菜品味道不错，食材新鲜，但服务质量参差不齐，部分服务人员缺乏专业性，遇到问题不是积极解决，而是试图把责任推给顾客。并且，住房顾客专享的用餐折扣也未主动告知，还是后来友人告知，回餐厅询问，工作人员却表示要顾客主动提才给优惠，一概不承认自己有问题。
入住期间，还因押金不足碰上服务被婉拒的状况。好在客服许经理处理问题及时又专业，让原本不太愉快的经历有所改观。客服打扫的工作人员都很细心。', '["https://dimg04.c-ctrip.com/images/0236512000jqsu2gq532F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233q12000jqu7oue0C02_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000jqss66hA170_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2025-04-12', '花园大床房', '大床房', '其他', 242, 5.493061443340548, 0, 0.0, 23, 3.1780538303479458, 9, '["房间设施", "前台服务", "餐饮设施"]'::jsonb, '房间设施', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '低楼层客房整体装修不算过时，不过细节欠佳，房门有起皮现象，沙发也显得很旧，坐感不', '低楼层客房整体装修不算过时，不过细节欠佳，房门有起皮现象，沙发也显得很旧，坐感不太舒适。
桃园餐厅菜品味道不错，食材新鲜，但服务质量参差不齐，部分服务人员缺乏专业性，遇到问题不是积极解决，而是试图把责任推给顾客。并且，住房顾客专享的用餐折扣也未主动告知，还是后来友人告知，回餐厅询问，工作人员却表示要顾客主动提才给优惠，一概不承认自己有问题。
入住期间，还因押金不足碰上服务被婉拒的状况。好在客服许经理处理问题及时又专业，让原本不太愉快的经历有所改观。客服打扫的工作人员都很细心。', '2025-04-12', 3, '房间设施');
