INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680278fee3c98b0941765769', '非常满意的入住体验，酒店的地理位置非常好，交通也很便利，出门就是地铁站，酒店的大堂非常气派，环境很好，见我带着老人和孩子，还升级了房间，房间干净舒适，服务贴心细致，设施一应俱全。非常推荐！', '["https://dimg04.c-ctrip.com/images/0235612000iuj8z1v9B04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000iuj2vb835A8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000iuj5u111A3C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000iuip8h048FF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000iujophp7AC5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-03', '花园双床房', '双床房', '家庭亲子', 94, 4.553876891600541, 0, 0.0, 16, 2.833213344056216, 8, '["整体满意度", "交通便利性", "卫生状况"]'::jsonb, '整体满意度', '交通便利性', '卫生状况', '未知酒店', '未知地点', '匿名', '非常满意的入住体验，酒店的地理位置非常好，交通也很便利，出门就是地铁站，酒店的大', '非常满意的入住体验，酒店的地理位置非常好，交通也很便利，出门就是地铁站，酒店的大堂非常气派，环境很好，见我带着老人和孩子，还升级了房间，房间干净舒适，服务贴心细致，设施一应俱全。非常推荐！', '2025-03-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027909e3c98b094176576a', '老五星酒店，但是出乎预料的惊喜，大堂很大气，环境很好，交通便利，对面就是广州酒家。荔湾亭的茶点很好吃??以后来广州还会选择花园酒家', '["https://dimg04.c-ctrip.com/images/0236e12000j5xvpisBCEF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000j5x92zt724D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-19', '红棉双床套房', '套房', '朋友出游', 65, 4.189654742026425, 0, 0.0, 12, 2.5649493574615367, 7, '["交通便利性", "周边配套", "整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '老五星酒店，但是出乎预料的惊喜，大堂很大气，环境很好，交通便利，对面就是广州酒家', '老五星酒店，但是出乎预料的惊喜，大堂很大气，环境很好，交通便利，对面就是广州酒家。荔湾亭的茶点很好吃??以后来广州还会选择花园酒家', '2025-03-19', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027909e3c98b094176576b', '入住体验非常好。因为看到早餐能选三家餐厅订了这家酒店，入住三天把三家餐厅都体验了一下，味道非常好（就是高峰期可能要排队，不过很快就排到了）。虽然是老酒店，但是房间里的装修、设施都很新，性价比很高。', '["https://dimg04.c-ctrip.com/images/0232w12000i6srp5cD0EA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000i6sczy0F448_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000i6rf0h98DF1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-31', '花园大床房', '大床房', '独自旅行', 98, 4.59511985013459, 0, 0.0, 1, 0.6931471805599453, 8, '["餐饮设施", "房间设施", "性价比"]'::jsonb, '餐饮设施', '房间设施', '性价比', '未知酒店', '未知地点', '匿名', '入住体验非常好。因为看到早餐能选三家餐厅订了这家酒店，入住三天把三家餐厅都体验了', '入住体验非常好。因为看到早餐能选三家餐厅订了这家酒店，入住三天把三家餐厅都体验了一下，味道非常好（就是高峰期可能要排队，不过很快就排到了）。虽然是老酒店，但是房间里的装修、设施都很新，性价比很高。', '2025-01-31', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027909e3c98b094176576c', '有名气的老酒店，但是维护保养的很不错，感觉也非常热闹入住人员挺多，所以房间没打扫空出的时候，前台小哥哥及时的升级安排房间，为宾客解决问题的能力点赞。酒店大堂富丽堂皇，还有自己的博物馆而且还规模不小，空闲时参观一下还是非常有意义的。花园酒店为这次的广州行添色不少。', '["https://dimg04.c-ctrip.com/images/0234u12000hzvgmbsB26E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000hzueid1A73A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000hzv7w0v3AE7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230j12000hzup90gF322_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000hzvzajq0486_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000hzuwpidF94F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-22', '花园双床房', '双床房', '家庭亲子', 131, 4.882801922586371, 0, 0.0, 30, 3.4339872044851463, 8, '["前台服务", "整体满意度", "公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '有名气的老酒店，但是维护保养的很不错，感觉也非常热闹入住人员挺多，所以房间没打扫', '有名气的老酒店，但是维护保养的很不错，感觉也非常热闹入住人员挺多，所以房间没打扫空出的时候，前台小哥哥及时的升级安排房间，为宾客解决问题的能力点赞。酒店大堂富丽堂皇，还有自己的博物馆而且还规模不小，空闲时参观一下还是非常有意义的。花园酒店为这次的广州行添色不少。', '2025-01-22', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027909e3c98b094176576d', '广州老牌的五星酒店，各方面都很满意。早餐体验了桃园馆和30楼的旋转餐厅，小朋友很开心，家庭旅行的首选！', '["https://dimg04.c-ctrip.com/images/0233o12000jlj9v9jC401_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000jlimaso8719_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000jljiawp2BF3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000jljk76sD6D0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000jljgxd4D923_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-06', '花园双床房', '双床房', '家庭亲子', 51, 3.951243718581428, 0, 0.0, 7, 2.079441541679836, 6, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '广州老牌的五星酒店，各方面都很满意。早餐体验了桃园馆和30楼的旋转餐厅，小朋友很', '广州老牌的五星酒店，各方面都很满意。早餐体验了桃园馆和30楼的旋转餐厅，小朋友很开心，家庭旅行的首选！', '2025-04-06', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027909e3c98b094176576e', '春节人流大，入住时间比较长，主动升级了房型，很舒适。整体感觉不错，服务效率高，体验了瀑布餐厅和旋转餐厅，环境不错，菜品感觉一般。酒店花园很美，博物馆也很用心，总归是很有特色，可以再来。', '["https://dimg04.c-ctrip.com/images/0235m12000iassmr4A100_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0236y12000iast3nk42EA_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233x12000iasvio2C328_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-02-04', '红棉大床套房', '套房', '家庭亲子', 92, 4.532599493153256, 0, 0.0, 14, 2.70805020110221, 7, '["整体满意度", "餐饮设施", "公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施', '未知酒店', '未知地点', '匿名', '春节人流大，入住时间比较长，主动升级了房型，很舒适。整体感觉不错，服务效率高，体', '春节人流大，入住时间比较长，主动升级了房型，很舒适。整体感觉不错，服务效率高，体验了瀑布餐厅和旋转餐厅，环境不错，菜品感觉一般。酒店花园很美，博物馆也很用心，总归是很有特色，可以再来。', '2025-02-04', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027909e3c98b094176576f', '带家人前往广州旅游，选择下榻广州花园酒店两晚，二楼餐厅荔湾亭跟三楼的粤菜餐厅出品菜品水准都是ok的，推荐体验！另外六小龄童经理不错，满分好评！', '["https://dimg04.c-ctrip.com/images/0231o12000j8d5zkaF60B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233412000j8dkyh7DBCB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-21', '花园大床房', '大床房', '家庭亲子', 71, 4.276666119016055, 0, 0.0, 8, 2.19722457733622, 7, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '带家人前往广州旅游，选择下榻广州花园酒店两晚，二楼餐厅荔湾亭跟三楼的粤菜餐厅出品', '带家人前往广州旅游，选择下榻广州花园酒店两晚，二楼餐厅荔湾亭跟三楼的粤菜餐厅出品菜品水准都是ok的，推荐体验！另外六小龄童经理不错，满分好评！', '2025-03-21', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027909e3c98b0941765770', '房间不错 虽然年代感强一些 但是还是挺干净的。前台服务人员也很贴心 我们到的晚 订的房型没有了 直接安排了升级房型。舟车劳顿后的关心真让人感动呀。早餐的餐厅环境不错 听着瀑布声吃早餐感觉很放空 ?值得再次体验', '["https://dimg04.c-ctrip.com/images/0232w12000hyj2rty1453_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-01-21', '花园双床房', '双床房', '家庭亲子', 104, 4.653960350157523, 0, 0.0, 14, 2.70805020110221, 8, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '房间不错 虽然年代感强一些 但是还是挺干净的。前台服务人员也很贴心 我们到的晚 ', '房间不错 虽然年代感强一些 但是还是挺干净的。前台服务人员也很贴心 我们到的晚 订的房型没有了 直接安排了升级房型。舟车劳顿后的关心真让人感动呀。早餐的餐厅环境不错 听着瀑布声吃早餐感觉很放空 ?值得再次体验', '2025-01-21', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027909e3c98b0941765771', '定了两间房，给妈妈的大床房升级成了套房，她很满意，我和孩子住的双床房一般，尤其是卫生间和浴缸共用一个推拉门这个设计着实有些减分。我想很多选择花园酒店的顾客多半是有些情怀的，毕竟曾经也是名气在线的。酒店的优势:位置好，出门是地铁，对面是商场，附近小吃多，广州酒家，点都德都在200米以内的范围。酒店有博物馆和花园，很赞，而且酒店博物馆的纪念品价格并不比外面高，这点很难得。酒店的不足:进门的服务很糟糕，我们大包小包的行李视若不见，而我一转身，后面的老外的行李，服务人员就笑脸相迎上去了，呵呵呵，什么年代了！！办理入住的队伍排很长，周边没有可以休息的座位，无奈，先存行李回来再次办理，问行李寄存处在哪里，手一挥，鬼知道你指的哪里！办理入住的前台小姐姐问一句，答一句，多说一个字像要收费似的，酒店里有博物馆和花园也不主动告知，还是旁边路过的阿姨告诉我们的！果断后两天转住了文华东方。除了入住前的不快，其余的时候都挺满意，心理觉得有些遗憾，以后不会选择这家了。五星酒店广州从来都不缺。', '["https://dimg04.c-ctrip.com/images/0233412000i0m2kqmB029_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000i0mruckD5FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233q12000i0mnn8h822A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000i0mokxwFD01_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000i0mycr81B8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000i0mp35pCD8E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000i0lxo5x83DE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000i0md1htE054_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-01-23', '花园大床房', '大床房', '家庭亲子', 438, 6.084499413075172, 1, 0.6931471805599453, 21, 3.091042453358316, 9, '["前台服务", "交通便利性", "周边配套"]'::jsonb, '前台服务', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '定了两间房，给妈妈的大床房升级成了套房，她很满意，我和孩子住的双床房一般，尤其是', '定了两间房，给妈妈的大床房升级成了套房，她很满意，我和孩子住的双床房一般，尤其是卫生间和浴缸共用一个推拉门这个设计着实有些减分。我想很多选择花园酒店的顾客多半是有些情怀的，毕竟曾经也是名气在线的。酒店的优势:位置好，出门是地铁，对面是商场，附近小吃多，广州酒家，点都德都在200米以内的范围。酒店有博物馆和花园，很赞，而且酒店博物馆的纪念品价格并不比外面高，这点很难得。酒店的不足:进门的服务很糟糕，我们大包小包的行李视若不见，而我一转身，后面的老外的行李，服务人员就笑脸相迎上去了，呵呵呵，什么年代了！！办理入住的队伍排很长，周边没有可以休息的座位，无奈，先存行李回来再次办理，问行李寄存处在哪里，手一挥，鬼知道你指的哪里！办理入住的前台小姐姐问一句，答一句，多说一个字像要收费似的，酒店里有博物馆和花园也不主动告知，还是旁边路过的阿姨告诉我们的！果断后两天转住了文华东方。除了入住前的不快，其余的时候都挺满意，心理觉得有些遗憾，以后不会选择这家了。五星酒店广州从来都不缺。', '2025-01-23', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027909e3c98b0941765772', '房间干净宽敞，因为是会员的关系还免费升级了房间和使用行政酒廊。出行也很方便，时间关系没有打卡酒店餐厅，据说有很多推荐好餐厅，下次有机会再试吧。', '["https://dimg04.c-ctrip.com/images/0236912000jiiab7q5FB2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000jihu00lFD3E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000jigwvsfF72B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-04-03', '花园双床房', '双床房', '朋友出游', 71, 4.276666119016055, 0, 0.0, 9, 2.302585092994046, 7, '["房间设施", "整体满意度", "交通便利性"]'::jsonb, '房间设施', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '房间干净宽敞，因为是会员的关系还免费升级了房间和使用行政酒廊。出行也很方便，时间', '房间干净宽敞，因为是会员的关系还免费升级了房间和使用行政酒廊。出行也很方便，时间关系没有打卡酒店餐厅，据说有很多推荐好餐厅，下次有机会再试吧。', '2025-04-03', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027909e3c98b0941765773', '服务意识不是很强，经常会没人帮着推门，办理行李寄存的时候小哥在接打电话，可以理解比较忙，但是也没有给客户打招呼表示歉意，旁边的工作人员看着我们傻等着也没有接手的意思，整体的体验感比较一般', '["https://dimg04.c-ctrip.com/images/0234112000ivcqmaa8219_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232i12000ivcabxs1960_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000ivbuwe62727_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-03-04', '花园大床房', '大床房', '家庭亲子', 93, 4.543294782270004, 0, 0.0, 4, 1.6094379124341005, 7, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '服务意识不是很强，经常会没人帮着推门，办理行李寄存的时候小哥在接打电话，可以理解', '服务意识不是很强，经常会没人帮着推门，办理行李寄存的时候小哥在接打电话，可以理解比较忙，但是也没有给客户打招呼表示歉意，旁边的工作人员看着我们傻等着也没有接手的意思，整体的体验感比较一般', '2025-03-04', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027915e3c98b0941765774', '广州花园酒店是一家老牌酒店，在市中心地段，地铁淘金站A口出地面只要走两分钟就到了酒店大堂。酒店服务周到，我们要求送的瓶装水浴巾拖鞋碘伏棉签创可贴也很快送到。酒店周围环境也很美，吃饭很方便。房间设施虽然有点旧，但很干净，唯一不太合理的就是灯光分组。', '["https://dimg04.c-ctrip.com/images/0230s12000hw06jjnCA5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000hvzijga6D8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000hvzygtlAA87_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-18', '花园双床房', '双床房', '家庭亲子', 123, 4.820281565605037, 0, 0.0, 6, 1.9459101490553128, 8, '["交通便利性", "客房服务", "房间设施"]'::jsonb, '交通便利性', '客房服务', '房间设施', '未知酒店', '未知地点', '匿名', '广州花园酒店是一家老牌酒店，在市中心地段，地铁淘金站A口出地面只要走两分钟就到了', '广州花园酒店是一家老牌酒店，在市中心地段，地铁淘金站A口出地面只要走两分钟就到了酒店大堂。酒店服务周到，我们要求送的瓶装水浴巾拖鞋碘伏棉签创可贴也很快送到。酒店周围环境也很美，吃饭很方便。房间设施虽然有点旧，但很干净，唯一不太合理的就是灯光分组。', '2025-01-18', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027915e3c98b0941765775', '蛮好的老牌酒店，交通便利，旁边有地铁站，停车疗仨人。春节很繁忙，管理也到位，房间卫生干净，早歺歺厅选择范围多，桃花馆歺厅味道佳，退房退押金快速。', '["https://dimg04.c-ctrip.com/images/0234j12000iafsxhx8753_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000iaf849vD485_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000iafoh9bFA53_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000iafggll77E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000iaflp7pC00C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000iaf3n000B40_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233g12000iafljzt78E4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000iafot9gA5D2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000iafvr6gFB2D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-04', '花园双床房', '双床房', '家庭亲子', 72, 4.290459441148391, 0, 0.0, 54, 4.007333185232471, 7, '["交通便利性", "卫生状况", "退房/入住效率"]'::jsonb, '交通便利性', '卫生状况', '退房/入住效率', '未知酒店', '未知地点', '匿名', '蛮好的老牌酒店，交通便利，旁边有地铁站，停车疗仨人。春节很繁忙，管理也到位，房间', '蛮好的老牌酒店，交通便利，旁边有地铁站，停车疗仨人。春节很繁忙，管理也到位，房间卫生干净，早歺歺厅选择范围多，桃花馆歺厅味道佳，退房退押金快速。', '2025-02-04', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027915e3c98b0941765776', '酒店地理位置优越，设施齐全，房屋整洁。酒店所有工作人员的服务都非常周到，尤其Winnie  wei很贴心，有求必应。有欢迎花束，还非常幸运地升级了房型。早上在旋转餐厅边吃饭边欣赏美景。偶然间选择的这个酒店，很满意！', '["https://dimg04.c-ctrip.com/images/0233c12000hynzyizC307_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000hyo4g8005C3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000hyo9v6aC5B6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-21', '花园大床房', '大床房', '家庭亲子', 107, 4.68213122712422, 0, 0.0, 10, 2.3978952727983707, 8, '["整体满意度", "前台服务", "周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套', '未知酒店', '未知地点', '匿名', '酒店地理位置优越，设施齐全，房屋整洁。酒店所有工作人员的服务都非常周到，尤其Wi', '酒店地理位置优越，设施齐全，房屋整洁。酒店所有工作人员的服务都非常周到，尤其Winnie  wei很贴心，有求必应。有欢迎花束，还非常幸运地升级了房型。早上在旋转餐厅边吃饭边欣赏美景。偶然间选择的这个酒店，很满意！', '2025-01-21', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027915e3c98b0941765777', '一如既往的好，尤其是春节期间，特别热闹又有年味。服务比多家五星级酒店更好，出街期间除了大堂有各种活动和集市以外，每一层都有一位工作人员帮忙按电梯，在过年期间，服务做到这个程度非常难得！', '["https://dimg04.c-ctrip.com/images/0234a12000i62cy3o7067_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233n12000i62dpj9238B_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0236y12000i62dr6tBA6D_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-01-30', '花园大床房', '大床房', '家庭亲子', 92, 4.532599493153256, 0, 0.0, 11, 2.4849066497880004, 9, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '一如既往的好，尤其是春节期间，特别热闹又有年味。服务比多家五星级酒店更好，出街期', '一如既往的好，尤其是春节期间，特别热闹又有年味。服务比多家五星级酒店更好，出街期间除了大堂有各种活动和集市以外，每一层都有一位工作人员帮忙按电梯，在过年期间，服务做到这个程度非常难得！', '2025-01-30', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027915e3c98b0941765778', '带爸妈去广州，住的花园酒店粤韵套房。入住期间正逢妈妈生日，酒店赠送了蛋糕，让我们宾至如归。二楼荔湾亭的东西也很好吃，我们那桌的服务员是位阿姨，很耐心，介绍的菜品也很得我们喜欢（忘记问姓名了）特此感谢。另外表扬前台Betty，12楼客服谢现涛，对我们无微不至的关怀和照顾。', '["https://dimg04.c-ctrip.com/images/0234n12000iizc1swAC19_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234h12000iizbntv2F81_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235b12000iizc3vx3586_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0230612000iizc6gj40D5_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-02-14', '粤韵双床套房', '套房', '家庭亲子', 135, 4.912654885736052, 0, 0.0, 23, 3.1780538303479458, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '带爸妈去广州，住的花园酒店粤韵套房。入住期间正逢妈妈生日，酒店赠送了蛋糕，让我们', '带爸妈去广州，住的花园酒店粤韵套房。入住期间正逢妈妈生日，酒店赠送了蛋糕，让我们宾至如归。二楼荔湾亭的东西也很好吃，我们那桌的服务员是位阿姨，很耐心，介绍的菜品也很得我们喜欢（忘记问姓名了）特此感谢。另外表扬前台Betty，12楼客服谢现涛，对我们无微不至的关怀和照顾。', '2025-02-14', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027915e3c98b0941765779', '来广州一定要争取住花园酒店！雍容华贵，是中国三家白金五星酒店之一。特别感谢前台服务员，给我们把房间升级了！让我们更加不虚此行！', '["https://dimg04.c-ctrip.com/images/0235e12000jcrhg0tB3E8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231p12000jct2n0q3F7E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000jcroc2d3E46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000jcsz4cu4C9E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-27', '花园大床房', '大床房', '朋友出游', 63, 4.158883083359672, 0, 0.0, 27, 3.332204510175204, 7, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '来广州一定要争取住花园酒店！雍容华贵，是中国三家白金五星酒店之一。特别感谢前台服', '来广州一定要争取住花园酒店！雍容华贵，是中国三家白金五星酒店之一。特别感谢前台服务员，给我们把房间升级了！让我们更加不虚此行！', '2025-03-27', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027915e3c98b094176577a', '费了半天口舌 那个岭汇峰金卡（好像是这个名吧 记不住了）终于派上用途给升了房型 红棉房还是真不错的 面积很大 客房很新 服务也算热情 酒店人巨多 好像是商务开会聚集地 定了三晚 只送了一个早餐卷 也没用上 每次路过都是站排 总体还是推荐的 附长隆动物图', '["https://dimg04.c-ctrip.com/images/0230612000hx33k365A89_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000hx0lye8FC18_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w12000hx2xk5j0E2C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000hx336if92DB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o12000hx0povy502A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000hx1kfla504A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231h12000hx20rgc5315_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000hx30w2i6B39_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000hx1dsdtDB44_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-20', '花园双床房', '双床房', '家庭亲子', 126, 4.844187086458591, 0, 0.0, 9, 2.302585092994046, 7, '["房间设施", "整体满意度", "前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '费了半天口舌 那个岭汇峰金卡（好像是这个名吧 记不住了）终于派上用途给升了房型 ', '费了半天口舌 那个岭汇峰金卡（好像是这个名吧 记不住了）终于派上用途给升了房型 红棉房还是真不错的 面积很大 客房很新 服务也算热情 酒店人巨多 好像是商务开会聚集地 定了三晚 只送了一个早餐卷 也没用上 每次路过都是站排 总体还是推荐的 附长隆动物图', '2025-01-20', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027915e3c98b094176577b', '服务：酒店的服务让人印象深刻，春节期间非常敬业。 行政酒廊，大堂的礼宾，公寓客房的服务都令人满意。
春节期间的布置，有节日的气氛。酒店内行政酒廊进去有个很大的后花园，还有瀑布。', '["https://dimg04.c-ctrip.com/images/0230c12000i8jbcsx42CA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000i8i1kod6C07_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000i8jlajs622A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000i8i0by0F0AE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231o12000i8joptoD7CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-02', '粤韵双床套房', '套房', '家庭亲子', 89, 4.499809670330265, 0, 0.0, 21, 3.091042453358316, 6, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '服务：酒店的服务让人印象深刻，春节期间非常敬业。 行政酒廊，大堂的礼宾，公寓客房', '服务：酒店的服务让人印象深刻，春节期间非常敬业。 行政酒廊，大堂的礼宾，公寓客房的服务都令人满意。
春节期间的布置，有节日的气氛。酒店内行政酒廊进去有个很大的后花园，还有瀑布。', '2025-02-02', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027915e3c98b094176577c', '住过的酒店不少，但离开后希望还有机会再次入住的酒店却很少。广州花园酒店是这很少之一。这次带了家里老人出行，选择入住花园酒店，优良的设施，便利的交通，白金五星的服务也让家人度过了非常愉快的假日。酒店自带的博物馆和有瀑布的中庭花园让我们很是惊喜，行政酒廊的出品和服务更让人印象深刻，在此特别感谢酒廊的Carrie、Mira、Berryle专业周到的服务，虽是短暂停逗，却令我们感觉如沐春风，宾至如归。', '["https://dimg04.c-ctrip.com/images/0230b12000gusr0hi1106_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000guthx6dE7A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000gus4srx62C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000gutmk1y06E4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000gusl87pAA89_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000guscemi1638_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000gus7qvtDBB7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000gusfvb74B65_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000gutip9zD8D6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-25', '花园双床房', '双床房', '其他', 198, 5.293304824724492, 0, 0.0, 29, 3.4011973816621555, 9, '["整体满意度", "交通便利性", "前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '住过的酒店不少，但离开后希望还有机会再次入住的酒店却很少。广州花园酒店是这很少之', '住过的酒店不少，但离开后希望还有机会再次入住的酒店却很少。广州花园酒店是这很少之一。这次带了家里老人出行，选择入住花园酒店，优良的设施，便利的交通，白金五星的服务也让家人度过了非常愉快的假日。酒店自带的博物馆和有瀑布的中庭花园让我们很是惊喜，行政酒廊的出品和服务更让人印象深刻，在此特别感谢酒廊的Carrie、Mira、Berryle专业周到的服务，虽是短暂停逗，却令我们感觉如沐春风，宾至如归。', '2024-11-25', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027915e3c98b094176577d', '服务非常满意，特别前台小姐姐给升级一房一厅客房啦??心情愉悦。这个老牌五星级酒店我在30年前来过，现在旧地重游还是感觉非常满意！特别是它家的后花园假山瀑布，绿色植物荷塘月色景致一流心旷神怡。这次我们房费还包括了行政酒廊欢乐时光，使用下来感觉质量非常满意，厨师水平比一般的五星级酒店高，精致味道超级好，特别有二个选项菜单，点的菜是米其林出品啊??前台后面的背景一如40年前大气豪华，有特色的原木旋转楼梯及二楼古色古香摆品都体现精致豪华。早餐还开放了30楼的旋转餐厅。这是一次完美的体验。', '["https://dimg04.c-ctrip.com/images/02342224x8ypjdbitCB74_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02310224x8ypklpzm5050_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02353224x8yplglzrFB19_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l224x8ypmmqqv04EB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02344224x8yplglzsD528_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o224x8ypji0cmDFED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-18', '花园双床房', '双床房', '情侣出游', 242, 5.493061443340548, 0, 0.0, 25, 3.258096538021482, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '服务非常满意，特别前台小姐姐给升级一房一厅客房啦??心情愉悦。这个老牌五星级酒店', '服务非常满意，特别前台小姐姐给升级一房一厅客房啦??心情愉悦。这个老牌五星级酒店我在30年前来过，现在旧地重游还是感觉非常满意！特别是它家的后花园假山瀑布，绿色植物荷塘月色景致一流心旷神怡。这次我们房费还包括了行政酒廊欢乐时光，使用下来感觉质量非常满意，厨师水平比一般的五星级酒店高，精致味道超级好，特别有二个选项菜单，点的菜是米其林出品啊??前台后面的背景一如40年前大气豪华，有特色的原木旋转楼梯及二楼古色古香摆品都体现精致豪华。早餐还开放了30楼的旋转餐厅。这是一次完美的体验。', '2025-01-18', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802791fe3c98b094176577e', '一家三口，由于工作关系四晚住了亚朵（五羊邨店2晚，太古汇2晚）只能说性价比非常低，爸爸果断选择了换花园，交通方便，吃住便利，环境怡人，订房文旅送了优惠券1间200元/每晚。只能说选花园红棉房太对了。和前台沟通带孩子避开头尾，安排的非常好呀。真是太满意了。虽没有早餐，但是酒店背后去吃了点都德早茶（超级近），还是得在本地点都德吃，非常好，孩子也高兴满意。', '["https://dimg04.c-ctrip.com/images/0232v12000i921ngu398F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235j12000i91bc9n288F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236512000i91wfez868E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000i90po2b9B50_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000i91kgh93446_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000i8zznha84D4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000i91h4zeD2F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000i91x52jE908_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000i91xv8v3A57_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-02', '红棉大床套房', '套房', '家庭亲子', 176, 5.176149732573829, 0, 0.0, 2, 1.0986122886681098, 8, '["性价比", "交通便利性", "前台服务"]'::jsonb, '性价比', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '一家三口，由于工作关系四晚住了亚朵（五羊邨店2晚，太古汇2晚）只能说性价比非常低', '一家三口，由于工作关系四晚住了亚朵（五羊邨店2晚，太古汇2晚）只能说性价比非常低，爸爸果断选择了换花园，交通方便，吃住便利，环境怡人，订房文旅送了优惠券1间200元/每晚。只能说选花园红棉房太对了。和前台沟通带孩子避开头尾，安排的非常好呀。真是太满意了。虽没有早餐，但是酒店背后去吃了点都德早茶（超级近），还是得在本地点都德吃，非常好，孩子也高兴满意。', '2025-02-02', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802791fe3c98b094176577f', '本地人第一次入住，体验不错，无论是大堂的装潢、香氛，还是房间的布局、设施都给我高级的感觉，入住第一感觉是卫生可靠。环境很安静。', '["https://dimg04.c-ctrip.com/images/0235v12000j85imwoB613_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000j85g4ja1D78_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000j84mztvE035_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-21', '花园大床房', '大床房', '独自旅行', 63, 4.158883083359672, 0, 0.0, 2, 1.0986122886681098, 7, '["整体满意度", "安静程度", "卫生状况"]'::jsonb, '整体满意度', '安静程度', '卫生状况', '未知酒店', '未知地点', '匿名', '本地人第一次入住，体验不错，无论是大堂的装潢、香氛，还是房间的布局、设施都给我高', '本地人第一次入住，体验不错，无论是大堂的装潢、香氛，还是房间的布局、设施都给我高级的感觉，入住第一感觉是卫生可靠。环境很安静。', '2025-03-21', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802791fe3c98b0941765780', '环境：后花园很气派，还有瀑布，小桥流水很优美
