INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802791fe3c98b0941765781', '房间酒店贴心服务，帮我们升级为套房，处处为客户着想，服务员微笑服务，打扫房间及时，酒店环境舒适温馨高雅。', '["https://dimg04.c-ctrip.com/images/0235o12000jct72xwC38B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000jcsil4cFFBA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-27', '花园双床房', '双床房', '家庭亲子', 52, 3.970291913552122, 0, 0.0, 4, 1.6094379124341005, 7, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '房间酒店贴心服务，帮我们升级为套房，处处为客户着想，服务员微笑服务，打扫房间及时', '房间酒店贴心服务，帮我们升级为套房，处处为客户着想，服务员微笑服务，打扫房间及时，酒店环境舒适温馨高雅。', '2025-03-27', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802791fe3c98b0941765782', '很好??！服务好，工作人员很耐心细致！不愧为五星级国际酒店！桃园馆定制早茶也有广式特色！特别是蛋塔很有风味！前台可以寄存物品。酒店管理很有秩序，很安全！真心觉得祖国很安全！', '["https://dimg04.c-ctrip.com/images/0230y12000i8ykbpp6B27_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000i8ywnz8D241_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000i8y2puw99DB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231o12000i8ynjyv98E6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-02', '花园双床房', '双床房', '家庭亲子', 86, 4.465908118654584, 0, 0.0, 5, 1.791759469228055, 8, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '很好??！服务好，工作人员很耐心细致！不愧为五星级国际酒店！桃园馆定制早茶也有广', '很好??！服务好，工作人员很耐心细致！不愧为五星级国际酒店！桃园馆定制早茶也有广式特色！特别是蛋塔很有风味！前台可以寄存物品。酒店管理很有秩序，很安全！真心觉得祖国很安全！', '2025-02-02', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802791fe3c98b0941765783', '住了七八次了，这次房间出了一点小小的问题。刘经理和麦经理先后帮我们细心处理，周到解决，都让我们感到非常不好意思了。所以，每次都是广州的入住首选。也在这里对两位巡房经理表示衷心的感谢！', '["https://dimg04.c-ctrip.com/images/0232s12000ie59s3g5441_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-08', '花园双床房', '双床房', '家庭亲子', 91, 4.5217885770490405, 0, 0.0, 4, 1.6094379124341005, 7, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '住了七八次了，这次房间出了一点小小的问题。刘经理和麦经理先后帮我们细心处理，周到', '住了七八次了，这次房间出了一点小小的问题。刘经理和麦经理先后帮我们细心处理，周到解决，都让我们感到非常不好意思了。所以，每次都是广州的入住首选。也在这里对两位巡房经理表示衷心的感谢！', '2025-02-08', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802791fe3c98b0941765784', '选择花园酒店是一个意外惊喜。
家人鼻子敏感 一直以来特别抗拒老旧酒店，主要是受不了沉积在排气管道、装饰里面的陈腐味道，比较偏向于选择5年内的新酒店。
被酒店的评论区以及多个米其林餐厅吸引，于是决定试试。进入酒店后，酒店浓浓的历史感经过岁月的沉淀以及酒店的用心维护，感受到的是古典、优雅、大气，更加惊喜的是它居然是剧院魅影的官方合作酒店，大堂中央放着经典的白色面具！可把孩子高兴坏了，我们大老远来就是来二刷魅影！这是一个意外的大彩蛋，好感度已经拉满。
另外一个惊喜是入住时，安排的低楼层接近装修项目，向酒店反映噪音问题后，马上进行了调整甚至升房，效率和服务很赞。因为孩子身体不适，延迟退房申请也安排得妥妥的，非常感谢！
套餐含夜茶任点，出品优秀，都是很经典的广府点心，推荐(＾ω＾)????', '["https://dimg04.c-ctrip.com/images/0234i12000hqf8r0p80DD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000hqf3htc60B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000hqfm21717AB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-12', '花园双床房', '双床房', '家庭亲子', 344, 5.84354441703136, 0, 0.0, 29, 3.4011973816621555, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '选择花园酒店是一个意外惊喜。', '选择花园酒店是一个意外惊喜。
家人鼻子敏感 一直以来特别抗拒老旧酒店，主要是受不了沉积在排气管道、装饰里面的陈腐味道，比较偏向于选择5年内的新酒店。
被酒店的评论区以及多个米其林餐厅吸引，于是决定试试。进入酒店后，酒店浓浓的历史感经过岁月的沉淀以及酒店的用心维护，感受到的是古典、优雅、大气，更加惊喜的是它居然是剧院魅影的官方合作酒店，大堂中央放着经典的白色面具！可把孩子高兴坏了，我们大老远来就是来二刷魅影！这是一个意外的大彩蛋，好感度已经拉满。
另外一个惊喜是入住时，安排的低楼层接近装修项目，向酒店反映噪音问题后，马上进行了调整甚至升房，效率和服务很赞。因为孩子身体不适，延迟退房申请也安排得妥妥的，非常感谢！
