INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802791fe3c98b0941765785', '酒店本身就是一个景点，很有设计感，酒店本身带有一个博物馆，很值得参观一下，就是人太多太杂，酒店的客房设施比较陈旧，而且设计有点不太合理，房间私密性不够，由于酒店周边在施工，有点噪音，不够安静，前台员工的服务意识有待提升，可能太忙的关系，全程都没笑脸，对于相关的酒店待遇没有主动介绍，还是客人自己提醒下才给予，感觉有点不太好，相比行政酒廊的员工就热情很多', '["https://dimg04.c-ctrip.com/images/0232a12000hs3f2naF521_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000hs33izl8D0F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000hs3b95u0CC2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-01-14', '花园大床房', '大床房', '家庭亲子', 176, 5.176149732573829, 2, 1.0986122886681098, 16, 2.833213344056216, 8, '["房间设施", "安静程度", "前台服务"]'::jsonb, '房间设施', '安静程度', '前台服务', '未知酒店', '未知地点', '匿名', '酒店本身就是一个景点，很有设计感，酒店本身带有一个博物馆，很值得参观一下，就是人', '酒店本身就是一个景点，很有设计感，酒店本身带有一个博物馆，很值得参观一下，就是人太多太杂，酒店的客房设施比较陈旧，而且设计有点不太合理，房间私密性不够，由于酒店周边在施工，有点噪音，不够安静，前台员工的服务意识有待提升，可能太忙的关系，全程都没笑脸，对于相关的酒店待遇没有主动介绍，还是客人自己提醒下才给予，感觉有点不太好，相比行政酒廊的员工就热情很多', '2025-01-14', 4, '房间设施');
