INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802791fe3c98b0941765787', '酒店有非常多的餐厅，中西餐厅日式餐厅都有，特别是有一个网红瀑布餐厅比较出名，很多人来到打卡，在酒店内就能够满足用餐需求。感谢前台Viria的介绍以及服务周到，给予好评！', '["https://dimg04.c-ctrip.com/images/0233n12000jg0r2pdEA60_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000jg0m34zA5FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000jg0aqmn710B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-31', '城央绿意双床房', '双床房', '朋友出游', 84, 4.442651256490317, 0, 0.0, 1, 0.6931471805599453, 8, '["餐饮设施", "前台服务"]'::jsonb, '餐饮设施', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '酒店有非常多的餐厅，中西餐厅日式餐厅都有，特别是有一个网红瀑布餐厅比较出名，很多', '酒店有非常多的餐厅，中西餐厅日式餐厅都有，特别是有一个网红瀑布餐厅比较出名，很多人来到打卡，在酒店内就能够满足用餐需求。感谢前台Viria的介绍以及服务周到，给予好评！', '2025-03-31', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802792ae3c98b0941765788', '酒店过年活动多，氛围很浓，一到酒店感觉很欢乐。房间很舒适，配有胶囊咖啡机，服务不错。一楼后面小花园修的很漂亮。只是设施稍显老旧，淋浴间漏水到隔壁马桶间，需要注意及时维修。', '["https://dimg04.c-ctrip.com/images/0235l12000i7zd6qk9D6C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000i7zd6qm5509_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000i7y6nh9C4A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000i7zd6qoD38E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-01', '红棉大床套房', '套房', '家庭亲子', 85, 4.454347296253507, 0, 0.0, 14, 2.70805020110221, 8, '["房间设施", "整体满意度", "卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店过年活动多，氛围很浓，一到酒店感觉很欢乐。房间很舒适，配有胶囊咖啡机，服务不', '酒店过年活动多，氛围很浓，一到酒店感觉很欢乐。房间很舒适，配有胶囊咖啡机，服务不错。一楼后面小花园修的很漂亮。只是设施稍显老旧，淋浴间漏水到隔壁马桶间，需要注意及时维修。', '2025-02-01', 4, '房间设施');
