INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802792ae3c98b094176578b', '一分钱一分货，这么老的酒店还是不错了，谢谢前台给我房间升级为套房，楼下花园还是很不错的，特别是瀑布。', '["https://dimg04.c-ctrip.com/images/0235r12000jcxo47zE671_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000jcxo481FECA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231h12000jcxrt549BF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-27', '花园大床房', '大床房', '商务出差', 50, 3.9318256327243257, 0, 0.0, 30, 3.4339872044851463, 6, '["整体满意度", "前台服务", "周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套', '未知酒店', '未知地点', '匿名', '一分钱一分货，这么老的酒店还是不错了，谢谢前台给我房间升级为套房，楼下花园还是很', '一分钱一分货，这么老的酒店还是不错了，谢谢前台给我房间升级为套房，楼下花园还是很不错的，特别是瀑布。', '2025-03-27', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802792ae3c98b094176578c', '春节带家里老小体验老牌的五星级酒店，环境服务都很好，过年的气氛也很浓，小朋友在花园里玩了很久，感谢前台ANN，服务态度非常好，还免费加赠了早餐，很美好的体验！', '["https://dimg04.c-ctrip.com/images/0232p12000ible13c4461_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000ibkzuklE21D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000ibl645v4D8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000ibl6tijBEF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 79, 4.382026634673881, 0, 0.0, 7, 2.079441541679836, 8, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '春节带家里老小体验老牌的五星级酒店，环境服务都很好，过年的气氛也很浓，小朋友在花', '春节带家里老小体验老牌的五星级酒店，环境服务都很好，过年的气氛也很浓，小朋友在花园里玩了很久，感谢前台ANN，服务态度非常好，还免费加赠了早餐，很美好的体验！', '2025-02-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802792ae3c98b094176578d', '花园酒店环境好，整洁干净，入住时前台升级了房间，服务人员热情周到，每天还送水果，下次来还住花园酒店。', '["https://dimg04.c-ctrip.com/images/0234h12000j9k6slq01C6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000j9k7kbh69AB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000j9jdwc0D173_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000j9k6z3t18F1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w12000j9k33vr338B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235x12000j9j37haCFE8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235b12000j9k4ruv5BD6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-23', '花园双床房', '双床房', '情侣出游', 50, 3.9318256327243257, 0, 0.0, 6, 1.9459101490553128, 7, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '花园酒店环境好，整洁干净，入住时前台升级了房间，服务人员热情周到，每天还送水果，', '花园酒店环境好，整洁干净，入住时前台升级了房间，服务人员热情周到，每天还送水果，下次来还住花园酒店。', '2025-03-23', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802792ae3c98b094176578e', '孩子不舒服，不小心吐在了床单上，服务人员耐心打扫，非常专业。酒店环境非常好，室内座椅有些老化。忘了东西在酒店，酒店及时联系并帮忙寄回。非常感谢！', '["https://dimg04.c-ctrip.com/images/0231y12000imcmrlq1EED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000imc1gn8FD13_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000imc8n7r61E5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-19', '花园双床房', '双床房', '家庭亲子', 72, 4.290459441148391, 0, 0.0, 4, 1.6094379124341005, 8, '["客房服务", "整体满意度", "房间设施"]'::jsonb, '客房服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '孩子不舒服，不小心吐在了床单上，服务人员耐心打扫，非常专业。酒店环境非常好，室内', '孩子不舒服，不小心吐在了床单上，服务人员耐心打扫，非常专业。酒店环境非常好，室内座椅有些老化。忘了东西在酒店，酒店及时联系并帮忙寄回。非常感谢！', '2025-02-19', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802792ae3c98b094176578f', '到酒店后前台把我的红棉房升级到了粤韵房，窗口正对着对面的白云宾馆的街口，酒店服务很好不愧是白金五星酒店，早晨早餐高峰和中午退房高峰时各楼层电梯口会安排服务生招呼客人，住过无数个酒店还是第一次看到这样的服务。
楼下就是地铁淘金站，外国住客多。免费参观酒店博物馆，整整在里面徜徉了45分钟，能看到很多东西，愿意拿出一个楼面做丝毫没有收益的博物馆，真壕。', '["https://dimg04.c-ctrip.com/images/0230l12000hnwl7jc7913_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000hnx172a8B65_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c12000hnwx0fe9C3B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000hnxbrhlC9CA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000hnw9zvrDD38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000hnxbmjx8933_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000hnw4m7sABA8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-01-08', '红棉双床套房', '套房', '朋友出游', 174, 5.1647859739235145, 0, 0.0, 61, 4.127134385045092, 9, '["前台服务", "交通便利性", "整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '到酒店后前台把我的红棉房升级到了粤韵房，窗口正对着对面的白云宾馆的街口，酒店服务', '到酒店后前台把我的红棉房升级到了粤韵房，窗口正对着对面的白云宾馆的街口，酒店服务很好不愧是白金五星酒店，早晨早餐高峰和中午退房高峰时各楼层电梯口会安排服务生招呼客人，住过无数个酒店还是第一次看到这样的服务。
楼下就是地铁淘金站，外国住客多。免费参观酒店博物馆，整整在里面徜徉了45分钟，能看到很多东西，愿意拿出一个楼面做丝毫没有收益的博物馆，真壕。', '2025-01-08', 4, '前台服务');
