INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802792ae3c98b0941765791', '花园房很小，进门就是一个浴缸，比较老式的风格，前台接待的服务很一般，携程的岭南客金卡有一份免费早餐，也是我自己问的，都不主动提起，入住收1000元押金，现在也不多见了。迷你吧都要收费。住的是一个情怀吧。下次不会再选择了。早餐也很一般。位置在中心。出门打车都很方便', '["https://dimg04.c-ctrip.com/images/0236s12000hjj3calEACD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o12000hjjaq602699_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233g12000hjit0xxBB98_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000hjiyhhh075A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2025-01-02', '花园大床房', '大床房', '家庭亲子', 131, 4.882801922586371, 1, 0.6931471805599453, 28, 3.367295829986474, 7, '["房间设施", "前台服务", "交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '花园房很小，进门就是一个浴缸，比较老式的风格，前台接待的服务很一般，携程的岭南客', '花园房很小，进门就是一个浴缸，比较老式的风格，前台接待的服务很一般，携程的岭南客金卡有一份免费早餐，也是我自己问的，都不主动提起，入住收1000元押金，现在也不多见了。迷你吧都要收费。住的是一个情怀吧。下次不会再选择了。早餐也很一般。位置在中心。出门打车都很方便', '2025-01-02', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027936e3c98b0941765792', '不愧是国内唯三的白金五星酒店，漂亮的瀑布花园，舒适的床品，优质的服务，改革开放历史见证，广州花园酒店值得再次入住。', '["https://dimg04.c-ctrip.com/images/0233v12000ivvkbi38D97_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000ivwc2xm8027_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234x12000ivvv2wa8F6E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000ivw5x8aD338_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000ivvqw8102A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000ivw0ehqF77D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-05', '花园大床房', '大床房', '情侣出游', 57, 4.060443010546419, 0, 0.0, 23, 3.1780538303479458, 8, '["整体满意度", "房间设施", "前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '不愧是国内唯三的白金五星酒店，漂亮的瀑布花园，舒适的床品，优质的服务，改革开放历', '不愧是国内唯三的白金五星酒店，漂亮的瀑布花园，舒适的床品，优质的服务，改革开放历史见证，广州花园酒店值得再次入住。', '2025-03-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027936e3c98b0941765793', '这次入住酒店，有幸遇见前台KIKI XU笑脸相迎，安排了舒适的房间，能遇见您，让我们的旅途变得更加美好。
        酒店在市中心，门口就是地铁站，去任何地方玩都很方便。
        酒店本身就是一个景点，有26个地方可以打卡，后花园很漂亮，不仅有水景假山，还挂着2条18米高的瀑布，4楼还有一个博物馆，住在这里有种世外桃源的感觉。
        祝酒店生意兴隆。', '["https://dimg04.c-ctrip.com/images/0233z12000h8buq6h138A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236412000h8bj1q4E577_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000h8c0agpC5A5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000h8cb71x288C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000h8bsyn9A5F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000h8bqa8zC251_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000h8cd3qd1380_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000h8c4sr1A00F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231z12000h8bfrdwF02A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-16', '花园双床房', '双床房', '其他', 187, 5.236441962829949, 0, 0.0, 43, 3.784189633918261, 8, '["前台服务", "交通便利性", "公共设施"]'::jsonb, '前台服务', '交通便利性', '公共设施', '未知酒店', '未知地点', '匿名', '这次入住酒店，有幸遇见前台KIKI XU笑脸相迎，安排了舒适的房间，能遇见您，让', '这次入住酒店，有幸遇见前台KIKI XU笑脸相迎，安排了舒适的房间，能遇见您，让我们的旅途变得更加美好。
        酒店在市中心，门口就是地铁站，去任何地方玩都很方便。
        酒店本身就是一个景点，有26个地方可以打卡，后花园很漂亮，不仅有水景假山，还挂着2条18米高的瀑布，4楼还有一个博物馆，住在这里有种世外桃源的感觉。
        祝酒店生意兴隆。', '2024-12-16', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027936e3c98b0941765794', '房间干净卫生，服务员态度很好，涉外酒店，入住客人多，早餐需要排队，但是用餐环境很好，顶楼还有旋转餐厅，可以边吃边欣赏城市景色，早饭品种很多，味道很棒！还有一个大花园，有瀑布，有金鱼，逛逛，大饱眼福。唯一不足房间有点小。', '["https://dimg04.c-ctrip.com/images/0230h12000jc5oh5l3F35_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000jc4roznCC8F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000jc5geev6CFF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-26', '花园双床房', '双床房', '情侣出游', 109, 4.700480365792417, 0, 0.0, 6, 1.9459101490553128, 8, '["卫生状况", "前台服务", "餐饮设施"]'::jsonb, '卫生状况', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '房间干净卫生，服务员态度很好，涉外酒店，入住客人多，早餐需要排队，但是用餐环境很', '房间干净卫生，服务员态度很好，涉外酒店，入住客人多，早餐需要排队，但是用餐环境很好，顶楼还有旋转餐厅，可以边吃边欣赏城市景色，早饭品种很多，味道很棒！还有一个大花园，有瀑布，有金鱼，逛逛，大饱眼福。唯一不足房间有点小。', '2025-03-26', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027936e3c98b0941765795', '位置很优越，就在地铁站旁边，去哪里都方便，马路对面的广州酒家菜品很好吃，酒店最出彩的是后花园，有山有水，树木茂盛，在里面悠闲惬意。早餐还是蛮丰富的，桃源阁的是广州特色定食，但得事先预约，用餐环境舒适。大堂金碧辉煌有点嘈杂', '["https://dimg04.c-ctrip.com/images/0232112000hjlchllB91D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000hjkrlctDF5D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000hjlq0au9FFB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235x12000hjld5048C23_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000hjln5gnC37E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2025-01-02', '城央绿意双床房', '双床房', '朋友出游', 110, 4.709530201312334, 0, 0.0, 42, 3.7612001156935615, 8, '["交通便利性", "周边配套", "餐饮设施"]'::jsonb, '交通便利性', '周边配套', '餐饮设施', '未知酒店', '未知地点', '匿名', '位置很优越，就在地铁站旁边，去哪里都方便，马路对面的广州酒家菜品很好吃，酒店最出', '位置很优越，就在地铁站旁边，去哪里都方便，马路对面的广州酒家菜品很好吃，酒店最出彩的是后花园，有山有水，树木茂盛，在里面悠闲惬意。早餐还是蛮丰富的，桃源阁的是广州特色定食，但得事先预约，用餐环境舒适。大堂金碧辉煌有点嘈杂', '2025-01-02', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027936e3c98b0941765796', '酒店外观很大，感觉很气派，所以选择入住，但是房间还是比较老旧的，差点意思，和现在新酒店相比还是新的酒店科技发达，关键充电地方多，这里还是老式的充电头，关键晚上的夜茶是真难吃，还有就是我想吐槽的，我老公证件忘记在房间，退房了两天既然也没有人和我联系，后来去机场发现没有了，又每个酒店去找，找到这里才给我们，说是疏忽了，难道这种重要的东西发现了不是这时间联系顾客的吗', '["https://dimg04.c-ctrip.com/images/0233e12000hldch6s0A26_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000hlciwhr9A5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000hld2x190BE5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000hld2x1bC406_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000hldaovhC58E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2025-01-05', '花园大床房', '大床房', '家庭亲子', 181, 5.204006687076795, 1, 0.6931471805599453, 2, 1.0986122886681098, 7, '["前台服务", "房间设施", "餐饮设施"]'::jsonb, '前台服务', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店外观很大，感觉很气派，所以选择入住，但是房间还是比较老旧的，差点意思，和现在', '酒店外观很大，感觉很气派，所以选择入住，但是房间还是比较老旧的，差点意思，和现在新酒店相比还是新的酒店科技发达，关键充电地方多，这里还是老式的充电头，关键晚上的夜茶是真难吃，还有就是我想吐槽的，我老公证件忘记在房间，退房了两天既然也没有人和我联系，后来去机场发现没有了，又每个酒店去找，找到这里才给我们，说是疏忽了，难道这种重要的东西发现了不是这时间联系顾客的吗', '2025-01-05', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027936e3c98b0941765797', '房间很安静，设施齐全，送餐服务及时周到，下午可以在花园散步，很适合放空', '["https://dimg04.c-ctrip.com/images/0230g12000jq3fmfp5ADD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000jq357w77697_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000jq4bb259C40_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-11', '红棉大床套房', '套房', '商务出差', 35, 3.58351893845611, 0, 0.0, 41, 3.737669618283368, 7, '["安静程度", "客房服务", "整体满意度"]'::jsonb, '安静程度', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '房间很安静，设施齐全，送餐服务及时周到，下午可以在花园散步，很适合放空', '房间很安静，设施齐全，送餐服务及时周到，下午可以在花园散步，很适合放空', '2025-04-11', 5, '安静程度');
