INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027941e3c98b094176579c', '期待的广州花园酒店没有让我们失望
一进大堂就感受到大气，真金剪纸壁画显示了红楼梦的故事情节，流程和导引非常高效，办理入住的小丘非常专业和亲切，作为金卡会员不但给了升级还体贴地赠送了小朋友的早餐！非常感动！房间也非常舒适，门口就有地铁站 下次来一定还住这里', '["https://dimg04.c-ctrip.com/images/0231512000iar8c4n5AFD_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233u12000iar7h2x0352_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232q12000iar6fufDA16_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234z12000iar7slx56C0_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232312000iar7h39FE71_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234n12000iar8evb65C7_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232g12000iar7cmxBF0D_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-02-04', '花园双床房', '双床房', '家庭亲子', 127, 4.852030263919617, 0, 0.0, 12, 2.5649493574615367, 9, '["前台服务", "交通便利性", "整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '期待的广州花园酒店没有让我们失望', '期待的广州花园酒店没有让我们失望
一进大堂就感受到大气，真金剪纸壁画显示了红楼梦的故事情节，流程和导引非常高效，办理入住的小丘非常专业和亲切，作为金卡会员不但给了升级还体贴地赠送了小朋友的早餐！非常感动！房间也非常舒适，门口就有地铁站 下次来一定还住这里', '2025-02-04', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027941e3c98b094176579d', '这个酒店最难受的是开放式卫生间。洗澡间和卫生间共用一个推拉门；然后与床之间也是一个半玻璃门隔开的。俩人入住，一个人洗澡，另一个人最上卫生间就是敞开式，真是不方便。
     我们的房间外面有个大工地，似乎是在修地铁，工地的噪声夜里还是听的听清楚的。
   不过酒店的工作人员服务很不错！ 不管是大堂还是前台，房间、餐厅，服务人员都非常有礼貌。 早餐也算是丰富了。作为老牌五星级酒店，健身房确实差一些，尤其是健身人员素质太差（这个不能怪酒店）。
    酒店位置还不错，门口就有5号线地铁。', '["https://dimg04.c-ctrip.com/images/0231x12000hd5y20qD08C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235b12000hd6wegvB624_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-12-23', '花园双床房', '双床房', '朋友出游', 244, 5.501258210544727, 1, 0.6931471805599453, 25, 3.258096538021482, 8, '["房间设施", "安静程度", "前台服务"]'::jsonb, '房间设施', '安静程度', '前台服务', '未知酒店', '未知地点', '匿名', '这个酒店最难受的是开放式卫生间。洗澡间和卫生间共用一个推拉门；然后与床之间也是一', '这个酒店最难受的是开放式卫生间。洗澡间和卫生间共用一个推拉门；然后与床之间也是一个半玻璃门隔开的。俩人入住，一个人洗澡，另一个人最上卫生间就是敞开式，真是不方便。
     我们的房间外面有个大工地，似乎是在修地铁，工地的噪声夜里还是听的听清楚的。
   不过酒店的工作人员服务很不错！ 不管是大堂还是前台，房间、餐厅，服务人员都非常有礼貌。 早餐也算是丰富了。作为老牌五星级酒店，健身房确实差一些，尤其是健身人员素质太差（这个不能怪酒店）。
    酒店位置还不错，门口就有5号线地铁。', '2024-12-23', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027941e3c98b094176579e', '一如既往的好。作为广州地标酒店，也并不是停步不前，而是一直在进步。服务也有提升，谢谢小宁和小鱼。床品舒适。早餐比以前好吃了', '["https://dimg04.c-ctrip.com/images/0231912000jg74qanD577_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-31', '花园大床房', '大床房', '商务出差', 61, 4.127134385045092, 0, 0.0, 9, 2.302585092994046, 7, '["整体满意度", "房间设施", "餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '一如既往的好。作为广州地标酒店，也并不是停步不前，而是一直在进步。服务也有提升，', '一如既往的好。作为广州地标酒店，也并不是停步不前，而是一直在进步。服务也有提升，谢谢小宁和小鱼。床品舒适。早餐比以前好吃了', '2025-03-31', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027941e3c98b094176579f', '过年安排在花园酒店，整个气氛很欢乐。酒店各个部门服务都很热情，在酒店用了早茶，也吃了年夜饭。新年第一天也看了舞狮。房间设施也很好。交通地铁也方便。', '["https://dimg04.c-ctrip.com/images/0233412000i8ryjk086EA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000i8t39te9E7F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-02', '花园大床房', '大床房', '家庭亲子', 73, 4.30406509320417, 0, 0.0, 32, 3.49650756146648, 7, '["整体满意度", "房间设施", "交通便利性"]'::jsonb, '整体满意度', '房间设施', '交通便利性', '未知酒店', '未知地点', '匿名', '过年安排在花园酒店，整个气氛很欢乐。酒店各个部门服务都很热情，在酒店用了早茶，也', '过年安排在花园酒店，整个气氛很欢乐。酒店各个部门服务都很热情，在酒店用了早茶，也吃了年夜饭。新年第一天也看了舞狮。房间设施也很好。交通地铁也方便。', '2025-02-02', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027941e3c98b09417657a0', '其实是一家很有特色的酒店，只是酒廊太太太太太拉夸，餐食一般服务更差，严重减分。
先说有点：在寸土寸金的广州中心地带能拥有小桥流水的岭南风格园林，甚至还有专门为此准备的导览参观活动，足见花园酒店作为一家白金五星级酒店的实力。而且这家酒店负责房务的叔叔阿姨特别热情亲切，是我在别的酒店没有感受过的。
但是，三天两晚的住宿中，花园酒廊拙劣的服务让我和家人一次次感到震惊：先是第一晚，19时许进入酒廊后是一条非常昏暗的通道，唯一的光源就是桌子上的蓝色小夜灯，等走到中心区域后也没有空余座位，虽然当时有两名服务人员，但是并没有解决座位问题，只是表示只能坐在黑暗的过道区域座位，我们询问是否能将过道区域顶灯打开，服务人员竟然答复“老板不喜欢开灯，所以开不了”，最后我们通知当天外籍值班经理到场交涉，在表达了我们不满以及不开灯可能造成客人受伤等安全问题后，经过十多分钟协调才打开了灯。第二天下午，到酒廊享用下午茶，我母亲想坐在室外区域，询问当日酒廊外籍管理人员后表示户外区域是酒吧（对，酒吧酒廊共用一个区域）客人专属座位，我们便在室内区域落座，但是发现有多波酒廊客人落座户外区域，当时酒廊内客人不多且有三名以上工作人员，均没有对这种行为进行劝阻制止，甚至在酒廊客人是否可以坐在户外的问题上不同服务人员回答都有分歧，而我和母亲只是因为“听*话”就遭到了区别对待，让我们非常恼火。
以上情况，在向酒店值班经理等领导层反馈后，也只是得到了敷衍回答，并没有实际解决问题。
综上，花园酒店给我的感觉就是金絮其外败絮其中，顶着白金五星级酒店的名号，却在本应该是加分项的酒廊，给客人极差的体验。
顺便说一句，酒店酒吧酒廊共用空间，而酒吧并未按照《中华人民共和国未成年人保护法》第五十八条　（营业性酒吧等不适宜未成年人活动场所的经营者，不得允许未成年人进入。经营者应当在显著位置设置未成年人禁入、限入标志；对难以判明是否是未成年人的，应当要求其出示身份证件）规定执行，此情况已向相关部门反映，也请酒店积极整改！', '["https://dimg04.c-ctrip.com/images/0231s12000hzwsavu5CBB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000hzwjuhzADB2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000hzvxnj9B655_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000hzwzqh8C2C3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2025-01-22', '花园双床房', '双床房', '家庭亲子', 840, 6.734591659972948, 0, 0.0, 5, 1.791759469228055, 9, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '其实是一家很有特色的酒店，只是酒廊太太太太太拉夸，餐食一般服务更差，严重减分。', '其实是一家很有特色的酒店，只是酒廊太太太太太拉夸，餐食一般服务更差，严重减分。
先说有点：在寸土寸金的广州中心地带能拥有小桥流水的岭南风格园林，甚至还有专门为此准备的导览参观活动，足见花园酒店作为一家白金五星级酒店的实力。而且这家酒店负责房务的叔叔阿姨特别热情亲切，是我在别的酒店没有感受过的。
但是，三天两晚的住宿中，花园酒廊拙劣的服务让我和家人一次次感到震惊：先是第一晚，19时许进入酒廊后是一条非常昏暗的通道，唯一的光源就是桌子上的蓝色小夜灯，等走到中心区域后也没有空余座位，虽然当时有两名服务人员，但是并没有解决座位问题，只是表示只能坐在黑暗的过道区域座位，我们询问是否能将过道区域顶灯打开，服务人员竟然答复“老板不喜欢开灯，所以开不了”，最后我们通知当天外籍值班经理到场交涉，在表达了我们不满以及不开灯可能造成客人受伤等安全问题后，经过十多分钟协调才打开了灯。第二天下午，到酒廊享用下午茶，我母亲想坐在室外区域，询问当日酒廊外籍管理人员后表示户外区域是酒吧（对，酒吧酒廊共用一个区域）客人专属座位，我们便在室内区域落座，但是发现有多波酒廊客人落座户外区域，当时酒廊内客人不多且有三名以上工作人员，均没有对这种行为进行劝阻制止，甚至在酒廊客人是否可以坐在户外的问题上不同服务人员回答都有分歧，而我和母亲只是因为“听*话”就遭到了区别对待，让我们非常恼火。
以上情况，在向酒店值班经理等领导层反馈后，也只是得到了敷衍回答，并没有实际解决问题。
综上，花园酒店给我的感觉就是金絮其外败絮其中，顶着白金五星级酒店的名号，却在本应该是加分项的酒廊，给客人极差的体验。
顺便说一句，酒店酒吧酒廊共用空间，而酒吧并未按照《中华人民共和国未成年人保护法》第五十八条　（营业性酒吧等不适宜未成年人活动场所的经营者，不得允许未成年人进入。经营者应当在显著位置设置未成年人禁入、限入标志；对难以判明是否是未成年人的，应当要求其出示身份证件）规定执行，此情况已向相关部门反映，也请酒店积极整改！', '2025-01-22', 3, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027941e3c98b09417657a1', '酒店超赞，不愧是白金五星，除了前台服务，其它酒店员工都很好。前台基本都板着脸，岭南金卡权益点一点拜一拜，不会主动把权益给你，赠送行政酒廊和早餐等，你提了，会给你加到备注里，不提就没有。', '["https://dimg04.c-ctrip.com/images/0236m12000hjj3qtf29AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000hji5rq590F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000hjijdy86431_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2025-01-02', '花园双床房', '双床房', '家庭亲子', 92, 4.532599493153256, 0, 0.0, 18, 2.9444389791664403, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店超赞，不愧是白金五星，除了前台服务，其它酒店员工都很好。前台基本都板着脸，岭', '酒店超赞，不愧是白金五星，除了前台服务，其它酒店员工都很好。前台基本都板着脸，岭南金卡权益点一点拜一拜，不会主动把权益给你，赠送行政酒廊和早餐等，你提了，会给你加到备注里，不提就没有。', '2025-01-02', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027941e3c98b09417657a2', '升级了套房，对着花园瀑布，入住当天等了太久所以送了酒店的欢乐时光，早餐1楼是瀑布餐厅无猪肉非常适合挑食的我，30楼是旋转餐厅，都很有特色，酒店本身自带的花园很舒服。酒店服务很好，感谢热情的carrie小姐姐给我们拍照。空调和马桶年代久远来的时候维修耽误了时间，总体瑕不掩瑜。提一点建议，打电话问酒店要蚊香和晾衣架接线的人说没有，还好奇为啥五星酒店这都不配，但是最后都送过来了，接线员连感觉酒店有啥都不知道', '["https://dimg04.c-ctrip.com/images/0235i12000ighceckEC50_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000igh4mzp958E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000iggytz2825D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000ighbvieA6B2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-11', '花园双床房', '双床房', '家庭亲子', 202, 5.313205979041787, 0, 0.0, 18, 2.9444389791664403, 8, '["景观/朝向", "餐饮设施", "客房服务"]'::jsonb, '景观/朝向', '餐饮设施', '客房服务', '未知酒店', '未知地点', '匿名', '升级了套房，对着花园瀑布，入住当天等了太久所以送了酒店的欢乐时光，早餐1楼是瀑布', '升级了套房，对着花园瀑布，入住当天等了太久所以送了酒店的欢乐时光，早餐1楼是瀑布餐厅无猪肉非常适合挑食的我，30楼是旋转餐厅，都很有特色，酒店本身自带的花园很舒服。酒店服务很好，感谢热情的carrie小姐姐给我们拍照。空调和马桶年代久远来的时候维修耽误了时间，总体瑕不掩瑜。提一点建议，打电话问酒店要蚊香和晾衣架接线的人说没有，还好奇为啥五星酒店这都不配，但是最后都送过来了，接线员连感觉酒店有啥都不知道', '2025-02-11', 5, '景观/朝向');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027941e3c98b09417657a3', '大堂、餐厅、花园等公共区域环境很好。房间有点儿小，有咖啡机很不错，茶难喝，打扫的非常及时。
