INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802794be3c98b09417657a9', '老牌的五星酒店，外国客人很多，服务员很热情，这点南方酒店胜出一大截。酒店出门就是地铁，工作日入住酒店给升了套间，本身的套餐包含了早餐和夜茶，所以性价比实在太高了。推荐！', '["https://dimg04.c-ctrip.com/images/0236s12000i9wmjzp3021_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000i9we0573795_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o12000i9wuyq39E38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y12000i9wnvw2438C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q12000i9wtu3jBDCC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000i9xd5t70FFD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-03', '花园双床房', '双床房', '家庭亲子', 84, 4.442651256490317, 0, 0.0, 6, 1.9459101490553128, 8, '["性价比", "交通便利性", "前台服务"]'::jsonb, '性价比', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '老牌的五星酒店，外国客人很多，服务员很热情，这点南方酒店胜出一大截。酒店出门就是', '老牌的五星酒店，外国客人很多，服务员很热情，这点南方酒店胜出一大截。酒店出门就是地铁，工作日入住酒店给升了套间，本身的套餐包含了早餐和夜茶，所以性价比实在太高了。推荐！', '2025-02-03', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802794be3c98b09417657aa', '度假结束了，有时间来好好写点评，看中花园酒店的位置，定了套餐，更看重花园酒店的历史酒店礼宾部John下午的酒店导览对我们这次入住花园酒店是最大的加分，不仅让我们了解了花园酒店的历史更了解了广州作为我国改革开放前沿的窗口的不同，当内地还在继续计划经济的时候，广州已经在吸引外资了，我们的港澳同胞们作为祖国改革开放的坚定拥护者，爱国拳拳之心！花园酒店的花园，瀑布，大锦鲤都让人印象深刻，遗憾的是广州的美食太多，酒店的套餐都没来得及吃，唯一吃了一次早餐一楼是要排队的还是顶楼的比较好！再次感谢John给我们的导览，还有前台Betty的鲜花，给我们的圣诞假期带来了美好的开始！', '["https://dimg04.c-ctrip.com/images/0234512000hkooj6aE601_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000hkonnha36C2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000hko1mh607DB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000hko1mh8A492_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000hkntxug7CA5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-03', '花园双床房', '双床房', '家庭亲子', 284, 5.652489180268651, 0, 0.0, 0, 0.0, 9, '["前台服务", "周边配套", "整体满意度"]'::jsonb, '前台服务', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '度假结束了，有时间来好好写点评，看中花园酒店的位置，定了套餐，更看重花园酒店的历', '度假结束了，有时间来好好写点评，看中花园酒店的位置，定了套餐，更看重花园酒店的历史酒店礼宾部John下午的酒店导览对我们这次入住花园酒店是最大的加分，不仅让我们了解了花园酒店的历史更了解了广州作为我国改革开放前沿的窗口的不同，当内地还在继续计划经济的时候，广州已经在吸引外资了，我们的港澳同胞们作为祖国改革开放的坚定拥护者，爱国拳拳之心！花园酒店的花园，瀑布，大锦鲤都让人印象深刻，遗憾的是广州的美食太多，酒店的套餐都没来得及吃，唯一吃了一次早餐一楼是要排队的还是顶楼的比较好！再次感谢John给我们的导览，还有前台Betty的鲜花，给我们的圣诞假期带来了美好的开始！', '2025-01-03', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802794be3c98b09417657ab', '装修很豪华美丽，外观、花园、大厅都非常漂亮，古典优雅，地段也很好，出行方便，周围吃喝玩乐都很丰富，但是毕竟是老酒店，房间很小，水池、浴室、墙角等角落也能看到发霉发黑，房间阴冷，被子也冰冰的，而且前台办入住非常慢，如果不是商务出行，自家出游的话，这个价位可以定综合水平更舒适的', '["https://dimg04.c-ctrip.com/images/0234112000hixaxjx28BD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235712000hix76rs8B75_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2025-01-01', '花园双床房', '双床房', '商务出差', 137, 4.927253685157205, 1, 0.6931471805599453, 4, 1.6094379124341005, 9, '["房间设施", "前台服务", "交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '装修很豪华美丽，外观、花园、大厅都非常漂亮，古典优雅，地段也很好，出行方便，周围', '装修很豪华美丽，外观、花园、大厅都非常漂亮，古典优雅，地段也很好，出行方便，周围吃喝玩乐都很丰富，但是毕竟是老酒店，房间很小，水池、浴室、墙角等角落也能看到发霉发黑，房间阴冷，被子也冰冰的，而且前台办入住非常慢，如果不是商务出行，自家出游的话，这个价位可以定综合水平更舒适的', '2025-01-01', 3, '房间设施');
