INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802794be3c98b09417657ad', '房间很大，安静干净，早餐在一楼瀑布餐厅和30楼旋转餐厅，风景不错。前台服务员业务熟悉，态度热情，保安非常主动帮助拿行李。酒店很大，管理到位。', '["https://dimg04.c-ctrip.com/images/0230x12000i6jz8vj5F54_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000i6kc5nj5BEA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000i6l0rwe785C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000i6lhpkwD0F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000i6kzz5196DC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000i6lcdwx05E7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-31', '花园大床房', '大床房', '家庭亲子', 70, 4.262679877041316, 0, 0.0, 48, 3.8918202981106265, 8, '["整体满意度", "前台服务", "安静程度"]'::jsonb, '整体满意度', '前台服务', '安静程度', '未知酒店', '未知地点', '匿名', '房间很大，安静干净，早餐在一楼瀑布餐厅和30楼旋转餐厅，风景不错。前台服务员业务', '房间很大，安静干净，早餐在一楼瀑布餐厅和30楼旋转餐厅，风景不错。前台服务员业务熟悉，态度热情，保安非常主动帮助拿行李。酒店很大，管理到位。', '2025-01-31', 5, '整体满意度');
