INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027957e3c98b09417657b3', '到酒店那天，出租车到正门口，没有服务员来开门与拿行李，我们带着孩子自己拿大包小包进门的。
酒店虽然不是很新，但是维护的很好。我们带小孩，酒店没有床围，我们订的房型大床才1.8米，没办法睡觉，交涉后才给我们升级了房型，但是真正入住是到5、6点才好的。我们吃完饭才回大堂拿了房卡并知道了房号，真的是第一次的体验。
