INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027957e3c98b09417657b8', '房间和外部看的出年份，也看的出一直不断改进的影子，总体对得起5星，携程的套餐写的定制早餐也没明确指引，早餐地方太多了。', '["https://dimg04.c-ctrip.com/images/0230612000ib2kfx7AF31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000ib24mvs009C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000ib20133B71A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-04', '花园双床房', '双床房', '家庭亲子', 59, 4.0943445622221, 0, 0.0, 25, 3.258096538021482, 6, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '房间和外部看的出年份，也看的出一直不断改进的影子，总体对得起5星，携程的套餐写的', '房间和外部看的出年份，也看的出一直不断改进的影子，总体对得起5星，携程的套餐写的定制早餐也没明确指引，早餐地方太多了。', '2025-02-04', 4, '餐饮设施');
