INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027962e3c98b09417657be', '来广州住这个酒店很开心的。酒店大堂宽敞明亮，各种设施齐全，酒店的花园景观别致，服务人员随时给提供帮助，早餐很美味', '["https://dimg04.c-ctrip.com/images/0235h12000iidf3vz7A5F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000iiccf3i9789_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000iicerb997BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-13', '花园双床房', '双床房', '家庭亲子', 56, 4.04305126783455, 0, 0.0, 11, 2.4849066497880004, 7, '["整体满意度", "公共设施", "餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '来广州住这个酒店很开心的。酒店大堂宽敞明亮，各种设施齐全，酒店的花园景观别致，服', '来广州住这个酒店很开心的。酒店大堂宽敞明亮，各种设施齐全，酒店的花园景观别致，服务人员随时给提供帮助，早餐很美味', '2025-02-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027962e3c98b09417657bf', '整体体验还是挺不错的，老牌酒店很有韵味，酒店里的内容也很丰富，博物馆很用心的了。房间层走廊确实比较偏低，但也是那个年代的特殊产物。房间里头淋浴间和厕所的门只能关其一的设计比较神奇，但其实也不太方便，尤其是双床房的话。水龙头的位置让水开大的时候容易溅出来。', '["https://dimg04.c-ctrip.com/images/0231v12000gz7miui60BD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000gz78s4u7A76_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000gz78h4q3C1A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.3, 4, '2024-12-01', '花园双床房', '双床房', '情侣出游', 127, 4.852030263919617, 2, 1.0986122886681098, 19, 2.995732273553991, 7, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '整体体验还是挺不错的，老牌酒店很有韵味，酒店里的内容也很丰富，博物馆很用心的了。', '整体体验还是挺不错的，老牌酒店很有韵味，酒店里的内容也很丰富，博物馆很用心的了。房间层走廊确实比较偏低，但也是那个年代的特殊产物。房间里头淋浴间和厕所的门只能关其一的设计比较神奇，但其实也不太方便，尤其是双床房的话。水龙头的位置让水开大的时候容易溅出来。', '2024-12-01', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027962e3c98b09417657c0', '过年期间去的，酒店非常有节日氛围，家人都非常满意。酒店服务也非常好，还送了下午茶，房间升了级！选对了一切都是最好的安排！', '["https://dimg04.c-ctrip.com/images/0234i12000iiojx2vA6DB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235t12000iipx18t24F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-14', '红棉大床套房', '套房', '家庭亲子', 60, 4.110873864173311, 0, 0.0, 13, 2.6390573296152584, 7, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '过年期间去的，酒店非常有节日氛围，家人都非常满意。酒店服务也非常好，还送了下午茶', '过年期间去的，酒店非常有节日氛围，家人都非常满意。酒店服务也非常好，还送了下午茶，房间升了级！选对了一切都是最好的安排！', '2025-02-14', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027962e3c98b09417657c1', '结论：整家酒店充斥着老广的精明算计和散漫。
先说优点：设计经典、大堂富丽堂皇、博物馆用心、后花园不错、房间维护尚可（红棉）、服务人员主动问好。
再说槽点，实在太多了，只能挑重点讲。
1. 前台极其不专业：效率低，排队久，期间还被几个老头插队。最活久见的是，办完给房卡，哪里坐电梯、几点吃早餐在哪里、酒店有什么设施全靠自己问，这东西不应该是主动介绍的吗？
2. 流程是混乱的。举个例子：早餐到了瀑布餐厅，说要排队，让去旋转餐厅，说那里人少，不用排队，到了 30 楼之后，跟我说前面还要等三桌。我？？？最关键是看到餐厅里还有好几张空桌子，写着 reserved，那好，你们早餐还需要预定我接受，那么能不能入住的时候提前告知我预定方式？？ 还有晚餐，打电话订荔湾亭，说订满了，问说想吃怎么办，必须 7 点半以后再来排队，来早了都不行；对比白天鹅宾馆，人家玉堂春暖提前一周打电话主动提醒预定，并且住店客人有优先预定权。随后订桃园馆，桃园馆问我是哪个房间的？因为酒店跟餐厅是分开运营的，所以还得留一遍电话。最关键的来了，结账说挂账，服务员说押金不够，我说不够那我现场补？不行，生带着我走回一楼前台刷了押金。
3. 服务人员素质参差不齐，看人下菜。为什么说参差不齐，是因为我觉得有些工作人员很认真负责，比如博物馆；因为订的携程套餐包含了小礼物，前台不会主动说，问了就说去给你找，然后还要提前强调这是随机的哦不能选，绝了；对比之前住过的君悦，人家公仔或者小朋友玩具都是主动赠予的，花园酒店是你去要，要完还跟你说不能随便选。桃园中餐厅，连续 7 年的米其林，点菜的时候跟我说房间五折这不能用那不能用，我寻思算了就点按道上的套餐好了，菜单拿过来，直接甩一句“我们套餐最便宜一个人 388”，醉了。米其林吃过不止 10 家，第一次被这么服务。
4. 还有一些其他的住多了五星级就容易发现的毛病，比如: 酒店大堂混乱（来回几次没见着大堂经理）各种网红 司机 游客，比较无序；房间洗手台设计容易溢水以及马桶浴缸非常旧（无智能马桶就不说了 每盖一次 bang 的巨响一次）；四楼酒店还连着一堆对外出租的写字楼并且看到有非酒店住客过来健身的（对外出租创收没问题但请确保隐私性）；楼下淘金站有大型工地，噪音不小，没办法睡午觉，这个很多人都提过，不再赘述。
总而言之：当初抱着对全国唯一一家民族品牌白金五星级的期待来，来了之后有点担心这样的酒店管理对不起贝聿铭先生的设计，对不起邓小平的题字，对不起“民族品牌”四个字。', '["https://dimg04.c-ctrip.com/images/0235212000gza72rg4033_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000gz9mg8x5D95_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000gz9mzqgCBF9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v12000gzabr4aB3B1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000gz9fnid7CDC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000gz9o1a1E6E7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000gz9eg9gCB7C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.6, 2, '2024-12-01', '红棉大床套房', '套房', '家庭亲子', 1050, 6.957497370876951, 37, 3.6375861597263857, 2, 1.0986122886681098, 9, '["前台服务", "整体满意度", "退房/入住效率"]'::jsonb, '前台服务', '整体满意度', '退房/入住效率', '未知酒店', '未知地点', '匿名', '结论：整家酒店充斥着老广的精明算计和散漫。', '结论：整家酒店充斥着老广的精明算计和散漫。
