INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027971e3c98b09417657c6', '房间虽然不大但配置很齐全，服务很好，非常满意的一次体验！套餐包含的东西也很正！酒店环境和位置是真的好到没得说！', '["https://dimg04.c-ctrip.com/images/0234s12000idfrefv8101_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234k12000idfm1gc36B2_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-02-07', '花园双床房', '双床房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 14, 2.70805020110221, 7, '["整体满意度", "房间设施", "周边配套"]'::jsonb, '整体满意度', '房间设施', '周边配套', '未知酒店', '未知地点', '匿名', '房间虽然不大但配置很齐全，服务很好，非常满意的一次体验！套餐包含的东西也很正！酒', '房间虽然不大但配置很齐全，服务很好，非常满意的一次体验！套餐包含的东西也很正！酒店环境和位置是真的好到没得说！', '2025-02-07', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027971e3c98b09417657c7', '前台02工作人员服务专业效率高几分钟就办好了入住手续，还主动帮我们升级了房间太惊喜了，无论是咨询还是解决问题都非常迅速，让人感到非常安心。', '["https://dimg04.c-ctrip.com/images/0230512000imnpg6p443A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000imo3xpd6FE6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000imnmd0zCEC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000imn90yw0583_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-20', '红棉大床套房', '套房', '商务出差', 69, 4.248495242049359, 0, 0.0, 5, 1.791759469228055, 9, '["前台服务", "退房/入住效率"]'::jsonb, '前台服务', '退房/入住效率', NULL, '未知酒店', '未知地点', '匿名', '前台02工作人员服务专业效率高几分钟就办好了入住手续，还主动帮我们升级了房间太惊', '前台02工作人员服务专业效率高几分钟就办好了入住手续，还主动帮我们升级了房间太惊喜了，无论是咨询还是解决问题都非常迅速，让人感到非常安心。', '2025-02-20', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027971e3c98b09417657c8', '酒店位置非常好，离地铁近，酒店门口一直有排队的出租车，出行方便，酒店大堂很漂亮，房间忘了拍照了，酒店早餐丰富', '["https://dimg04.c-ctrip.com/images/0232u12000ibpdzcb794A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-05', '城央绿意双床房', '双床房', '家庭亲子', 54, 4.007333185232471, 0, 0.0, 22, 3.1354942159291497, 7, '["交通便利性", "周边配套", "餐饮设施"]'::jsonb, '交通便利性', '周边配套', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店位置非常好，离地铁近，酒店门口一直有排队的出租车，出行方便，酒店大堂很漂亮，', '酒店位置非常好，离地铁近，酒店门口一直有排队的出租车，出行方便，酒店大堂很漂亮，房间忘了拍照了，酒店早餐丰富', '2025-02-05', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027971e3c98b09417657c9', '房间窗户一点点都不能打开通风，房间设施维护比较一般。房间很小，两个人住，卫生间都转不了身。住了两个晚上，行政酒廊都挺好吃，即使快结束了，看到有人来，还会补吃的。在此特别感谢印度裔Carrie，服务特别亲切，表扬Carrie，唯独你留下了好印象。其他的服务人员都不咋滴了，特别是前台办理入住的人员得多加培训，感觉对工作有怨气。', '["https://dimg04.c-ctrip.com/images/0236712000i5rqw1g67DB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000i5qw0b62CBE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-01-30', '花园大床房', '大床房', '家庭亲子', 162, 5.093750200806762, 0, 0.0, 37, 3.6375861597263857, 8, '["房间设施", "前台服务", "餐饮设施"]'::jsonb, '房间设施', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '房间窗户一点点都不能打开通风，房间设施维护比较一般。房间很小，两个人住，卫生间都', '房间窗户一点点都不能打开通风，房间设施维护比较一般。房间很小，两个人住，卫生间都转不了身。住了两个晚上，行政酒廊都挺好吃，即使快结束了，看到有人来，还会补吃的。在此特别感谢印度裔Carrie，服务特别亲切，表扬Carrie，唯独你留下了好印象。其他的服务人员都不咋滴了，特别是前台办理入住的人员得多加培训，感觉对工作有怨气。', '2025-01-30', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027971e3c98b09417657ca', '酒店在市区，周边就是商场，酒店门口车子多，看来入住的人也比较多，店内服务先生小姐热情，办入住的时候还收到送的鲜花好开心，同时也看到沙特航空公司的几位漂亮小姐?也在办理入住，酒店有不少外宾入住，酒店楼上有一个层面还有介绍该酒店的一个历史的博物馆，?我也进去参观了挺好的，酒店有40多年历史不少名人居住过大名在外，店内大堂气派，早餐丰富，味道也好，用早餐的地方也能看到窗外的人造瀑布?。因为酒店建得早停车要停到地下人上来的时候要绕一条过道从酒店后门进酒店?不是太方便，房间干净，样式老了一点，在房间也收到了酒店送的送了点心好温馨，谢谢酒店了！??', '["https://dimg04.c-ctrip.com/images/0202012000gwimnzf97E3_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0203x12000gwinczqBE56_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0233k12000gwiguwn5F3B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000gwi37hk041F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-27', '花园双床房', '双床房', '其他', 271, 5.605802066295998, 0, 0.0, 37, 3.6375861597263857, 9, '["周边配套", "整体满意度", "前台服务"]'::jsonb, '周边配套', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '酒店在市区，周边就是商场，酒店门口车子多，看来入住的人也比较多，店内服务先生小姐', '酒店在市区，周边就是商场，酒店门口车子多，看来入住的人也比较多，店内服务先生小姐热情，办入住的时候还收到送的鲜花好开心，同时也看到沙特航空公司的几位漂亮小姐?也在办理入住，酒店有不少外宾入住，酒店楼上有一个层面还有介绍该酒店的一个历史的博物馆，?我也进去参观了挺好的，酒店有40多年历史不少名人居住过大名在外，店内大堂气派，早餐丰富，味道也好，用早餐的地方也能看到窗外的人造瀑布?。因为酒店建得早停车要停到地下人上来的时候要绕一条过道从酒店后门进酒店?不是太方便，房间干净，样式老了一点，在房间也收到了酒店送的送了点心好温馨，谢谢酒店了！??', '2024-11-27', 5, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027971e3c98b09417657cb', '设施：老牌五星，铂金。就缺晾衣服的
