INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027971e3c98b09417657cc', '不愧是老牌五星级酒店，虽然设施老了一点，但服务人员热情，春节期间酒店氛围热闹，家人住得特别开心，有机会会再次入住', '["https://dimg04.c-ctrip.com/images/0235c12000ibhujet741C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000ibi6ety288C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-05', '花园双床房', '双床房', '家庭亲子', 56, 4.04305126783455, 0, 0.0, 4, 1.6094379124341005, 7, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '不愧是老牌五星级酒店，虽然设施老了一点，但服务人员热情，春节期间酒店氛围热闹，家', '不愧是老牌五星级酒店，虽然设施老了一点，但服务人员热情，春节期间酒店氛围热闹，家人住得特别开心，有机会会再次入住', '2025-02-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027971e3c98b09417657cd', '房间很舒服，酒店各方面服务好，尤其是餐饮的服务态度亲切，业务专业，早餐可以四个餐厅用，满足了不同体验，期盼下次继续入住', '["https://dimg04.c-ctrip.com/images/0231b12000ifp17d5326F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000ifppqm1A7EF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000ifpznntB615_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000ifqxuxi8998_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-10', '红棉双床套房', '套房', '家庭亲子', 59, 4.0943445622221, 0, 0.0, 24, 3.218875824868201, 7, '["餐饮设施", "整体满意度", "前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '房间很舒服，酒店各方面服务好，尤其是餐饮的服务态度亲切，业务专业，早餐可以四个餐', '房间很舒服，酒店各方面服务好，尤其是餐饮的服务态度亲切，业务专业，早餐可以四个餐厅用，满足了不同体验，期盼下次继续入住', '2025-02-10', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802797de3c98b09417657ce', '超出预期的完美体验！之前看到是老牌酒店重装修，预期不高，但是入住后我没觉得有陈旧感，有特色又有品质的装修风格，很惊艳，和价钱差不多的所谓快捷酒店完全两个概念。因为一点小插曲升级了套房，享受了行政酒廊，哈哈超值！一定要观赏岭南风格的花园，很美！下次来广州一定还来花园酒店！', '["https://dimg04.c-ctrip.com/images/0235q12000gx33g4u993D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236q12000gx2y2832455_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000gx2izrc58C8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000gx37cv20E78_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000gx2vgfe8E2F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-28', '花园双床房', '双床房', '朋友出游', 135, 4.912654885736052, 0, 0.0, 14, 2.70805020110221, 9, '["整体满意度", "性价比", "公共设施"]'::jsonb, '整体满意度', '性价比', '公共设施', '未知酒店', '未知地点', '匿名', '超出预期的完美体验！之前看到是老牌酒店重装修，预期不高，但是入住后我没觉得有陈旧', '超出预期的完美体验！之前看到是老牌酒店重装修，预期不高，但是入住后我没觉得有陈旧感，有特色又有品质的装修风格，很惊艳，和价钱差不多的所谓快捷酒店完全两个概念。因为一点小插曲升级了套房，享受了行政酒廊，哈哈超值！一定要观赏岭南风格的花园，很美！下次来广州一定还来花园酒店！', '2024-11-28', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802797de3c98b09417657cf', '花园酒店，白天鹅宾馆都是广州的名片，第一次到花园酒店已是三十年前啦，酒店的管理的一如既往，从硬件维护到服务质量都无可挑剔。', '["https://dimg04.c-ctrip.com/images/0235y12000i27ycru63E4_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231d12000i27wr8h3BD5_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233k12000i27zmhm0216_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235v12000i27tvrqC66F_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-01-25', '花园双床房', '双床房', '家庭亲子', 61, 4.127134385045092, 0, 0.0, 4, 1.6094379124341005, 7, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '花园酒店，白天鹅宾馆都是广州的名片，第一次到花园酒店已是三十年前啦，酒店的管理的', '花园酒店，白天鹅宾馆都是广州的名片，第一次到花园酒店已是三十年前啦，酒店的管理的一如既往，从硬件维护到服务质量都无可挑剔。', '2025-01-25', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802797de3c98b09417657d0', '花园酒店是我在广州旅行最喜欢的酒店，非常迷人的花园环境，超一流的服务，完美的床上用品，前台优秀的较高职业素养的Kasas，以极快的速度帮我们办理入住，同时又精准的解答我的问题，还为我们升了级！温暖的笑容让我们宾至如归！早餐丰富，摆放艺术氛围拉满！祝福花园酒店！爱花园酒店', '["https://dimg04.c-ctrip.com/images/0234612000jeoua28F85E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235x12000jep88y710B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000jep2l9d7032_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000jep9gjs4386_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000jeon37w1B0F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000jep8my87E07_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-29', '城央绿意双床房', '双床房', '朋友出游', 135, 4.912654885736052, 0, 0.0, 77, 4.356708826689592, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '花园酒店是我在广州旅行最喜欢的酒店，非常迷人的花园环境，超一流的服务，完美的床上', '花园酒店是我在广州旅行最喜欢的酒店，非常迷人的花园环境，超一流的服务，完美的床上用品，前台优秀的较高职业素养的Kasas，以极快的速度帮我们办理入住，同时又精准的解答我的问题，还为我们升了级！温暖的笑容让我们宾至如归！早餐丰富，摆放艺术氛围拉满！祝福花园酒店！爱花园酒店', '2025-03-29', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802797de3c98b09417657d1', '酒店是老酒店了，房间的环境确实不错，吃喝玩乐都很方便，酒店大厅也是富丽堂皇，重点来了，酒店房间的实施太老气了，还有那个电视剧小到无语。酒店里面的酒吧很棒哦！', '["https://dimg04.c-ctrip.com/images/0235512000heqc41r8991_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000hepjxtpCC02_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000hepckjdC55E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000hepf3huBD89_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-12-25', '花园大床房', '大床房', '商务出差', 78, 4.3694478524670215, 0, 0.0, 133, 4.897839799950911, 7, '["房间设施", "周边配套", "餐饮设施"]'::jsonb, '房间设施', '周边配套', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店是老酒店了，房间的环境确实不错，吃喝玩乐都很方便，酒店大厅也是富丽堂皇，重点', '酒店是老酒店了，房间的环境确实不错，吃喝玩乐都很方便，酒店大厅也是富丽堂皇，重点来了，酒店房间的实施太老气了，还有那个电视剧小到无语。酒店里面的酒吧很棒哦！', '2024-12-25', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802797de3c98b09417657d2', '酒店位置优越，公共区域设施好??庭院设计管理很好，酒店博物馆也非常不错值得一逛??酒店的服务质量还是可以??不足：房间设施比较陈旧，不提供一次性马桶垫；楼下有装修白天比较闹；入住居然还要押金，太不方便了！！！', '["https://dimg04.c-ctrip.com/images/0232w12000h2psebm526E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000h2psoa14DE8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000h2pxv6u583D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000h2pyewi7C6B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000h2ovbzk4620_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-12-06', '花园双床房', '双床房', '朋友出游', 104, 4.653960350157523, 0, 0.0, 7, 2.079441541679836, 7, '["房间设施", "安静程度", "周边配套"]'::jsonb, '房间设施', '安静程度', '周边配套', '未知酒店', '未知地点', '匿名', '酒店位置优越，公共区域设施好??庭院设计管理很好，酒店博物馆也非常不错值得一逛?', '酒店位置优越，公共区域设施好??庭院设计管理很好，酒店博物馆也非常不错值得一逛??酒店的服务质量还是可以??不足：房间设施比较陈旧，不提供一次性马桶垫；楼下有装修白天比较闹；入住居然还要押金，太不方便了！！！', '2024-12-06', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802797de3c98b09417657d3', '预订了两间房家庭亲子带老带小，到了的那天有一个特殊酒会导致前台搬了位置，办理好入住没有空房需要寄存行李，被告知要自己推到礼宾处，我们三个大箱子呢，无奈自己推过去。入住时要求不要靠电梯，一上楼就是一间电梯口房间，另一件窗帘机又坏的，等了半天说给我升房了，还说要给我水果盘，但是错过了唯一一次行政酒廊的机会，后面几天都有别的安排也没时间去。
换完房就出门了，晚上回房间发现夜床也没开。不是我矫情是我真的找不到拖鞋！开了夜床就不需要自己找了。打电话问拖鞋的时候就不该多问怎么没开夜床，搞得我一包气，前台回答我是我没要求，他们酒店是要客人要求的，真是闻所未闻，那你是不是该问我下需不需要呢？
搞了半天，结果第二天早上起来其中一间房间的窗帘开关还是坏的，真的很无语。最后这次我都没和携程吐槽，真的吐槽无能了。
好了吐槽完了。酒店虽然有点年头，但是内部保养的很不错，年代感和现代化结合的非常好。酒店里的花园真的特别美，锦鲤又多又大，孩子很喜欢。
行政酒廊的HH很西式，不符合我们的中国胃，没有米饭面条，就是些面包。泳池就是港片里能看到的那种样子，露天的，淋浴也在外面。
有些遗憾没去看花园酒店博物馆，时间没安排好。但anyway，以后应该是不会再去了，这次经历属实不太愉快。', '["https://dimg04.c-ctrip.com/images/0235s12000gv4om6mC725_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000gv5ch8731F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000gv4z8ksB777_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-11-25', '花园大床房', '大床房', '家庭亲子', 533, 6.280395838960195, 1, 0.6931471805599453, 1, 0.6931471805599453, 9, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '预订了两间房家庭亲子带老带小，到了的那天有一个特殊酒会导致前台搬了位置，办理好入', '预订了两间房家庭亲子带老带小，到了的那天有一个特殊酒会导致前台搬了位置，办理好入住没有空房需要寄存行李，被告知要自己推到礼宾处，我们三个大箱子呢，无奈自己推过去。入住时要求不要靠电梯，一上楼就是一间电梯口房间，另一件窗帘机又坏的，等了半天说给我升房了，还说要给我水果盘，但是错过了唯一一次行政酒廊的机会，后面几天都有别的安排也没时间去。
换完房就出门了，晚上回房间发现夜床也没开。不是我矫情是我真的找不到拖鞋！开了夜床就不需要自己找了。打电话问拖鞋的时候就不该多问怎么没开夜床，搞得我一包气，前台回答我是我没要求，他们酒店是要客人要求的，真是闻所未闻，那你是不是该问我下需不需要呢？
搞了半天，结果第二天早上起来其中一间房间的窗帘开关还是坏的，真的很无语。最后这次我都没和携程吐槽，真的吐槽无能了。
好了吐槽完了。酒店虽然有点年头，但是内部保养的很不错，年代感和现代化结合的非常好。酒店里的花园真的特别美，锦鲤又多又大，孩子很喜欢。
行政酒廊的HH很西式，不符合我们的中国胃，没有米饭面条，就是些面包。泳池就是港片里能看到的那种样子，露天的，淋浴也在外面。
有些遗憾没去看花园酒店博物馆，时间没安排好。但anyway，以后应该是不会再去了，这次经历属实不太愉快。', '2024-11-25', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802797de3c98b09417657d4', '非常不错的一个酒店，据说是广州本地老牌豪华酒店，地理位置好，交通便利出门就是地铁，房间也不错，服务贴心，很好', '["https://dimg04.c-ctrip.com/images/0234i12000ib3n2xuC195_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000ib2ccofF502_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q12000ib2pp6kAED4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000ib3340656F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000ib2xtvy2500_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000ib2viftBCAA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000ib36lkx58BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000ib2r9c51DAA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-04', '红棉大床套房', '套房', '家庭亲子', 54, 4.007333185232471, 0, 0.0, 16, 2.833213344056216, 6, '["交通便利性", "整体满意度", "前台服务"]'::jsonb, '交通便利性', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '非常不错的一个酒店，据说是广州本地老牌豪华酒店，地理位置好，交通便利出门就是地铁', '非常不错的一个酒店，据说是广州本地老牌豪华酒店，地理位置好，交通便利出门就是地铁，房间也不错，服务贴心，很好', '2025-02-04', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802797de3c98b09417657d5', '老牌酒店，很有调调，位置就在地铁边上，出行很方便。服务人员也都很nice，酒店还有个博物馆，可以逛逛。早餐可以在30楼旋转餐厅用餐。', '["https://dimg04.c-ctrip.com/images/0233l12000hx9b9uj4F68_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000hx8h3zr5E39_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000hx8vava9B65_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-01-20', '花园双床房', '双床房', '家庭亲子', 66, 4.204692619390966, 0, 0.0, 40, 3.713572066704308, 7, '["交通便利性", "餐饮设施", "整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '老牌酒店，很有调调，位置就在地铁边上，出行很方便。服务人员也都很nice，酒店还', '老牌酒店，很有调调，位置就在地铁边上，出行很方便。服务人员也都很nice，酒店还有个博物馆，可以逛逛。早餐可以在30楼旋转餐厅用餐。', '2025-01-20', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802797de3c98b09417657d6', '酒店很有底蕴的，也很有特色，整体氛围很好。升级了房间，很宽敞，打扫也很到位。瀑布餐厅自肋早餐挺好的。一次满意的体验。', '["https://dimg04.c-ctrip.com/images/0234u12000i343rz846E8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000i3422sa0A4E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231112000i3357hv7CE3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-26', '花园大床房', '大床房', '情侣出游', 58, 4.07753744390572, 0, 0.0, 47, 3.871201010907891, 7, '["整体满意度", "客房服务", "餐饮设施"]'::jsonb, '整体满意度', '客房服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店很有底蕴的，也很有特色，整体氛围很好。升级了房间，很宽敞，打扫也很到位。瀑布', '酒店很有底蕴的，也很有特色，整体氛围很好。升级了房间，很宽敞，打扫也很到位。瀑布餐厅自肋早餐挺好的。一次满意的体验。', '2025-01-26', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802797de3c98b09417657d7', '房间很大，睡得挺舒服的，老牌大酒店环境没得说，瀑布餐厅的早餐还不错，我们去的时候要排队，有个女的像是管理人员，说可以安排更好的餐厅吃，我们想想算了，也不赶时间就不折腾了，没想到这女的还说了句很不好听的话，素质这么低怎么当上管理职位的，其他硬件方面都不错，门口的服务员还帮忙搬行李，印象不错。', '["https://dimg04.c-ctrip.com/images/0232012000hj714sp3489_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000hj7mgqd0B84_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000hj6jvkl026A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000hj7bqlb0B5C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-01-01', '红棉大床套房', '套房', '情侣出游', 145, 4.983606621708336, 0, 0.0, 6, 1.9459101490553128, 7, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '房间很大，睡得挺舒服的，老牌大酒店环境没得说，瀑布餐厅的早餐还不错，我们去的时候', '房间很大，睡得挺舒服的，老牌大酒店环境没得说，瀑布餐厅的早餐还不错，我们去的时候要排队，有个女的像是管理人员，说可以安排更好的餐厅吃，我们想想算了，也不赶时间就不折腾了，没想到这女的还说了句很不好听的话，素质这么低怎么当上管理职位的，其他硬件方面都不错，门口的服务员还帮忙搬行李，印象不错。', '2025-01-01', 4, '整体满意度');
