INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027988e3c98b09417657db', '房间很小，也比较旧，公共区域倒是不错，花园，博物馆都可以逛逛。离地铁站很近，出行方便，外国人特别多。桃园的早茶很不错', '["https://dimg04.c-ctrip.com/images/0233r12000i871ev12B50_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235v12000i88tbooADF5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230812000i888oij1087_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000i88dhka494D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.8, 3, '2025-02-01', '花园双床房', '双床房', '家庭亲子', 58, 4.07753744390572, 0, 0.0, 4, 1.6094379124341005, 7, '["房间设施", "交通便利性", "周边配套"]'::jsonb, '房间设施', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '房间很小，也比较旧，公共区域倒是不错，花园，博物馆都可以逛逛。离地铁站很近，出行', '房间很小，也比较旧，公共区域倒是不错，花园，博物馆都可以逛逛。离地铁站很近，出行方便，外国人特别多。桃园的早茶很不错', '2025-02-01', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027988e3c98b09417657dc', '自从九月份住过花园的红梅套房之后，我家太上皇和小朋友都非常喜欢，这次买了三天两晚的套餐，包含行政酒廊和早餐，非常划算。行政酒廊下午茶正对着花园瀑布景色，打卡一流，有中式和西式点心，尤其是印度的Carriy主管非常nice，服务非常好，让我特别感动的是她居然还记得我们是9月来过，更是热情为我们介绍花园酒店的特色和打卡点，让老人家赞不绝口。30楼的旋转餐厅早餐和景观也特别棒。值得一住再住，尤其我们是地道广州人，情怀也很重要。', '["https://dimg04.c-ctrip.com/images/0233712000guk29vyD652_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000gujmabf45B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231112000guju8oo6776_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000gujsa6sCD17_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000gujsalfB648_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000guk9y5aA864_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-24', '花园双床房', '双床房', '家庭亲子', 212, 5.3612921657094255, 0, 0.0, 7, 2.079441541679836, 9, '["餐饮设施", "前台服务", "性价比"]'::jsonb, '餐饮设施', '前台服务', '性价比', '未知酒店', '未知地点', '匿名', '自从九月份住过花园的红梅套房之后，我家太上皇和小朋友都非常喜欢，这次买了三天两晚', '自从九月份住过花园的红梅套房之后，我家太上皇和小朋友都非常喜欢，这次买了三天两晚的套餐，包含行政酒廊和早餐，非常划算。行政酒廊下午茶正对着花园瀑布景色，打卡一流，有中式和西式点心，尤其是印度的Carriy主管非常nice，服务非常好，让我特别感动的是她居然还记得我们是9月来过，更是热情为我们介绍花园酒店的特色和打卡点，让老人家赞不绝口。30楼的旋转餐厅早餐和景观也特别棒。值得一住再住，尤其我们是地道广州人，情怀也很重要。', '2024-11-24', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027988e3c98b09417657dd', '服务一流，环境很好，地理位置优越，与地铁口几乎零距离，家庭亲子商务外出旅游出行都很合适，性价比可以的', '["https://dimg04.c-ctrip.com/images/0230y12000jqp3bso965F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000jqoraps1DC8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000jqoylbv97F6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-04-12', '城央绿意大床房', '大床房', '家庭亲子', 50, 3.9318256327243257, 0, 0.0, 7, 2.079441541679836, 6, '["交通便利性", "整体满意度", "性价比"]'::jsonb, '交通便利性', '整体满意度', '性价比', '未知酒店', '未知地点', '匿名', '服务一流，环境很好，地理位置优越，与地铁口几乎零距离，家庭亲子商务外出旅游出行都', '服务一流，环境很好，地理位置优越，与地铁口几乎零距离，家庭亲子商务外出旅游出行都很合适，性价比可以的', '2025-04-12', 4, '交通便利性');
