INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027993e3c98b09417657e2', '很好，服务很热情，很有年味，一如既往的好，金卡做了升级，行政酒廊carrie 非常好，期待再次相遇', '["https://dimg04.c-ctrip.com/images/02325224x8z3ujvyt7171_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02344224x8z3ua9hrD315_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-03', '花园大床房', '大床房', '家庭亲子', 49, 3.912023005428146, 0, 0.0, 19, 2.995732273553991, 6, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '很好，服务很热情，很有年味，一如既往的好，金卡做了升级，行政酒廊carrie 非', '很好，服务很热情，很有年味，一如既往的好，金卡做了升级，行政酒廊carrie 非常好，期待再次相遇', '2025-02-03', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027993e3c98b09417657e3', '这次带妈妈去旅行，选择了地理位置优越，具有岭南风格的花园酒店。妈妈真的喜欢的不行！
光是酒店里的花园，我们都逛了一下午。瀑布、锦鲤、各式各样的花朵绿植，随意走到每一处都是一道靓丽的风景。
从进门到退房，妈妈都是依依不舍。酒店里的每一位工作人员给予的服务都是无微不至的！前台的Viria，听到我是带妈妈旅行，还很贴心的给妈妈送了花园酒店的花！
行政酒廊的出品也很丰富，香槟、红酒、啤酒，还有很多无酒精饮料。期间，Carrie,Berlye,Mira为我们介绍了很多菜品和酒水，妈妈第一次来真的感受到了满满的热情！说下次还要选择花园酒店！', '["https://dimg04.c-ctrip.com/images/0235x12000fx9iwyq66F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000fx9obxlFDA2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000fxc04xs424F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000fxaadsp14B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000fxaumi344AE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000fxakei33A14_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231j12000fxbirux515F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000fxbca0o5A94_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000fxb4kzu50C1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-02', '花园大床房', '大床房', '朋友出游', 267, 5.5909869805108565, 0, 0.0, 2, 1.0986122886681098, 9, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '这次带妈妈去旅行，选择了地理位置优越，具有岭南风格的花园酒店。妈妈真的喜欢的不行', '这次带妈妈去旅行，选择了地理位置优越，具有岭南风格的花园酒店。妈妈真的喜欢的不行！
光是酒店里的花园，我们都逛了一下午。瀑布、锦鲤、各式各样的花朵绿植，随意走到每一处都是一道靓丽的风景。
从进门到退房，妈妈都是依依不舍。酒店里的每一位工作人员给予的服务都是无微不至的！前台的Viria，听到我是带妈妈旅行，还很贴心的给妈妈送了花园酒店的花！
行政酒廊的出品也很丰富，香槟、红酒、啤酒，还有很多无酒精饮料。期间，Carrie,Berlye,Mira为我们介绍了很多菜品和酒水，妈妈第一次来真的感受到了满满的热情！说下次还要选择花园酒店！', '2024-10-02', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027993e3c98b09417657e4', '房间非常干净，入住的时候前台小姐姐还给了一朵康乃馨，好温馨', '["https://dimg04.c-ctrip.com/images/0232g12000j1hc8rv2BF3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000j1hxzoc48B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000j1g9ohsB5DD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-13', '花园大床房', '大床房', '独自旅行', 29, 3.4011973816621555, 0, 0.0, 6, 1.9459101490553128, 7, '["卫生状况", "前台服务"]'::jsonb, '卫生状况', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '房间非常干净，入住的时候前台小姐姐还给了一朵康乃馨，好温馨', '房间非常干净，入住的时候前台小姐姐还给了一朵康乃馨，好温馨', '2025-03-13', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027993e3c98b09417657e5', '酒店是知名度较高的涉外国际饭店，整体服务水平较高。位于广州老城区，寸土寸金之地内部有花园散步，不错。打造了酒店博物馆，增添了文化气息。相对酒店的价格，房间浴卫盥洗区等略显局促。', '["https://dimg04.c-ctrip.com/images/0233212000h3493sn01AB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232i12000h342u0w3343_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000h33qvb7C3FE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-12-07', '花园双床房', '双床房', '朋友出游', 88, 4.48863636973214, 0, 0.0, 41, 3.737669618283368, 7, '["房间设施", "整体满意度", "性价比"]'::jsonb, '房间设施', '整体满意度', '性价比', '未知酒店', '未知地点', '匿名', '酒店是知名度较高的涉外国际饭店，整体服务水平较高。位于广州老城区，寸土寸金之地内', '酒店是知名度较高的涉外国际饭店，整体服务水平较高。位于广州老城区，寸土寸金之地内部有花园散步，不错。打造了酒店博物馆，增添了文化气息。相对酒店的价格，房间浴卫盥洗区等略显局促。', '2024-12-07', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027993e3c98b09417657e6', '服务非常好，看到带了小朋友多送了好多饮用水，还送了小甜品，打扫好房间还留了手写卡片，很暖心', '["https://dimg04.c-ctrip.com/images/0234312000ieync743245_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-09', '红棉大床套房', '套房', '家庭亲子', 45, 3.828641396489095, 0, 0.0, 8, 2.19722457733622, 9, '["客房服务", "前台服务"]'::jsonb, '客房服务', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '服务非常好，看到带了小朋友多送了好多饮用水，还送了小甜品，打扫好房间还留了手写卡', '服务非常好，看到带了小朋友多送了好多饮用水，还送了小甜品，打扫好房间还留了手写卡片，很暖心', '2025-02-09', 5, '客房服务');
