INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027993e3c98b09417657e8', '每次来广州都会来住一下，酒店服务一如既往的好，吃完早餐逛逛瀑布花园，时间充足的话，还可以逛一下博物馆。', '["https://dimg04.c-ctrip.com/images/0233x12000i3g56ykAE25_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000i3h1rmo95A0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231j12000i3ha0iyA0FB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-27', '红棉大床套房', '套房', '情侣出游', 51, 3.951243718581428, 0, 0.0, 36, 3.610917912644224, 6, '["整体满意度", "餐饮设施", "周边配套"]'::jsonb, '整体满意度', '餐饮设施', '周边配套', '未知酒店', '未知地点', '匿名', '每次来广州都会来住一下，酒店服务一如既往的好，吃完早餐逛逛瀑布花园，时间充足的话', '每次来广州都会来住一下，酒店服务一如既往的好，吃完早餐逛逛瀑布花园，时间充足的话，还可以逛一下博物馆。', '2025-01-27', 5, '整体满意度');
