INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802799fe3c98b09417657ee', '又带家人在广州过年，这次选择在广州花园酒店，很有年味非常棒的体验！
特别要感谢酒店的礼宾部和客房部。由于老人腿脚不便需要借用轮椅，礼宾部小李美女安排得体贴周到，让我们出行无忧游玩了很多景点，谢谢！
