特别要感谢酒店的礼宾部和客房部。由于老人腿脚不便需要借用轮椅，礼宾部小李美女安排得体贴周到，让我们出行无忧游玩了很多景点，谢谢！
负责2218客房的一位男生得知老人嫌床垫软，二话不说直接把床垫翻了个面，这是事后老人对我说的，我虽未曾谋面在此表示感谢！', '2025-02-01', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802799fe3c98b09417657ef', '初次入住花园酒店，就被酒店内圣诞的气氛吸引，非常漂亮！虽入住时遇到问题，前台很快解决了，并给我们房间升级。房间舒适宽敞，非常干净！是一次不错的体验。', '["https://dimg04.c-ctrip.com/images/0236y12000h9n8xfrCFA3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000h9n96po8101_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000h9n7z70B954_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v12000h9n5slb33C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000h9n87877B5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000h9n9phi9B67_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000h9n8rb9DA82_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236q12000h9n646h2DC5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000h9n8myt0552_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-18', '花园大床房', '大床房', '朋友出游', 74, 4.31748811353631, 1, 0.6931471805599453, 1, 0.6931471805599453, 7, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '初次入住花园酒店，就被酒店内圣诞的气氛吸引，非常漂亮！虽入住时遇到问题，前台很快', '初次入住花园酒店，就被酒店内圣诞的气氛吸引，非常漂亮！虽入住时遇到问题，前台很快解决了，并给我们房间升级。房间舒适宽敞，非常干净！是一次不错的体验。', '2024-12-18', 5, '整体满意度');
