INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802799fe3c98b09417657f1', '下车后的迎宾团队做的很好，主动开车，取行李，用行李车运输大行李。 
前台办理入住时间很长， 行政礼遇也没有加快办理，， 没有工作人员主动引领到旁边的休息区。 后面我们自己问了一圈， 了解到旁边的沙发可以坐着等， 在旁边的沙发区等待了一个小时才拿房卡。 排队等待办理入住的人大多都有怨言，说太慢了。
定的两个大床房都很温馨， 干净， 床品质量都非常好。会有咖啡，茶水，矿泉水。喜欢提供的浴盐，但是没有提供一次性浴缸套。 针线包，丝瓜络都很好用。插座都是国际国内通用，不需要转换插头。 
小花园很美， 博物馆很不错，了解一下酒店的百年史。
早餐品类丰富， 最喜欢吃牛腩米粉。 行政走廊下午茶的点心有限， 是一些小糕点，咖啡，茶， 软饮。 晚上的行政走廊提供finger food， 对于饭量小的女士，其实也够了。 
整体来说性价比很高， 不过因为在广交会时期，酒店每天都是注满， 感觉服务上欠了点，没有达到五星酒店的松弛感。', '["https://dimg04.c-ctrip.com/images/0232g12000gaf824p8B29_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000gae2540968F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231112000gaexfvs18A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000gaeas091404_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000gae92qrDECD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000gaegaypEBE6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233412000gaeaq0n2ED2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000gaf5o15184F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000gaeasea9010_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-10-24', '花园大床房', '大床房', '家庭亲子', 411, 6.021023349349527, 0, 0.0, 7, 2.079441541679836, 8, '["前台服务", "退房/入住效率", "整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度', '未知酒店', '未知地点', '匿名', '下车后的迎宾团队做的很好，主动开车，取行李，用行李车运输大行李。 ', '下车后的迎宾团队做的很好，主动开车，取行李，用行李车运输大行李。 
前台办理入住时间很长， 行政礼遇也没有加快办理，， 没有工作人员主动引领到旁边的休息区。 后面我们自己问了一圈， 了解到旁边的沙发可以坐着等， 在旁边的沙发区等待了一个小时才拿房卡。 排队等待办理入住的人大多都有怨言，说太慢了。
定的两个大床房都很温馨， 干净， 床品质量都非常好。会有咖啡，茶水，矿泉水。喜欢提供的浴盐，但是没有提供一次性浴缸套。 针线包，丝瓜络都很好用。插座都是国际国内通用，不需要转换插头。 
小花园很美， 博物馆很不错，了解一下酒店的百年史。
早餐品类丰富， 最喜欢吃牛腩米粉。 行政走廊下午茶的点心有限， 是一些小糕点，咖啡，茶， 软饮。 晚上的行政走廊提供finger food， 对于饭量小的女士，其实也够了。 
整体来说性价比很高， 不过因为在广交会时期，酒店每天都是注满， 感觉服务上欠了点，没有达到五星酒店的松弛感。', '2024-10-24', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802799fe3c98b09417657f2', '作为广州人，每次来到花园酒店的大堂都觉得很感动，这里一直是小时候记忆里的模样，忘不了第一次遇见时的惊艳。
