INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279aae3c98b09417657f7', '花园酒店装修豪华，卫生与服务一直保持高水准，我也多次入住，值得推荐。这次入住并免费升级了行政套房，非常享受的一次元旦假日。', '["https://dimg04.c-ctrip.com/images/0232z12000hj3zn3iD472_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233312000hj3zq7g880B_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232512000hj3yw0i979B_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-01-01', '花园双床房', '双床房', '家庭亲子', 61, 4.127134385045092, 0, 0.0, 13, 2.6390573296152584, 7, '["整体满意度", "卫生状况", "前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务', '未知酒店', '未知地点', '匿名', '花园酒店装修豪华，卫生与服务一直保持高水准，我也多次入住，值得推荐。这次入住并免', '花园酒店装修豪华，卫生与服务一直保持高水准，我也多次入住，值得推荐。这次入住并免费升级了行政套房，非常享受的一次元旦假日。', '2025-01-01', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279aae3c98b09417657f8', '旅行的最后一个酒店，给了非常好的体验。因为带了老人出行对房间的私密和安静程度要求有点，前台的小姐姐给了房间升级，而且正对瀑布花园景色。行政礼遇的下午茶和晚餐虽然东西不多，但是都很精致可口，好像是叫carrie外籍小姐姐吧还会不时来关心老人家的用餐体验。早餐虽然去了网红瀑布餐厅用餐，但是和行政礼遇一样偏向西式的为主。整个入住期间，每位服务人员都态度很亲切，也很有边缘感很舒服。
如果下次来广州还会住', '["https://dimg04.c-ctrip.com/images/0230912000ghth5oj4824_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000ghsxxooB58F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000ghsvgaqD3BC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000ghsq6c90997_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000ghtg7wj0BE4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-04', '花园双床房', '双床房', '家庭亲子', 199, 5.298317366548036, 0, 0.0, 34, 3.555348061489413, 9, '["前台服务", "景观/朝向", "整体满意度"]'::jsonb, '前台服务', '景观/朝向', '整体满意度', '未知酒店', '未知地点', '匿名', '旅行的最后一个酒店，给了非常好的体验。因为带了老人出行对房间的私密和安静程度要求', '旅行的最后一个酒店，给了非常好的体验。因为带了老人出行对房间的私密和安静程度要求有点，前台的小姐姐给了房间升级，而且正对瀑布花园景色。行政礼遇的下午茶和晚餐虽然东西不多，但是都很精致可口，好像是叫carrie外籍小姐姐吧还会不时来关心老人家的用餐体验。早餐虽然去了网红瀑布餐厅用餐，但是和行政礼遇一样偏向西式的为主。整个入住期间，每位服务人员都态度很亲切，也很有边缘感很舒服。
如果下次来广州还会住', '2024-11-04', 5, '前台服务');
