INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279b5e3c98b0941765802', '本来有小意外不太愉快，但前台服务态度好给升房了。套房宽敞舒适洁净，设施保养得很好，酒店早餐夜茶水准也高，整体满意。', '["https://dimg04.c-ctrip.com/images/0232c12000hq5wm7x2C1A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-01-11', '花园双床房', '双床房', '朋友出游', 57, 4.060443010546419, 0, 0.0, 2, 1.0986122886681098, 7, '["前台服务", "整体满意度", "房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '本来有小意外不太愉快，但前台服务态度好给升房了。套房宽敞舒适洁净，设施保养得很好', '本来有小意外不太愉快，但前台服务态度好给升房了。套房宽敞舒适洁净，设施保养得很好，酒店早餐夜茶水准也高，整体满意。', '2025-01-11', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279b5e3c98b0941765803', '花园酒店LNhotel ，历史悠久，非常大气，展现出改革开放以来的欣欣向荣, 外国宾客占比近一半。设施齐全，室外游泳池，健身房，瑜伽馆，和米其林餐厅，行政酒廊，酒吧应有尽有。美中不足 房间内没有USB插口。
服务非常好，白金五星级的水准在线。
地理位置在越秀区，老城区。高峰时段比较拥堵。', '["https://dimg04.c-ctrip.com/images/0232t12000ge3cq5s6CCC_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0236f12000ge3cn5iAE89_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235212000ge3e5c99980_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231j12000ge3cryk8B90_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0230y12000ge3cd9x700C_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232f12000ge3ck9x7A19_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234112000ge3ebkdB0A9_R_150_150_R5_Q70_D.png"]'::jsonb, 4.7, 4, '2024-10-30', '花园大床房', '大床房', '情侣出游', 144, 4.976733742420574, 0, 0.0, 21, 3.091042453358316, 8, '["公共设施", "房间设施", "前台服务"]'::jsonb, '公共设施', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '花园酒店LNhotel ，历史悠久，非常大气，展现出改革开放以来的欣欣向荣, 外', '花园酒店LNhotel ，历史悠久，非常大气，展现出改革开放以来的欣欣向荣, 外国宾客占比近一半。设施齐全，室外游泳池，健身房，瑜伽馆，和米其林餐厅，行政酒廊，酒吧应有尽有。美中不足 房间内没有USB插口。
服务非常好，白金五星级的水准在线。
地理位置在越秀区，老城区。高峰时段比较拥堵。', '2024-10-30', 4, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279b5e3c98b0941765804', '广州花园酒店的Echo：服务之星，温暖如家的体验
在广州花园酒店，有这样一个名字，让人一提起就赞不绝口——Echo。她不仅是行政酒廊里的一道亮丽风景线，更是每一位入住宾客心中难以忘怀的温暖记忆。
Echo的服务态度，简直令人印象深刻。她以专业的知识和亲切的微笑，仿佛能瞬间化解旅途的疲惫。无论是对酒店设施的介绍，还是对周边景点的推荐，Echo总能信手拈来，让人感受到她的专业与用心。每当宾客提出需求，无论是房间的细微调整，还是餐饮的特殊要求，Echo都能迅速响应，耐心解答，确保每一位客人都能住得舒心、放心。
更难能可贵的是，Echo的细心关怀仿佛能洞察人心。她总能在不经意间，为宾客送上贴心的小惊喜，比如一杯温热的茶水，或是一份精心准备的点心。这些看似微不足道的细节，却让人感受到了家一般的温暖。', '["https://dimg04.c-ctrip.com/images/0232b12000goegkat2B54_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-14', '城央绿意大床房', '大床房', '商务出差', 352, 5.8664680569332965, 0, 0.0, 50, 3.9318256327243257, 9, '["前台服务", "客房服务"]'::jsonb, '前台服务', '客房服务', NULL, '未知酒店', '未知地点', '匿名', '广州花园酒店的Echo：服务之星，温暖如家的体验', '广州花园酒店的Echo：服务之星，温暖如家的体验
在广州花园酒店，有这样一个名字，让人一提起就赞不绝口——Echo。她不仅是行政酒廊里的一道亮丽风景线，更是每一位入住宾客心中难以忘怀的温暖记忆。
Echo的服务态度，简直令人印象深刻。她以专业的知识和亲切的微笑，仿佛能瞬间化解旅途的疲惫。无论是对酒店设施的介绍，还是对周边景点的推荐，Echo总能信手拈来，让人感受到她的专业与用心。每当宾客提出需求，无论是房间的细微调整，还是餐饮的特殊要求，Echo都能迅速响应，耐心解答，确保每一位客人都能住得舒心、放心。
更难能可贵的是，Echo的细心关怀仿佛能洞察人心。她总能在不经意间，为宾客送上贴心的小惊喜，比如一杯温热的茶水，或是一份精心准备的点心。这些看似微不足道的细节，却让人感受到了家一般的温暖。', '2024-11-14', 5, '前台服务');
