INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279b5e3c98b0941765809', '国庆去旅行
房间设施:60+平方，一房一厅一卫，麻雀虽小五脏俱全，两个1.35的床，三口之家也住得很舒服。起居动线合理，有咖啡机。
性价比:国庆期间，5k不到3晚的价格相当友好。
早餐:早餐可以有四个地方选。
瀑布餐厅是传统自助，景色拍照无敌，但人较多，9点去要排队，就没进去。
顶楼旋转餐厅也是自助，人也不少，第一天没排队，第三天排了一会儿队，东西嘛，该有的都有了，就中规中矩吧，特别好吃的没有。
桃园馆是最精致的，一人一份，一个点心四小拼，一碗粥配油条，一份肠粉，一个蛋挞配水果，茶咖啡牛奶，据说不够可以加，但其实这点量我甚至吃不下！
健身房:健身房干净，器材新、全，为了可以在广州多吃点，每天都去报到1-2次
位置交通:周围挺热闹的，好吃的不少，广州酒家，利苑都是步行可达。
酒店超级大，餐厅就有四五个，还有自己的博物馆，有一个很大的后花园，酒店够老牌，有一说一，这样不计成本的排场，现在应该是很难再有了。
值得一住的酒店，有机会会再来的', '["https://dimg04.c-ctrip.com/images/0235k12000hh3hzhb73AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000hh3epr8E8A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000hh3scbv3D70_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000hh3oqzo7111_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000hh3o28y63D2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000hh3ueij9E87_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233q12000hh3u45x1E1E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000hh3c7yuFD54_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000hh3n2p7FBDA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-29', '粤韵双床套房', '套房', '家庭亲子', 428, 6.061456918928017, 0, 0.0, 28, 3.367295829986474, 9, '["房间设施", "性价比", "餐饮设施"]'::jsonb, '房间设施', '性价比', '餐饮设施', '未知酒店', '未知地点', '匿名', '国庆去旅行', '国庆去旅行
