INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279c1e3c98b094176580c', '这家是我广州首选酒店之一，富丽堂皇的大堂给人印象深刻。从大堂门口到电梯厅及楼层一路都有服务员热情洋溢的打招呼，确实有宾至如归的感觉，特别温馨。房间设施齐全，整洁干净，床品舒适。住了好多次第一次有空去了宝藏花园，终于觉得花园酒店名副其实了。送房间的小食和水果也很精致。', '["https://dimg04.c-ctrip.com/images/0235m12000g9f427q3DB2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000g9fg0vw3D5A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000g9f7x2i11CD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000g9f3j13D72F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231o12000g9f94vy423E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000g9fhe9f3E6A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-22', '花园大床房', '大床房', '商务出差', 133, 4.897839799950911, 0, 0.0, 13, 2.6390573296152584, 9, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '这家是我广州首选酒店之一，富丽堂皇的大堂给人印象深刻。从大堂门口到电梯厅及楼层一', '这家是我广州首选酒店之一，富丽堂皇的大堂给人印象深刻。从大堂门口到电梯厅及楼层一路都有服务员热情洋溢的打招呼，确实有宾至如归的感觉，特别温馨。房间设施齐全，整洁干净，床品舒适。住了好多次第一次有空去了宝藏花园，终于觉得花园酒店名副其实了。送房间的小食和水果也很精致。', '2024-10-22', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279c1e3c98b094176580d', '时隔一年又来广州啦，这次依旧选了花园。体验感和去年一样棒，这次还升级成了套房。
不过这次下午行政酒廊时发现多了不少女孩子在大镜子前拍照，还会占用卫生间，多少有些打扰住客了。', '["https://dimg04.c-ctrip.com/images/0236e12000gob1vm05542_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000gobs3n2252A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000gobmz63E3FF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-14', '花园大床房', '大床房', '情侣出游', 86, 4.465908118654584, 0, 0.0, 6, 1.9459101490553128, 7, '["整体满意度", "公共设施", "安静程度"]'::jsonb, '整体满意度', '公共设施', '安静程度', '未知酒店', '未知地点', '匿名', '时隔一年又来广州啦，这次依旧选了花园。体验感和去年一样棒，这次还升级成了套房。', '时隔一年又来广州啦，这次依旧选了花园。体验感和去年一样棒，这次还升级成了套房。
不过这次下午行政酒廊时发现多了不少女孩子在大镜子前拍照，还会占用卫生间，多少有些打扰住客了。', '2024-11-14', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279c1e3c98b094176580e', '买了关注很久po主推送的套餐，也比较优惠，就再去住一晚。最后发现，失望的多，以后没有特别情况就不会再去了。办理入住的速度很慢，这无关效率和是否人多，其实就是系统太落后了。这次选了看环市路这边的，景观也是不错，但隔音效果实在有点差，开始以为是系统隔音玻璃没问题，但归根还是之前的玻璃幕墙系统落后了。走了要登记车牌号码时，那个前台好像是欠了她钱不给的那副嘴脸，这个人估计也劝退后面不少回头客。最后车牌识别也出了问题，只有一个出口，堵着久了后面的车也不断按喇叭，打电话给一个男的来解决问题，他也是气冲冲对客户。妈呀，如果是私人酒店，首先要把这两个家伙干掉，但花园嘛，可能无所谓。不过，我更无所谓，毕竟广州还有很多的五星级酒店。', '["https://dimg04.c-ctrip.com/images/0233f12000gcd3snr3E41_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000gcd9iciB524_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234x12000gcdjs939687_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000gcd9pnv33AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000gcdce1m0EB8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000gcdik0045BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.1, 3, '2024-10-27', '红棉大床套房', '套房', '商务出差', 310, 5.739792912179234, 2, 1.0986122886681098, 141, 4.955827057601261, 9, '["前台服务", "安静程度", "退房/入住效率"]'::jsonb, '前台服务', '安静程度', '退房/入住效率', '未知酒店', '未知地点', '匿名', '买了关注很久po主推送的套餐，也比较优惠，就再去住一晚。最后发现，失望的多，以后', '买了关注很久po主推送的套餐，也比较优惠，就再去住一晚。最后发现，失望的多，以后没有特别情况就不会再去了。办理入住的速度很慢，这无关效率和是否人多，其实就是系统太落后了。这次选了看环市路这边的，景观也是不错，但隔音效果实在有点差，开始以为是系统隔音玻璃没问题，但归根还是之前的玻璃幕墙系统落后了。走了要登记车牌号码时，那个前台好像是欠了她钱不给的那副嘴脸，这个人估计也劝退后面不少回头客。最后车牌识别也出了问题，只有一个出口，堵着久了后面的车也不断按喇叭，打电话给一个男的来解决问题，他也是气冲冲对客户。妈呀，如果是私人酒店，首先要把这两个家伙干掉，但花园嘛，可能无所谓。不过，我更无所谓，毕竟广州还有很多的五星级酒店。', '2024-10-27', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279c1e3c98b094176580f', '不愧为老牌五星级酒店，环境，卫生的说，下次还住这里', '["https://dimg04.c-ctrip.com/images/0231912000io55vb43569_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000io5jns67462_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-22', '红棉大床套房', '套房', '商务出差', 25, 3.258096538021482, 0, 0.0, 3, 1.3862943611198906, 5, '["整体满意度", "卫生状况"]'::jsonb, '整体满意度', '卫生状况', NULL, '未知酒店', '未知地点', '匿名', '不愧为老牌五星级酒店，环境，卫生的说，下次还住这里', '不愧为老牌五星级酒店，环境，卫生的说，下次还住这里', '2025-02-22', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279c1e3c98b0941765810', '首先我要对花园酒店的工作人员表示感谢，其中包括17楼的客房服务人员，办理入住登记的Betty，以及礼宾部的工作人员，他们的服务让我看到一个五星级酒店的高水准，给人宾至如归的感受！入住当天，办理入住登记的小姑娘Betty看到我们中间有年纪大的老人，随即给我们升级了套房，借来轮椅，还送上鲜花，这样的待遇让我们充满惊喜。接下来几天，负责我们房间的客房服务人员也是认真负责，对我们的要求是有求必应，感恩，感谢。因为我们老人腿脚不便，每次出入酒店大堂，礼宾部工作人员总是特别关照，帮忙叫出租车，帮我们搬轮椅等等，谢谢你们了。除了这些员工，大堂里所见的工作人员都是对客人热情微笑，一位戴眼镜的小姐姐更是主动帮我们在大堂拍合影。酒店的硬件设施我就不赘述了，绝对的五星级感受。相比硬件设施，工作人员的礼貌、热情、乐于助人我觉得才是这个酒店最拿得出手的优势。祝你们生意兴隆！', '["https://dimg04.c-ctrip.com/images/0232512000hl6ir7aF606_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000hl6bxstB7E8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000hl6p9ly48B6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000hl6t8p22B8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000hl6a5mz15EE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235x12000hl6isf119CC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-04', '花园双床房', '双床房', '家庭亲子', 379, 5.940171252720432, 0, 0.0, 7, 2.079441541679836, 9, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '首先我要对花园酒店的工作人员表示感谢，其中包括17楼的客房服务人员，办理入住登记', '首先我要对花园酒店的工作人员表示感谢，其中包括17楼的客房服务人员，办理入住登记的Betty，以及礼宾部的工作人员，他们的服务让我看到一个五星级酒店的高水准，给人宾至如归的感受！入住当天，办理入住登记的小姑娘Betty看到我们中间有年纪大的老人，随即给我们升级了套房，借来轮椅，还送上鲜花，这样的待遇让我们充满惊喜。接下来几天，负责我们房间的客房服务人员也是认真负责，对我们的要求是有求必应，感恩，感谢。因为我们老人腿脚不便，每次出入酒店大堂，礼宾部工作人员总是特别关照，帮忙叫出租车，帮我们搬轮椅等等，谢谢你们了。除了这些员工，大堂里所见的工作人员都是对客人热情微笑，一位戴眼镜的小姐姐更是主动帮我们在大堂拍合影。酒店的硬件设施我就不赘述了，绝对的五星级感受。相比硬件设施，工作人员的礼貌、热情、乐于助人我觉得才是这个酒店最拿得出手的优势。祝你们生意兴隆！', '2025-01-04', 5, '前台服务');
