INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279c1e3c98b0941765812', '全国仅三，广州唯一的白金五星级酒店，服务很好，大堂很有气势，首先映入眼帘的是一幅大型壁画，酒店一步一景，可以玩的地方很多，房间面积很大，床品舒服。', '["https://dimg04.c-ctrip.com/images/0232412000gy2b4coC818_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232m12000gy2tw1x9FA8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000gy2aii163C2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o12000gy221vi6CCB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000gy2l2in829A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000gy2m7hq5527_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-30', '花园大床房', '大床房', '其他', 73, 4.30406509320417, 0, 0.0, 125, 4.836281906951478, 8, '["整体满意度", "房间设施", "前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '全国仅三，广州唯一的白金五星级酒店，服务很好，大堂很有气势，首先映入眼帘的是一幅', '全国仅三，广州唯一的白金五星级酒店，服务很好，大堂很有气势，首先映入眼帘的是一幅大型壁画，酒店一步一景，可以玩的地方很多，房间面积很大，床品舒服。', '2024-11-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279c1e3c98b0941765813', '升级了套房，住的很舒服，酒店就在地铁站口附近，距离各个景点也近。', '["https://dimg04.c-ctrip.com/images/0230v12000idy4gtm4FD6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236512000idye67xE8FC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-08', '花园大床房', '大床房', '家庭亲子', 32, 3.49650756146648, 0, 0.0, 9, 2.302585092994046, 6, '["交通便利性", "整体满意度"]'::jsonb, '交通便利性', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '升级了套房，住的很舒服，酒店就在地铁站口附近，距离各个景点也近。', '升级了套房，住的很舒服，酒店就在地铁站口附近，距离各个景点也近。', '2025-02-08', 5, '交通便利性');
