INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279cbe3c98b0941765816', '房间比较宽敞，40年老酒店维护还不错，21楼视野很开阔。洗手间拉门设计感觉不方便，穿衣镜对着淋浴房会尴尬。房门把手开门要向上，一开始没反应过来，还好客房服务员主动打招呼过来帮忙说明。公共区域环境非常赞，大堂富丽堂皇，酒店博物馆，花园和瀑布非常漂亮。交通特别方便，地铁5号线淘金站就在边上，去哪里都方便。附近很多美食，对面广州酒家，不远就是利苑，北园也很近。一楼瀑布餐厅早餐比较丰富，推荐竹升面配萝卜牛腩。30楼旋转餐厅有点晕，品种比一楼少，但是也够了，现煮面条配红烧牛腩很赞。', '["https://dimg04.c-ctrip.com/images/0233h12000g0jo3f5B58B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000g0jjw722279_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000g0jjbkn2F5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000g0jln2uC106_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000g0j3z9f6465_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000g0jfhm1D8AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000g0jlv0w3B5F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000g0jb9khF236_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000g0jm8h7C385_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-10-06', '花园双床房', '双床房', '家庭亲子', 238, 5.476463551931511, 0, 0.0, 1, 0.6931471805599453, 9, '["周边配套", "交通便利性", "公共设施"]'::jsonb, '周边配套', '交通便利性', '公共设施', '未知酒店', '未知地点', '匿名', '房间比较宽敞，40年老酒店维护还不错，21楼视野很开阔。洗手间拉门设计感觉不方便', '房间比较宽敞，40年老酒店维护还不错，21楼视野很开阔。洗手间拉门设计感觉不方便，穿衣镜对着淋浴房会尴尬。房门把手开门要向上，一开始没反应过来，还好客房服务员主动打招呼过来帮忙说明。公共区域环境非常赞，大堂富丽堂皇，酒店博物馆，花园和瀑布非常漂亮。交通特别方便，地铁5号线淘金站就在边上，去哪里都方便。附近很多美食，对面广州酒家，不远就是利苑，北园也很近。一楼瀑布餐厅早餐比较丰富，推荐竹升面配萝卜牛腩。30楼旋转餐厅有点晕，品种比一楼少，但是也够了，现煮面条配红烧牛腩很赞。', '2024-10-06', 4, '周边配套');
