INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279d6e3c98b094176581f', '酒店地理位置极佳，挨着淘金站地铁口，大堂门口也常有空出租车在等客人。卫生方面其实挺好的，就是刚进房的时候发现有前面客人遗留的依云水标签没收走，其他地方都很干净。设施方面，房间衣柜表面有明显的木头老化痕迹，床很高偏软但不会太塌，洗手间水力够大，水压水温都稳。房间装饰挺不错的，但是靠门口的墙上有红字印子。窗对着正门花坛和外面的主干道，但是不吵，窗户隔音到位，不过如果有人在走廊上说话或者邻居的关门声还是能从门传进来。', '["https://dimg04.c-ctrip.com/images/0230i12000fcmn3m8BAD2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000fcm9s49914F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000fcmnm1c50B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000fcmebhh4B36_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235l12000fcmd9p39A92_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000fcmob5f7AE4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236412000fcmi7es0220_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000fcmdo1t3AB4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000fcmobwc9207_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-09-02', '花园双床房', '双床房', '家庭亲子', 207, 5.337538079701318, 0, 0.0, 10, 2.3978952727983707, 9, '["交通便利性", "房间设施", "安静程度"]'::jsonb, '交通便利性', '房间设施', '安静程度', '未知酒店', '未知地点', '匿名', '酒店地理位置极佳，挨着淘金站地铁口，大堂门口也常有空出租车在等客人。卫生方面其实', '酒店地理位置极佳，挨着淘金站地铁口，大堂门口也常有空出租车在等客人。卫生方面其实挺好的，就是刚进房的时候发现有前面客人遗留的依云水标签没收走，其他地方都很干净。设施方面，房间衣柜表面有明显的木头老化痕迹，床很高偏软但不会太塌，洗手间水力够大，水压水温都稳。房间装饰挺不错的，但是靠门口的墙上有红字印子。窗对着正门花坛和外面的主干道，但是不吵，窗户隔音到位，不过如果有人在走廊上说话或者邻居的关门声还是能从门传进来。', '2024-09-02', 4, '交通便利性');
