INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279d6e3c98b0941765823', '房间很好，免费升级了房型，服务周到，环境也很好，非常满意！！！', '["https://dimg04.c-ctrip.com/images/0234n12000i4sbwcb112D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000i4salpbEDCE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000i4st6eqAFEC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-29', '红棉双床套房', '套房', '家庭亲子', 31, 3.4657359027997265, 0, 0.0, 3, 1.3862943611198906, 5, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '房间很好，免费升级了房型，服务周到，环境也很好，非常满意！！！', '房间很好，免费升级了房型，服务周到，环境也很好，非常满意！！！', '2025-01-29', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279d6e3c98b0941765824', '老牌的五星酒店，携程买的套餐价格还挺划算的。入住送了欢迎小点心，甚至第二天玩回来居然准备了一个生日蛋糕，真是意外。整体工作人员的服务很好，搞得我都有点不好意思。
行政酒廊附赠的早餐比较一般了，下午茶还行，一楼花园很好拍有瀑布适合拍照。
老式的五星级酒店，房间会有一点点潮湿味道的感觉，然后淋浴房和厕所的推移门有点卡顿，房间的浴缸摆放位置会有点影响动线。然后没有共享洗衣房，可能住这个酒店的不需要这个吧哈哈哈哈', '["https://dimg04.c-ctrip.com/images/0234y12000g2j5qhz600E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233q12000g2j1xyb82AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000g2j1xyd83E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000g2j3mxu3F99_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-10-10', '花园大床房', '大床房', '情侣出游', 204, 5.3230099791384085, 1, 0.6931471805599453, 12, 2.5649493574615367, 8, '["房间设施", "前台服务", "性价比"]'::jsonb, '房间设施', '前台服务', '性价比', '未知酒店', '未知地点', '匿名', '老牌的五星酒店，携程买的套餐价格还挺划算的。入住送了欢迎小点心，甚至第二天玩回来', '老牌的五星酒店，携程买的套餐价格还挺划算的。入住送了欢迎小点心，甚至第二天玩回来居然准备了一个生日蛋糕，真是意外。整体工作人员的服务很好，搞得我都有点不好意思。
行政酒廊附赠的早餐比较一般了，下午茶还行，一楼花园很好拍有瀑布适合拍照。
老式的五星级酒店，房间会有一点点潮湿味道的感觉，然后淋浴房和厕所的推移门有点卡顿，房间的浴缸摆放位置会有点影响动线。然后没有共享洗衣房，可能住这个酒店的不需要这个吧哈哈哈哈', '2024-10-10', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279d6e3c98b0941765825', '房间老旧，墙壁发霉，很潮湿。
服务质量没发上传照片，广州首批五星酒店服务态度领教了，分享一下我的体验大家参考吧。
带小孩办理入住，问能否加婴儿床？
不行，65平的房间才可以加婴儿床。
办理的时候想问问有没有已经收拾好的房间？
没有，而且我们这里入住时间是2点。
通常不是留个联系方式，有打扫出来的房间，我们会电话通知您吗？？？
没事，寄存行李，然后出去逛一圈，2点之后回来领房卡，电脑一顿敲，然后就只说先生办好了。卡也没给，房号也没告诉，整个过程早餐在哪，行政酒廊在哪，什么都没告知，两位前台整个过程没一点微笑。
其他酒店通常都是想办法帮助客人，而不是给人一种高冷的态度，与前两天住Langham相比，不管是服务，设施，早餐或是酒廊，差得不只一点，这样的花园酒店还配五星？
对了 happy hour酒水就只有gin and tonic和JackDaniel with coke两种...
整体不推荐尝试这家老牌五星级酒店', '["https://dimg04.c-ctrip.com/images/0235q12000g29f06rA9F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000g293h97205E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 0.5, 1, '2024-10-09', '花园双床房', '双床房', '家庭亲子', 411, 6.021023349349527, 4, 1.6094379124341005, 2, 1.0986122886681098, 9, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间老旧，墙壁发霉，很潮湿。', '房间老旧，墙壁发霉，很潮湿。
