INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279d6e3c98b0941765827', '中秋来广州之前定了能看到广州塔的宾馆，但是考虑到大部分景点和美食都在越秀和荔湾，最后一刻改回了花园酒店。网上差评不少，因为酒店年头太久了，说房间种种不好，本来心中非常忐忑，但是在踏进大堂的一瞬间就觉得来对了。不同于传统连锁五星的模式化设计，富有岭南特色的大堂气派非凡，节假日虽然房间内没有升级但也非常精致。酒店设施齐全服务热情体贴，钻石会员升级了行政礼遇，赠送了30楼旋转餐厅的早餐，还有下午茶和happy hour，可以广东的美食太多了，根本没有那么多胃口一一品尝。酒店花园小巧精致，人工瀑布，小桥流水，锦鲤往来，酒店博物馆诉说了悠久的历史和文化，总结来说放心来住，非常好??', '["https://dimg04.c-ctrip.com/images/0236b12000flwx1u6009D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000flx5mgp4B66_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000flwjktcCB16_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000flwxispF733_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000flwr1vfAFCF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000flwyn1vE915_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000flx7qd7BB1F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000flwr1vh9A7D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000flwx1u870BC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-17', '花园大床房', '大床房', '家庭亲子', 289, 5.66988092298052, 0, 0.0, 19, 2.995732273553991, 9, '["整体满意度", "公共设施", "餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '中秋来广州之前定了能看到广州塔的宾馆，但是考虑到大部分景点和美食都在越秀和荔湾，', '中秋来广州之前定了能看到广州塔的宾馆，但是考虑到大部分景点和美食都在越秀和荔湾，最后一刻改回了花园酒店。网上差评不少，因为酒店年头太久了，说房间种种不好，本来心中非常忐忑，但是在踏进大堂的一瞬间就觉得来对了。不同于传统连锁五星的模式化设计，富有岭南特色的大堂气派非凡，节假日虽然房间内没有升级但也非常精致。酒店设施齐全服务热情体贴，钻石会员升级了行政礼遇，赠送了30楼旋转餐厅的早餐，还有下午茶和happy hour，可以广东的美食太多了，根本没有那么多胃口一一品尝。酒店花园小巧精致，人工瀑布，小桥流水，锦鲤往来，酒店博物馆诉说了悠久的历史和文化，总结来说放心来住，非常好??', '2024-09-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279e8e3c98b0941765828', '在广州永远的第一选择，宾至如归。酒店位置优越，交通便利。设施齐全，床铺柔软，视野良好。餐饮出色，美食多样且美味。工作人员热情友好、专业高效，服务周到。', '["https://dimg04.c-ctrip.com/images/0235e12000gm98ovs39F6_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234z12000gm935vw25BC_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231a12000gm96eomFB4F_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-11-11', '花园大床房', '大床房', '情侣出游', 75, 4.330733340286331, 0, 0.0, 4, 1.6094379124341005, 8, '["整体满意度", "交通便利性", "餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '在广州永远的第一选择，宾至如归。酒店位置优越，交通便利。设施齐全，床铺柔软，视野', '在广州永远的第一选择，宾至如归。酒店位置优越，交通便利。设施齐全，床铺柔软，视野良好。餐饮出色，美食多样且美味。工作人员热情友好、专业高效，服务周到。', '2024-11-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279e8e3c98b0941765829', '酒店真的超级棒，推荐入住，酒店在十一长假中还帮我升级了房间，和父母住了超大的套房，酒店有自己的花园、瀑布餐厅、层顶泳池、博物馆，大厅的超大大观园漆面描金画真的很生动，木雕楼梯也很绝。就是超五星的配置。', '["https://dimg04.c-ctrip.com/images/0230u12000g11amihEC8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000g11b9ya6772_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-07', '花园双床房', '双床房', '家庭亲子', 100, 4.61512051684126, 0, 0.0, 8, 2.19722457733622, 9, '["整体满意度", "公共设施", "房间设施"]'::jsonb, '整体满意度', '公共设施', '房间设施', '未知酒店', '未知地点', '匿名', '酒店真的超级棒，推荐入住，酒店在十一长假中还帮我升级了房间，和父母住了超大的套房', '酒店真的超级棒，推荐入住，酒店在十一长假中还帮我升级了房间，和父母住了超大的套房，酒店有自己的花园、瀑布餐厅、层顶泳池、博物馆，大厅的超大大观园漆面描金画真的很生动，木雕楼梯也很绝。就是超五星的配置。', '2024-10-07', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279e8e3c98b094176582a', '地理位置不错，出门就是地铁站，步行沿淘金路去了韵姐糖水，挺好吃的，值得尝试，当然你也可以点外卖。房间有免费的咖啡胶囊，还有小瓶漱口水，这点我觉得很棒。酒店的博物馆也很值得参观，蛮大的，东西也多。
瀑布餐厅也就那样吧，可能是水气的原因，玻璃感觉脏脏的，糊糊的，观感大打折扣。早茶种类较少，没有特点也没啥亮点，就牛肉烧卖和蔬菜蒸饺有点好吃，所以不值得买带早餐的房间我觉得。
房间空调关了还是冷，服务员提供了暖风机，但开着很吵，不过阿姨很热情笑脸相迎。
我觉得床太软了而且没弹性非常不舒服，一晚上没睡好，另外床单上有两处碎头发，洗脸池有上个客人粘在上面的鼻屎。尽管房间的装修风格我很喜欢，但以后应该不会再入住了。', '["https://dimg04.c-ctrip.com/images/0234812000fzxcvjt5BB8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000fzx37jk3393_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-10-05', '花园大床房', '大床房', '独自旅行', 303, 5.717027701406222, 0, 0.0, 22, 3.1354942159291497, 9, '["房间设施", "交通便利性", "卫生状况"]'::jsonb, '房间设施', '交通便利性', '卫生状况', '未知酒店', '未知地点', '匿名', '地理位置不错，出门就是地铁站，步行沿淘金路去了韵姐糖水，挺好吃的，值得尝试，当然', '地理位置不错，出门就是地铁站，步行沿淘金路去了韵姐糖水，挺好吃的，值得尝试，当然你也可以点外卖。房间有免费的咖啡胶囊，还有小瓶漱口水，这点我觉得很棒。酒店的博物馆也很值得参观，蛮大的，东西也多。
瀑布餐厅也就那样吧，可能是水气的原因，玻璃感觉脏脏的，糊糊的，观感大打折扣。早茶种类较少，没有特点也没啥亮点，就牛肉烧卖和蔬菜蒸饺有点好吃，所以不值得买带早餐的房间我觉得。
房间空调关了还是冷，服务员提供了暖风机，但开着很吵，不过阿姨很热情笑脸相迎。
我觉得床太软了而且没弹性非常不舒服，一晚上没睡好，另外床单上有两处碎头发，洗脸池有上个客人粘在上面的鼻屎。尽管房间的装修风格我很喜欢，但以后应该不会再入住了。', '2024-10-05', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279e8e3c98b094176582b', '房间干净，环境很好，服务态度满意，早餐品种丰富，午茶好喝又休闲，晚餐虽然品种少了点，但高端上挡次，不愧为花园一样的酒店。', '["https://dimg04.c-ctrip.com/images/0232v12000h15ktsc5C82_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000h15bb6jDCBC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000h15j7jv287A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-04', '花园双床房', '双床房', '朋友出游', 60, 4.110873864173311, 0, 0.0, 24, 3.218875824868201, 7, '["卫生状况", "餐饮设施", "整体满意度"]'::jsonb, '卫生状况', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间干净，环境很好，服务态度满意，早餐品种丰富，午茶好喝又休闲，晚餐虽然品种少了', '房间干净，环境很好，服务态度满意，早餐品种丰富，午茶好喝又休闲，晚餐虽然品种少了点，但高端上挡次，不愧为花园一样的酒店。', '2024-12-04', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279e8e3c98b094176582c', '选择入住花园酒店作为此次广州旅行的第一站，花园酒店是我国唯三家的白金五星酒店，也是亚运会的接待酒店，非常磅礴经典大气，妈妈第一眼就爱上了，映入眼帘的黑金配色的大观园，黑白配色经典的瀑布餐厅，后花园的超级大的鲤鱼都给这次旅行注入新鲜活力。
花园博物馆是一大特色，里面记录了我国酒店发展的故事，花园酒店里面设施的用心，非常推荐。这是第二次入住花园酒店了，应该会有第三次？', '["https://dimg04.c-ctrip.com/images/0234p12000g04stvv153F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000g04oqdc0441_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235912000g04m8f01C2E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-06', '花园大床房', '大床房', '家庭亲子', 184, 5.220355825078324, 0, 0.0, 8, 2.19722457733622, 9, '["整体满意度", "公共设施", "餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '选择入住花园酒店作为此次广州旅行的第一站，花园酒店是我国唯三家的白金五星酒店，也', '选择入住花园酒店作为此次广州旅行的第一站，花园酒店是我国唯三家的白金五星酒店，也是亚运会的接待酒店，非常磅礴经典大气，妈妈第一眼就爱上了，映入眼帘的黑金配色的大观园，黑白配色经典的瀑布餐厅，后花园的超级大的鲤鱼都给这次旅行注入新鲜活力。
花园博物馆是一大特色，里面记录了我国酒店发展的故事，花园酒店里面设施的用心，非常推荐。这是第二次入住花园酒店了，应该会有第三次？', '2024-10-06', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279e8e3c98b094176582d', '种草了很久的酒店，这次终于住上了，硬件非常好
其实设施和大多数五星级酒店差不多，亮点在花园和博物馆，花园植物非常丰富，我们参加活动找10种指定植物很有意义，瀑布拍照??很美丽。博物馆在四层，展品丰富。
酒店附近711，点都德，地铁都超级近
我们住了两天，房间打扫很及时，整洁如新
槽点在前台，第一天入住居然要排队，大家在大厅罚站，倒水喝根本解决不了问题，不如搞些pad也做入住。早饭也是排队。一个问题问好几个服务人员才行。和客人交流不说您好……最后想晚一些退房，前台穿金片衣服的小姐姐直接要好评，还要我展示给她看，五星级还要这样刷好评吗？', '["https://dimg04.c-ctrip.com/images/0233u12000g0x4d039CEC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235512000g0x5qzgBB17_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-10-07', '花园大床房', '大床房', '家庭亲子', 269, 5.598421958998375, 0, 0.0, 17, 2.8903717578961645, 9, '["前台服务", "周边配套", "客房服务"]'::jsonb, '前台服务', '周边配套', '客房服务', '未知酒店', '未知地点', '匿名', '种草了很久的酒店，这次终于住上了，硬件非常好', '种草了很久的酒店，这次终于住上了，硬件非常好
其实设施和大多数五星级酒店差不多，亮点在花园和博物馆，花园植物非常丰富，我们参加活动找10种指定植物很有意义，瀑布拍照??很美丽。博物馆在四层，展品丰富。
