INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279e8e3c98b094176582f', '确实是老牌酒店，金碧辉煌，如果在30年前一定是顶流', '["https://dimg04.c-ctrip.com/images/0234q12000ibm5r0f2AB7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000ibm0z7c3127_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000iblpc2c5285_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000ibli0pj7F9D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 25, 3.258096538021482, 0, 0.0, 4, 1.6094379124341005, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '确实是老牌酒店，金碧辉煌，如果在30年前一定是顶流', '确实是老牌酒店，金碧辉煌，如果在30年前一定是顶流', '2025-02-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279e8e3c98b0941765830', '之前看评论说酒店旧，可是冲着老牌酒店的名声还是去决定试试，结果超预期。酒店房间还带一客厅，等于是套房，房间也挺新的，房间两个洗手台，厕所干湿分离很不错。提前告知孩子生日还把房间布置了，送了一个小蛋糕。酒店后花园也很漂亮，还有后花园和四楼博物馆打卡活动，孩子玩的很开心，下次还会选择入住，老牌五星酒店还是有他的底蕴在的', '["https://dimg04.c-ctrip.com/images/0232512000fz502fy7A4C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000fz5up7vAA97_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000fz52xewBFC9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000fz502g273C3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000fz5165l96EB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000fz5mwcg8A7D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000fz42nfaFAF2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000fz4n3yw356D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-10-04', '城央绿意双床房', '双床房', '家庭亲子', 158, 5.068904202220232, 0, 0.0, 7, 2.079441541679836, 9, '["房间设施", "整体满意度", "前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '之前看评论说酒店旧，可是冲着老牌酒店的名声还是去决定试试，结果超预期。酒店房间还', '之前看评论说酒店旧，可是冲着老牌酒店的名声还是去决定试试，结果超预期。酒店房间还带一客厅，等于是套房，房间也挺新的，房间两个洗手台，厕所干湿分离很不错。提前告知孩子生日还把房间布置了，送了一个小蛋糕。酒店后花园也很漂亮，还有后花园和四楼博物馆打卡活动，孩子玩的很开心，下次还会选择入住，老牌五星酒店还是有他的底蕴在的', '2024-10-04', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279e8e3c98b0941765831', '不愧是白金级五星酒店，大堂的布置既富贵又有文化，特别是两幅壁画，叹为观止。酒店的博物馆很值得一看，了解到中西酒店的发展历史和酒店文化。酒店地理位置好，在地铁边，交通方便。对面就是广州酒家和友谊商店。酒店房间不大，但设计精巧，类似国外酒店。后花园有高，低两个瀑布，人少景美，很喜欢这家酒店！', '["https://dimg04.c-ctrip.com/images/0200e12000g1j7o9851B0_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0234d12000g1isd27C0AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000g1ivfk4F4E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000g1iva0a745B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-08', '花园双床房', '双床房', '家庭亲子', 144, 4.976733742420574, 0, 0.0, 35, 3.58351893845611, 9, '["交通便利性", "周边配套", "整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '不愧是白金级五星酒店，大堂的布置既富贵又有文化，特别是两幅壁画，叹为观止。酒店的', '不愧是白金级五星酒店，大堂的布置既富贵又有文化，特别是两幅壁画，叹为观止。酒店的博物馆很值得一看，了解到中西酒店的发展历史和酒店文化。酒店地理位置好，在地铁边，交通方便。对面就是广州酒家和友谊商店。酒店房间不大，但设计精巧，类似国外酒店。后花园有高，低两个瀑布，人少景美，很喜欢这家酒店！', '2024-10-08', 5, '交通便利性');
